window.__ARXIV_DATA__ = {"papers":[{"id":"2607.15278v1","title":"Hierarchical Denoising For Multi-Step Visual Reasoning","abstract":"Video models are evolving into vision foundation models, yet they still lack human-like multi-step reasoning. Streaming autoregressive diffusion models are efficient but limited in reasoning, while bidirectional diffusion enables global revision with high inference costs due to dense frame-level denoising. Both paradigms struggle to achieve logical consistency and low-latency streaming for complex reasoning tasks. We propose HDR (Hierarchical Denoising for Visual Reasoning), a unified framework that integrates hierarchical latents into causal video generation for multi-step reasoning. HDR organizes video latents into a tree-structured hierarchy, enabling coarse-to-fine reasoning before streaming output. Coarse denoising layers preserve uncertain hypotheses for global planning, while finer layers progressively refine them into concrete visual states. A sparse hierarchical attention pattern (SHAP) further reduces temporal attention costs. We introduce a level-stratified multi-step video reasoning benchmark with out-of-distribution cases, covering six tasks: maze navigation, Tower of Hanoi, one-line drawing, sliding puzzle, Sokoban, and water pouring. Compared with streaming autoregressive diffusion baselines, HDR improves success from 34.22 to 60.29 (76.2% relative gain) and increases average progress from 76.00 to 89.56, demonstrating more consistent reasoning trajectories. HDR maintains low-latency streaming at 0.70 seconds per latent, achieving 54.2 times faster inference than bidirectional diffusion. It also retains 82.9% of full-data performance with only 2% training data, compared with 52.0% for bidirectional diffusion. Real-world robot experiments further demonstrate HDR's potential for physical interaction and world modeling. Project demo: https://hierarchical-diffusion-reasoning.github.io/.","authors":["Zezhong Qian","Xiaowei Chi","Chak-Wing Mak","Tianze Zhou","Ruibin Yuan","Yuhan Rui","Hengzhe Sun","Zhuoqun Wu","Yuming Li","Siyuan Qian","Sirui Han","Shanghang Zhang"],"published":"2026-07-16T17:59:57Z","updated":"2026-07-16T17:59:57Z","abstract_url":"https://arxiv.org/abs/2607.15278v1","html_url":"https://arxiv.org/html/2607.15278v1","pdf_url":"https://arxiv.org/pdf/2607.15278v1.pdf","matched_keywords":["video","diffusion"],"source_used":"html","source_text_chars":100103,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, diffusion 相关；摘要显示其主要贡献为：Video models are evolving into vision foundation models, yet they still lack human-like multi-step reasoning. Streaming autoregressive diffusion models are efficient but limited in reasoning, while bidirectional diffusion enables global revision with high inf...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:56:59+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15273v1","title":"MeanFlowNFT: Bringing Forward-Process RL to Average-Velocity Generators","abstract":"MeanFlow generators achieve fast few-step sampling by predicting average velocities over time intervals, making them attractive for efficient generation. Reinforcement learning (RL) has become a powerful way to align diffusion and flow models with human preferences and task-specific objectives. In particular, DiffusionNFT offers an efficient forward-process RL framework that does not require reverse-process trajectories or likelihood estimation. However, applying such RL methods to MeanFlow remains underexplored. DiffusionNFT optimizes instantaneous velocities, whereas MeanFlow samples with average velocities. To bridge this gap, we introduce MeanFlowNFT. Inspired by the MeanFlow identity, which bridges average and instantaneous velocities, we construct an induced instantaneous-velocity predictor. We apply the DiffusionNFT objective to this predictor, making reward optimization well-defined for MeanFlow. Sampling remains based on the average velocity, preserving MeanFlow's fast few-step generation. We further prove that MeanFlowNFT inherits DiffusionNFT's strict policy-improvement guarantee. Experiments on image and video generation show that MeanFlowNFT consistently improves baselines. Moreover, it outperforms prior state-of-the-art RL-tuned few-step generators on most metrics ($6$ of $8$ on SD3.5-M), and can even surpass multi-step RL-tuned diffusion while using only a few sampling steps. For instance, on Wan 2.1, $4$-step MeanFlowNFT reaches a VBench score of $84.33$, surpassing $50$-step LongCat-Video RL ($82.57$).","authors":["Yushi Huang","Xiangxin Zhou","Jun Zhang","Liefeng Bo","Tianyu Pang"],"published":"2026-07-16T17:59:02Z","updated":"2026-07-16T17:59:02Z","abstract_url":"https://arxiv.org/abs/2607.15273v1","html_url":"https://arxiv.org/html/2607.15273v1","pdf_url":"https://arxiv.org/pdf/2607.15273v1.pdf","matched_keywords":["video","instance","diffusion"],"source_used":"html","source_text_chars":101845,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, instance, diffusion 相关；摘要显示其主要贡献为：MeanFlow generators achieve fast few-step sampling by predicting average velocities over time intervals, making them attractive for efficient generation. Reinforcement learning (RL) has become a powerful way to align diffusion and flow models with human prefe...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:56:59+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15271v1","title":"Online Neural Space Time Memory for Dynamic Novel View Synthesis","abstract":"Online novel view synthesis from multi-view streaming videos faces a fundamental trade-off: maintaining a persistent, long-horizon memory to reconstruct temporarily occluded regions while operating under strict real-time constraints. While Test-Time Training (TTT) offers a powerful memory mechanism, standard models mandate gradient-based memory updates at every frame to adapt to the changing motion in dynamic scenes. The computational cost of heavy memory updates precludes real-time application and can lead to instability over long contexts. Given that memory updates are more demanding than memory application and video content is largely redundant, we propose to decouple the frequencies of these two processes. Our approach performs periodic memory updates while applying the memory on a per-frame basis, using cross-view attention to manage deformations between the prior memory state and the current frame. To lock in the historical context, we introduce two critical mechanisms: an auxiliary Memory Loss that forces persistent internalization of the scene, and a Memory Caching strategy that regularizes active weights against catastrophic drift. Our method demonstrates real-time, state-of-the-art performance on scenes with dynamic human motion as well as minute-scale online memorization.","authors":["Baback Elmieh","Lynn Tsai","Zeman Li","Srinivas Kaza","Tiancheng Sun","Gabor Csapo","Ali Behrouz","Yuan Deng","Stephen Lombardi","Steven M. Seitz","Xuan Luo"],"published":"2026-07-16T17:58:18Z","updated":"2026-07-16T17:58:18Z","abstract_url":"https://arxiv.org/abs/2607.15271v1","html_url":"https://arxiv.org/html/2607.15271v1","pdf_url":"https://arxiv.org/pdf/2607.15271v1.pdf","matched_keywords":["video"],"source_used":"html","source_text_chars":73968,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video 相关；摘要显示其主要贡献为：Online novel view synthesis from multi-view streaming videos faces a fundamental trade-off: maintaining a persistent, long-horizon memory to reconstruct temporarily occluded regions while operating under strict real-time constraints. While Test-Time Training...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:00+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15268v1","title":"Motion-Conditioned Multi-View Fusion for Myocardial Infarction Localization from Echocardiography","abstract":"Myocardial infarction (MI) remains a leading cause of mortality worldwide. Echocardiography (Echo) is a widely available modality for MI assessment, where regional wall motion abnormality is a key indicator. Prior learning based methods for myocardial motion analysis often use handcrafted descriptors or densely supervised estimation, but the need for extensive annotation limits applicability. Foundation models have recently improved vision-based Echo analysis; however, most methods operate on single views and segment-level localization remains unreliable under view-dependent ambiguity, especially in apical views. To address this, we propose MCF-Net, a novel motion-guided multi-view fusion framework that fuses myocardial motion cues with foundation model representations to localize infarction. Visual features are extracted using EchoPrime, a pretrained Echo foundation model shared across dual views. Cardiac motion is modeled with extremely sparse supervision: a single annotated template frame is transferred across videos to initialize point tracking, avoiding dense labels. Motion-derived segment-aware soft masks provide coarse spatial priors that selectively enhance features for challenging myocardial segments. A motion-conditioned fusion mechanism then integrates motion and vision across views, refining predictions without overriding strong appearance cues. On segment-level MI localization, MCF-Net achieves 72.4\\% F1 and 84.9\\% accuracy, outperforming state-of-the-art motion-only, vision-only, and fusion baselines.","authors":["Guang Yang","Wentian Xu","Siyu Wang","Betty Raman","Lei Li","Vicente Grau"],"published":"2026-07-16T17:56:56Z","updated":"2026-07-16T17:56:56Z","abstract_url":"https://arxiv.org/abs/2607.15268v1","html_url":"https://arxiv.org/html/2607.15268v1","pdf_url":"https://arxiv.org/pdf/2607.15268v1.pdf","matched_keywords":["video","representation"],"source_used":"html","source_text_chars":32830,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, representation 相关；摘要显示其主要贡献为：Myocardial infarction (MI) remains a leading cause of mortality worldwide. Echocardiography (Echo) is a widely available modality for MI assessment, where regional wall motion abnormality is a key indicator. Prior learning based methods for myocardial motion...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:00+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15265v1","title":"SceneBind: Binding What and Where Across Vision, Audio and Language","abstract":"We present SceneBind, an omni-modal representation of realistic scenes with joint semantic and 3D spatial understanding across vision, audio and language. Existing omni-modal encoders excel at instance-level semantics (i.e., what is present), but often lack explicit spatial structure (i.e., where it is). SceneBind addresses this gap by representing each scene as a semantic-spatial entity, combining a global semantic embedding with object-centric semantic-spatial slots. This representation explicitly captures object-level semantics, spatial attributes, and uncertainty. We further propose SceneBind Matching, a semantic-spatial matching scheme that integrates global scene similarity with object alignment, supporting cross-modal scene retrieval and object grounding. To train and evaluate SceneBind, we curate a novel real-world binaural audio-visual dataset with structured semantic and spatial annotations, and propose a training protocol for aligning semantic and spatial signals across modalities. SceneBind is compatible with large-scale pretrained semantic encoders, adds lightweight spatial modeling with only a few additional tokens. It achieves state-of-the-art scene and spatial retrieval while enabling strong zero-shot transfer to downstream tasks such as audio-visual localization.","authors":["Mingfei Chen","Zijun Cui","Ruoke Zhang","Hyeonggon Ryu","Eli Shlizerman"],"published":"2026-07-16T17:55:15Z","updated":"2026-07-16T17:55:15Z","abstract_url":"https://arxiv.org/abs/2607.15265v1","html_url":"https://arxiv.org/html/2607.15265v1","pdf_url":"https://arxiv.org/pdf/2607.15265v1.pdf","matched_keywords":["retrieval","3d","representation","instance"],"source_used":"html","source_text_chars":120625,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 retrieval, 3d, representation, instance 相关；摘要显示其主要贡献为：We present SceneBind, an omni-modal representation of realistic scenes with joint semantic and 3D spatial understanding across vision, audio and language. Existing omni-modal encoders excel at instance-level semantics (i.e., what is present), but often lack e...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:00+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15246v1","title":"ARMOR++: Agentic Orchestration of a Multi-Domain Primitive Set for Transferable Attacks on Deepfake Detectors","abstract":"The reliability of deepfake detectors frequently degrades under black-box adversarial transfer, as these models often rely on fragile, architecture-dependent forensic cues. Existing transfer attacks often lack semantic awareness and struggle to maintain effectiveness under strict no-query constraints, particularly when perturbations are transferred from convolutional surrogates to transformer-based targets. To address these limitations, this paper introduces ARMOR++, a robust multi-agent framework designed for high-transferability deepfake evasion. The framework leverages the Qwen2.5-VL Vision-Language Model (VLM) to supply spatial semantic priors, while the Qwen3 Large Language Model (LLM) orchestrates primitive selection, adaptive hyperparameter reparameterization, and entropy-regularized perturbation mixing. By integrating five complementary primitives, spanning dense optimization, saliency-based methods, spatial transformations, frequency-domain perturbations, and block-structured modifications, ARMOR++ effectively targets heterogeneous inductive biases. Rigorous evaluation on the AADD-2025 benchmark demonstrates that ARMOR++ significantly outperforms existing agentic and non-agentic baselines across both low- and high-quality image regimes. Statistical analysis confirms a substantial gain in blind-target Attack Success Rate (ASR) over the state-of-the-art agentic baseline, with further performance advantages evidenced against non-agentic benchmarks and under robust defensive configurations. These findings highlight a significant residual reliability gap in current deepfake detector deployments and demonstrate the efficacy of agentic orchestration in identifying latent vulnerabilities.","authors":["Christos Korgialas","Gabriel Lee Jun Rong","Dion Jia Xu Ho","Pai Chet Ng","Xiaoxiao Miao","Konstantinos N. Plataniotis"],"published":"2026-07-16T17:45:13Z","updated":"2026-07-16T17:45:13Z","abstract_url":"https://arxiv.org/abs/2607.15246v1","html_url":"https://arxiv.org/html/2607.15246v1","pdf_url":"https://arxiv.org/pdf/2607.15246v1.pdf","matched_keywords":["agent"],"source_used":"html","source_text_chars":110140,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 agent 相关；摘要显示其主要贡献为：The reliability of deepfake detectors frequently degrades under black-box adversarial transfer, as these models often rely on fragile, architecture-dependent forensic cues. Existing transfer attacks often lack semantic awareness and struggle to maintain effec...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:00+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15241v1","title":"Beyond the Leaderboard: Design Lessons for Trustworthy Multimodal VQA","abstract":"Healthcare multimodal AI must combine visual and textual evidence while remaining reliable and interpretable. Using MediaEval Medico 2025 as a retrospective GI endoscopy case study, we analyze design choices across nine documented systems for question answering and explanation quality. Parameter-efficient adaptation of pretrained backbones provides strong challenge performance, but answer-level gains do not consistently translate into faithful and complete clinical reasoning. Methods enforcing structured reasoning and explicit grounding show more reliable behavior across heterogeneous question types, although the evidence is correlational rather than ablation-based. These results motivate evaluation beyond lexical overlap, standardized evidence-linked explanations, leakage-aware data governance, and lightweight robustness and calibration checks. The findings support trustworthy multimodal healthcare AI based on data fusion, explainability, and resilient evaluation.","authors":["Sushant Gautam","Vajira Thambawita","Michael A. Riegler","Pål Halvorsen","Steven A. Hicks"],"published":"2026-07-16T17:38:19Z","updated":"2026-07-16T17:38:19Z","abstract_url":"https://arxiv.org/abs/2607.15241v1","html_url":"https://arxiv.org/html/2607.15241v1","pdf_url":"https://arxiv.org/pdf/2607.15241v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":45166,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：Healthcare multimodal AI must combine visual and textual evidence while remaining reliable and interpretable. Using MediaEval Medico 2025 as a retrospective GI endoscopy case study, we analyze design choices across nine documented systems for question answeri...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:00+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15220v1","title":"Structural-Semantic Reciprocal Learning for Unsupervised Visible-Infrared Person Re-Identification","abstract":"Unsupervised visible-infrared person re-identification (USVI-ReID) is challenging due to the large modality gap and the lack of cross-modal identity annotations. Progressive association paradigms have been proposed to gradually bridge the gap, but they suffer from two critical bottlenecks: reliance on ambiguous global representations and unchecked propagation of pseudo-label noise in an open-loop manner. To address these issues, we propose Structural-Semantic Reciprocal Learning (SSRL), a framework that transforms open-loop association into a self-correcting closed-loop system. Structurally, we introduce Fine-grained Structural Decoupling (FSD) to extract discriminative body-part primitives as reliable spatial anchors, complementing ambiguous holistic silhouettes with spatially consistent structural details. Semantically, we design a Closed-loop Semantic Calibration (CSC) mechanism that reconstructs shared semantic prototypes at each epoch and feeds them back into the training loop, effectively filtering pseudo-label noise before the next clustering cycle. Through the reciprocal interaction between structural and semantic learning, SSRL achieves robust cross-modal representation. Extensive experiments demonstrate the competitive performance of SSRL against state-of-the-art USVI-ReID methods on both SYSU-MM01 and RegDB, notably surpassing several supervised counterparts on RegDB.","authors":["Moyao Tian","Shijia Liu","Yan Yang","Xin Yuan","Minshi Chen","Wei Wang","Xiao Wang"],"published":"2026-07-16T17:22:51Z","updated":"2026-07-16T17:22:51Z","abstract_url":"https://arxiv.org/abs/2607.15220v1","html_url":"https://arxiv.org/html/2607.15220v1","pdf_url":"https://arxiv.org/pdf/2607.15220v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":64232,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：Unsupervised visible-infrared person re-identification (USVI-ReID) is challenging due to the large modality gap and the lack of cross-modal identity annotations. Progressive association paradigms have been proposed to gradually bridge the gap, but they suffer...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:00+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15216v1","title":"Symbal: Detecting Systematic Misalignments in Model-Generated Captions","abstract":"Multimodal large language models (MLLMs) often introduce errors when generating image captions, resulting in misaligned image-text pairs. Our work focuses on a class of captioning errors that we refer to as systematic misalignments, where a recurring error in MLLM-generated captions is closely associated with the presence of a specific visual feature in the paired image. Given a vision-language dataset with MLLM-generated captions, our aim in this work is to detect such errors, a task we refer to as systematic misalignment detection. As our first key contribution, we present Symbal, which utilizes a structured, dual-stage setup with off-the-shelf foundation models to identify systematic misalignments and summarize results in natural language. As our second key contribution, we introduce SymbalBench, a benchmark designed to evaluate automated methods on our proposed task. SymbalBench consists of 1.7 million image-text pairs from two domains (natural and medical images), organized into 420 vision-language datasets with annotated systematic misalignments. Symbal exhibits strong performance on this benchmark, correctly identifying systematic misalignments in 63.8% of datasets, a nearly 4x improvement over the closest baseline. We supplement our evaluations on SymbalBench with real-world evaluations, showing that (1) Symbal can accurately surface systematic misalignments in captions generated by four MLLMs and (2) Symbal is a powerful tool for auditing off-the-shelf image-caption datasets. Ultimately, our novel task, method, and benchmark can aid users with auditing MLLM-generated captions and identifying critical errors, without requiring access to the underlying MLLM. Code is available at https://github.com/Stanford-AIMI/Symbal.","authors":["Maya Varma","Jean-Benoit Delbrouck","Sophie Ostmeier","Akshay Chaudhari","Curtis Langlotz"],"published":"2026-07-16T17:18:37Z","updated":"2026-07-16T17:18:37Z","abstract_url":"https://arxiv.org/abs/2607.15216v1","html_url":"https://arxiv.org/html/2607.15216v1","pdf_url":"https://arxiv.org/pdf/2607.15216v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":108408,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：Multimodal large language models (MLLMs) often introduce errors when generating image captions, resulting in misaligned image-text pairs. Our work focuses on a class of captioning errors that we refer to as systematic misalignments, where a recurring error in...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:00+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15211v1","title":"MAGiSt3R: Multi-Agent Feed-forward 3D Reconstruction from Monocular RGB Videos","abstract":"This paper presents MAGiSt3R, a multi-agent 3D reconstruction framework performing reconstruction and camera tracking for monocular RGB videos at almost 10 FPS. MAGiSt3R relies on a feed-forward model from the 3R family to process RGB videos and regress local point maps, and on a merging model, MAGMA, that combines local maps at both intra-agent and inter-agent levels to obtain the final global point map. Furthermore, MAGiSt3R performs pose graph optimization to mitigate cumulative camera drift occurring along the feed-forward pipeline. We evaluate MAGiSt3R on both synthetic and real-world datasets, demonstrating its superior reconstruction and camera tracking accuracy compared to state-of-the-art approaches.","authors":["Ziren Gong","Xiaohan Li","Fabio Tosi","Ninghui Xu","Stefano Mattoccia","Jianfei Cai","Matteo Poggi"],"published":"2026-07-16T17:12:58Z","updated":"2026-07-16T17:12:58Z","abstract_url":"https://arxiv.org/abs/2607.15211v1","html_url":"https://arxiv.org/html/2607.15211v1","pdf_url":"https://arxiv.org/pdf/2607.15211v1.pdf","matched_keywords":["video","3d","agent"],"source_used":"html","source_text_chars":50528,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, 3d, agent 相关；摘要显示其主要贡献为：This paper presents MAGiSt3R, a multi-agent 3D reconstruction framework performing reconstruction and camera tracking for monocular RGB videos at almost 10 FPS. MAGiSt3R relies on a feed-forward model from the 3R family to process RGB videos and regress local...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:00+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15128v1","title":"DAPGNet: Dynamic Adaptive Physics-Guided Graph Diffusion Network for Hyperspectral Image Classification","abstract":"Hyperspectral image (HSI) classification requires reliable pixel-relation modeling under spectral variability, mixed pixels, and heterogeneous boundaries. Existing graph-based HSI classifiers usually construct graph topology from spatial proximity, superpixel connectivity, or learned feature affinity. However, the spectral physical prior carried by contiguous bands has limited influence on topology estimation and message propagation. This paper presents DAPGNet, a dynamic adaptive physics-guided graph diffusion network that injects a structure-constrained physical prior into relation-level graph learning. DAPGNet first encodes contiguous spectral responses into node-wise multiscale physical-prior representations. A two-stage graph constructor then combines spectral-spatial affinity, physical-prior consistency, and spatial distance to form a physical-prior-aware sparse topology. During graph diffusion, learned edge weights are transformed into additive attention biases, while a physical gate performs node-wise and feature-wise interpolation between graph-aggregated features and projected physical-prior features. Cross-scale fusion integrates node states from different diffusion depths, and the network is optimized with main classification, auxiliary supervision, and second-order spectral smoothness regularization. Experiments on Indian Pines, WHU-Hi-LongKou, Houston2013, and Houston2018 show that DAPGNet achieves the best OA, AA, and Kappa among representative CNN-, Transformer-, Mamba-, and graph-based baselines. It improves AA over the strongest competing method by 3.64 to 7.31 percentage points across the four datasets. Ablation and sensitivity analyses further support the complementary effects of physical-prior extraction, prior-aware topology construction, physics-gated propagation, and spectral smoothness regularization.","authors":["Pengkun Wang","Weijia Cao","Ning Wang","Xiaofei Yang"],"published":"2026-07-16T15:37:32Z","updated":"2026-07-16T15:37:32Z","abstract_url":"https://arxiv.org/abs/2607.15128v1","html_url":"https://arxiv.org/html/2607.15128v1","pdf_url":"https://arxiv.org/pdf/2607.15128v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"html","source_text_chars":101087,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation, diffusion 相关；摘要显示其主要贡献为：Hyperspectral image (HSI) classification requires reliable pixel-relation modeling under spectral variability, mixed pixels, and heterogeneous boundaries. Existing graph-based HSI classifiers usually construct graph topology from spatial proximity, superpixel...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:00+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15097v1","title":"QuReC: All-in-One Image Restoration with Query-Specific Guidance and Local-Global Response Calibration","abstract":"All-in-one image restoration aims to recover clean images degraded by multiple corruption types using a single unified model. Existing methods typically rely on image-level prompts or shared guidance to handle diverse degradations. However, such a paradigm becomes inadequate when degradations are spatially heterogeneous or even coexist in mixed forms within a single image. Yet spatially adaptive guidance alone is not sufficient, since accurate restoration also requires each spatial query to reliably aggregate complementary information from local neighborhoods and global contexts. To this end, we propose QuReC, a unified framework for all-in-one image restoration. QuReC consists of a Degradation-Guided Query Reconstruction Module (DQRM) and a Local-Global Response Calibration Module (LGRCM). Specifically, DQRM matches each spatial query against a degradation prototype space to reconstruct a query-specific degradation-aware representation, thereby providing fine-grained spatially adaptive restoration guidance. To further stabilize this query-wise matching process, we introduce a weakly supervised prototype matching learning strategy to improve optimization stability and degradation semantic consistency. Meanwhile, LGRCM performs local-global dual-branch aggregation and calibrates the aggregated responses with learnable priors, improving the reliability of feature aggregation and the coordination between local detail modeling and global context modeling. Extensive experiments demonstrate that QuReC achieves superior performance on multiple all-in-one image restoration benchmarks. The code is released at https://github.com/zhoushen1/QuReC.","authors":["Shen Zhou","Jinghui Zhang","Wenbo Huang","Xuwei Qian","Zhen Wu","Guangwen Peng","Zhiyuan Li","Ding Ding","Dian Shen","Fang Dong"],"published":"2026-07-16T15:10:00Z","updated":"2026-07-16T15:10:00Z","abstract_url":"https://arxiv.org/abs/2607.15097v1","html_url":"https://arxiv.org/html/2607.15097v1","pdf_url":"https://arxiv.org/pdf/2607.15097v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":101576,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：All-in-one image restoration aims to recover clean images degraded by multiple corruption types using a single unified model. Existing methods typically rely on image-level prompts or shared guidance to handle diverse degradations. However, such a paradigm be...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:01+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15094v1","title":"AlphaWiSE: Adaptive Weight Interpolation for Continual Multimodal Representation Learning","abstract":"Multimodal models such as CLIP learn a shared embedding space for cross-modal retrieval, but continual adaptation to sequentially arriving data can disrupt the cross-modal alignment acquired from earlier phases. Conventional continual-learning methods return a single checkpoint, which commits every retrieval direction to the same stability-plasticity trade-off. We propose AlphaWiSE, a post-hoc weight-space interpolation method that composes two frozen source checkpoints. For each aligned parameter tensor identified by its checkpoint key, AlphaWiSE fits one scalar interpolation coefficient shared by all tensor entries. The coefficients are fitted on a smaller exemplar memory and used to materialize one interpolated checkpoint. The deployed model has the same architecture and parameter count as either source checkpoint, which does not require additional inference time. Extensive experiments on audio-image-text retrieval show consistent improvements over strong continual-learning baselines across multiple retrieval directions and evaluation metrics.","authors":["Sarthak Jain","Qiran Hu","Zhen Zhu","Yaoyao Liu"],"published":"2026-07-16T15:07:23Z","updated":"2026-07-16T15:07:23Z","abstract_url":"https://arxiv.org/abs/2607.15094v1","html_url":"https://arxiv.org/html/2607.15094v1","pdf_url":"https://arxiv.org/pdf/2607.15094v1.pdf","matched_keywords":["retrieval","representation","multimodal"],"source_used":"html","source_text_chars":62534,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 retrieval, representation, multimodal 相关；摘要显示其主要贡献为：Multimodal models such as CLIP learn a shared embedding space for cross-modal retrieval, but continual adaptation to sequentially arriving data can disrupt the cross-modal alignment acquired from earlier phases. Conventional continual-learning methods return...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:01+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15082v1","title":"Towards Hierarchical Structure Understanding of Newspaper Images","abstract":"Understanding newspaper images remains a challenging task due to their complex, nested hierarchical structures and dense, heterogeneous layouts. In this paper, we explore two complementary approaches for newspaper structure understanding. First, we present a modular bottom-up pipeline that combines state-of-the-art open-source models: YOLO for layout detection, LayoutReader for reading order prediction, and a custom algorithm for article segmentation. This approach leverages existing robust components while maintaining flexibility and interpretability. Second, we introduce Tiramisu (Tiered Transformers for Hierarchical Structure Understanding), a novel end-to-end transformer-based architecture that explicitly models document hierarchy through an iterative tiered process. Tiramisu performs section and article separation, block localization, semantic categorization, and reading order prediction using highly parallelized attention mechanisms. Finally, we release Finlam La Liberté, a new dataset designed specifically for evaluating hierarchical information retrieval in historical newspapers. Experimental results demonstrate the effectiveness of both approaches in reconstructing complex newspaper hierarchies, with comparative analysis highlighting their respective strengths for scalable document digitization. The Tiramisu training code, including the synthetic newspaper generator, is available at https://git.litislab.fr/tiramisu/tiramisu-newspaper-articles-extractor.","authors":["William Mocaër","Solène Tarride","Thomas Constum","Merveilles Agbeti-Messan","Tom Simon","Clément Chatelain","Stéphane Nicolas","Pierrick Tranouez","Sébastien Cretin","Thierry Paquet"],"published":"2026-07-16T14:52:08Z","updated":"2026-07-16T14:52:08Z","abstract_url":"https://arxiv.org/abs/2607.15082v1","html_url":"https://arxiv.org/html/2607.15082v1","pdf_url":"https://arxiv.org/pdf/2607.15082v1.pdf","matched_keywords":["retrieval"],"source_used":"html","source_text_chars":47630,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 retrieval 相关；摘要显示其主要贡献为：Understanding newspaper images remains a challenging task due to their complex, nested hierarchical structures and dense, heterogeneous layouts. In this paper, we explore two complementary approaches for newspaper structure understanding. First, we present a...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:01+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15065v1","title":"DriftWorld: Fast World Modeling through Drifting","abstract":"Predictive world models enable robots to plan by imagining the outcomes of their actions, but their value for control hinges on generating many rollouts quickly. This creates a bottleneck for diffusion-based world models: multistep sampling makes each rollout expensive, limiting large-scale action search at inference time. We introduce DriftWorld, an action-conditioned world model based on drifting generative models. Rather than denoising iteratively at inference, DriftWorld learns an action-conditioned drift during training, allowing it to generate future frames from the current observation and a candidate action sequence in a single forward pass at 30+ fps, which is 17x faster on average than diffusion based baselines. We evaluate DriftWorld on standard vision-based robotic manipulation benchmarks, including Bridge-V2, RT-1, Language Table, Push-T, and Robomimic. By producing rollouts that are both accurate and fast, DriftWorld achieves state-of-the-art decision-making performance with far less inference time than diffusion-based world model baselines. Beyond online control, DriftWorld can also serve as an offline simulator for ranking real-world robot policies, with rollout-based scores correlating with ground truth at up to 0.99. These results show that drifting models are a strong fit for robot world modeling, where fast, high-quality imagination directly supports planning and policy evaluation.","authors":["Susie Lu","Haonan Chen","Weirui Ye","Yilun Du"],"published":"2026-07-16T14:37:43Z","updated":"2026-07-16T14:37:43Z","abstract_url":"https://arxiv.org/abs/2607.15065v1","html_url":"https://arxiv.org/html/2607.15065v1","pdf_url":"https://arxiv.org/pdf/2607.15065v1.pdf","matched_keywords":["diffusion"],"source_used":"html","source_text_chars":65469,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 diffusion 相关；摘要显示其主要贡献为：Predictive world models enable robots to plan by imagining the outcomes of their actions, but their value for control hinges on generating many rollouts quickly. This creates a bottleneck for diffusion-based world models: multistep sampling makes each rollout...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:01+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15058v1","title":"SUFLECA: Scaling Up Feature Learning for CAD-to-image Alignment","abstract":"CAD-to-image alignment aims to estimate an object's 9D pose (rotation, translation, and anisotropic scale) from a single RGB image, enabling applications in robotics and augmented reality. Recent zero-shot methods use visual foundation models to match image regions to CAD models, yet typically their correspondences are appearance-driven and degrade under occlusion or sim-to-real domain shift. To address these limitations, we introduce SUFLECA (Scaling Up Feature LEarning for CAD Alignment), a weakly-supervised framework for zero-shot CAD alignment with two key contributions. First, SUFLECA scales up geometry-grounded feature learning from pretrained visual representations through Normalized Object Coordinates (NOCs) supervision on 674K images spanning 12 real and synthetic datasets, learning compact geometry-aware features that generalize across domains. Second, we propose a geometrically consistent matching algorithm that establishes reliable one-to-one CAD-to-image correspondences. Together, these contributions enable accurate, sub-second alignment per object instance without iterative pose refinement. On ScanNet25k, SUFLECA achieves 33.4%/42.3% category/instance accuracy, outperforming, with a smaller computational footprint, the strongest zero-shot baseline by 10.3/12.2 percentage points and, for the first time on this benchmark, even surpassing fully supervised methods. Code is available at: https://github.com/snt-arg/SUFLECA","authors":["Saad Ejaz","Miguel Fernandez-Cortizas","Javier Civera","Holger Voos","Jose Luis Sanchez-Lopez"],"published":"2026-07-16T14:32:34Z","updated":"2026-07-16T14:32:34Z","abstract_url":"https://arxiv.org/abs/2607.15058v1","html_url":"https://arxiv.org/html/2607.15058v1","pdf_url":"https://arxiv.org/pdf/2607.15058v1.pdf","matched_keywords":["representation","instance"],"source_used":"html","source_text_chars":52909,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation, instance 相关；摘要显示其主要贡献为：CAD-to-image alignment aims to estimate an object's 9D pose (rotation, translation, and anisotropic scale) from a single RGB image, enabling applications in robotics and augmented reality. Recent zero-shot methods use visual foundation models to match image r...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:01+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15054v1","title":"Beyond Single Expert: Harmonizing Diverse Visual Priors in MLLMs for Spatial Understanding","abstract":"Multimodal Large Language Models (MLLMs) have demonstrated substantial promise in spatial understanding. Existing works typically incorporate prior knowledge extracted from a pre-trained foundation model to further enhance the spatial awareness of MLLMs. In this paper, we first reveal that when integrating diverse foundation models into MLLMs, different models provide complementary spatial priors that benefit different tasks. Motivated by this, we propose $\\textbf{ViPS}$, a novel multi-model prior framework designed to fully unleash the potential of incorporating multiple $\\textbf{Vi}$sual $\\textbf{P}$riors from diverse models into MLLMs for $\\textbf{S}$patial understanding. Specifically, ViPS introduces an Efficient Prior Proxy to generate multiple foundational priors with minimal inference overhead, and a Dynamic Prior Fusion mechanism to achieve harmonious and context-aware prior fusion and injection from the prior proxies. Extensive experiments demonstrate that ViPS successfully harmonizes diverse visual priors, establishing new state-of-the-art performance across multiple complex spatial reasoning and 3D spatial understanding benchmarks. Project page: https://visual-ai.github.io/vips","authors":["Xiao Lin","Xiaohu Huang","Kai Han"],"published":"2026-07-16T14:31:16Z","updated":"2026-07-16T14:31:16Z","abstract_url":"https://arxiv.org/abs/2607.15054v1","html_url":"https://arxiv.org/html/2607.15054v1","pdf_url":"https://arxiv.org/pdf/2607.15054v1.pdf","matched_keywords":["3d","multimodal"],"source_used":"html","source_text_chars":61994,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, multimodal 相关；摘要显示其主要贡献为：Multimodal Large Language Models (MLLMs) have demonstrated substantial promise in spatial understanding. Existing works typically incorporate prior knowledge extracted from a pre-trained foundation model to further enhance the spatial awareness of MLLMs. In t...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:01+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15048v1","title":"RoGS: Adaptive Meshgrid Gaussian for Large-Scale Road Surface Mapping","abstract":"Road surface mapping plays a crucial role in autonomous driving, supporting high-definition map generation, lane-level perception, and automatic road annotation. Recent mesh-based road surface reconstruction methods have shown promising results, but they still suffer from limited reconstruction quality and high optimization cost, especially in large-scale driving scenarios. To address these limitations, we propose ROADGS-T, a robust and efficient large-scale road surface mapping framework based on adaptive meshgrid Gaussian representation. Specifically, we model the road surface by placing 2D Gaussian surfels on a meshgrid, where each surfel explicitly stores color, semantic, and geometric information. Compared with conventional mesh-based representations and 3D Gaussian primitives, the proposed meshgrid Gaussian representation better matches the thin-surface property of roads while significantly reducing redundant primitives and overlap during optimization. To further improve representation efficiency and structural fidelity, we introduce a road-structure-aware adaptive meshgrid strategy, which allocates denser Gaussian surfels to geometrically or semantically complex regions, such as lane markings, road boundaries, and height discontinuities, while maintaining a compact representation in flat road areas. Moreover, instead of relying on a single nearest vehicle pose, we design a trajectory-consistency-guided pose-robust refinement strategy, which estimates local surface priors from multiple neighboring poses and adaptively weights pose-guided height regularization according to their geometric consistency.","authors":["Tianchen Deng","Zhiheng Feng","Wenhua Wu","Ziming Li","Siting Zhu","Hesheng Wang"],"published":"2026-07-16T14:26:52Z","updated":"2026-07-16T14:26:52Z","abstract_url":"https://arxiv.org/abs/2607.15048v1","html_url":"https://arxiv.org/html/2607.15048v1","pdf_url":"https://arxiv.org/pdf/2607.15048v1.pdf","matched_keywords":["3d","representation"],"source_used":"html","source_text_chars":62151,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, representation 相关；摘要显示其主要贡献为：Road surface mapping plays a crucial role in autonomous driving, supporting high-definition map generation, lane-level perception, and automatic road annotation. Recent mesh-based road surface reconstruction methods have shown promising results, but they stil...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:01+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15041v1","title":"Weakly-Supervised RGB-D Salient Object Detection via SAM-driven Pseudo Annotation and State Space Interaction-based Diffusion","abstract":"Weakly-supervised RGB-D Salient Object Detection (SOD) is explored to reduce the heavy burden of pixel-level annotations. But scribble annotations lack the structure and details of objects, resulting in inaccurate saliency maps. In this paper, we propose a novel scribble-supervised RGB-D SOD method, consisting of a Segment Anything Model (SAM)-driven pseudo annotation generation method (\\emph{SAM-PAG}) and a state space interaction-based conditional diffusion model (\\emph{$S^2$Diff}). Specifically, SAM-PAG is tailored to address the issue of sparse supervision information. In SAM-PAG, we adopt the advanced SAM to expand sparse scribbles to dense pixel-level pseudo annotations through the dual-branch structure and the consistency of segmentation masks. In $S^2$Diff, we adopt the diffusion model to iteratively refine the noisy saliency maps with the guidance of conditional information, generating accurate saliency maps. Naturally, the core of our $S^2$Diff lies in the acquisition of conditional features and the denoising of saliency maps. For the former, we employ a cross-modal conditional generation module to interweave cross-modal features through frequency integration and implicit-explicit state space interaction, effectively achieving global conditional features. For the latter, we employ a context injection module to mitigate noise interference and to enhance object information with the conditional context. With the close cooperation of SAM-PAG and $S^2$Diff, our method outperforms relevant scribble-supervised methods and achieves competitive performance compared to fully-supervised methods on seven datasets. The code and results of our method are available at https://github.com/Switch457/WeakS2Diff_SOD.","authors":["Wenqi Si","Gongyang Li","Shixiang Shi","Weisi Lin"],"published":"2026-07-16T14:21:12Z","updated":"2026-07-16T14:21:12Z","abstract_url":"https://arxiv.org/abs/2607.15041v1","html_url":"https://arxiv.org/html/2607.15041v1","pdf_url":"https://arxiv.org/pdf/2607.15041v1.pdf","matched_keywords":["diffusion"],"source_used":"html","source_text_chars":84621,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 diffusion 相关；摘要显示其主要贡献为：Weakly-supervised RGB-D Salient Object Detection (SOD) is explored to reduce the heavy burden of pixel-level annotations. But scribble annotations lack the structure and details of objects, resulting in inaccurate saliency maps. In this paper, we propose a no...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:01+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15038v1","title":"Video = World + Event Stream","abstract":"We present Wan-Streamer v0.3, which reframes our native-streaming interaction model under a single organizing view: a video is a world plus an event stream. The world is the persistent context in which a video unfolds, including the environment, scene, subjects, ambient acoustic conditions, voice characteristics, and other relatively stable conditions. The event stream is everything that changes over time within that world, including scene or environmental changes, subject behavior, speech, and other sounds. This yields a general-purpose pretraining task over large amounts of real video: given a world and incoming input, predict how the world moves, changes, and responds in real time. The resulting competence can be specialized to a broad family of real-time downstream tasks. We instantiate it on real-time full-duplex audio-visual interaction, where the event stream is the agent's speech together with free-form behavior. Functionally, the model's multimodal understanding process is vision-language-action-like: it maps multimodal user input to language-form speech and behavior actions. Wan-Streamer v0.3 preserves the v0.2 operating point: 640x368 video at 25 FPS, a 160 ms streaming unit, approximately 200 ms model-side response latency, and approximately 550 ms total interaction latency under a 350 ms bidirectional network budget.","authors":["Lianghua Huang","Zhi-Fan Wu","Yupeng Shi","Wei Wang","Mengyang Feng","Cheng Yu","Chen Liang","Junjie He","Chen-Wei Xie","Yu Liu","Jingren Zhou","Ang Wang","Bang Zhang","Baole Ai","Chongyang Zhong","Jinwei Qi","Kai Zhu","Pandeng Li","Peng Zhang","Wenyuan Zhang","Xinhua Cheng","Yitong Huang","Yun Zheng","Yuxiang Bao","Yuzheng Wang","Zhiwei Lin","Zoubin Bi"],"published":"2026-07-16T14:19:42Z","updated":"2026-07-16T14:19:42Z","abstract_url":"https://arxiv.org/abs/2607.15038v1","html_url":"https://arxiv.org/html/2607.15038v1","pdf_url":"https://arxiv.org/pdf/2607.15038v1.pdf","matched_keywords":["video","agent","multimodal"],"source_used":"html","source_text_chars":21545,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, agent, multimodal 相关；摘要显示其主要贡献为：We present Wan-Streamer v0.3, which reframes our native-streaming interaction model under a single organizing view: a video is a world plus an event stream. The world is the persistent context in which a video unfolds, including the environment, scene, subjec...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:01+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14990v1","title":"JADE-GS: Joint Alternating Deblurring Guided by Events in 3D Gaussian Splatting","abstract":"When a camera moves fast during exposure, blur destroys the intra-exposure motion a 3D model needs to recover the sharp scene, while event cameras capture exactly this signal at microsecond resolution. Turning them into reliable 3D supervision faces two obstacles. First, the two restoration priors fail in opposite ways: physics-based event-integration priors preserve edges but accumulate drift; learned networks recover texture but distort boundaries. Second, existing pipelines run in one direction only, so raw event noise or the biases of fixed 2D pseudo-labels pass uncorrected into the geometry. JADE-GS addresses both: a pixel-adaptive routing gate fuses the complementary priors, and the resulting 2D restorer is coupled to a 3D Gaussian Splatting student in a bidirectional loop, where detached, multi-view-consistent renders and a physics-based reblurring constraint regularize the restorer, turning a fixed preprocessor into a geometry-aware predictor. Across synthetic and real benchmarks, JADE-GS attains the best perceptual quality, leading LPIPS and CLIP-IQA on both benchmarks with competitive PSNR and SSIM, and trainsin about one hour under 5 GB on a single consumer GPU while preserving real-time rendering.","authors":["Haoyu Fu","Jiafeng Huang","Yuchen Wang","Shengjie Zhao"],"published":"2026-07-16T13:40:13Z","updated":"2026-07-16T13:40:13Z","abstract_url":"https://arxiv.org/abs/2607.14990v1","html_url":"https://arxiv.org/html/2607.14990v1","pdf_url":"https://arxiv.org/pdf/2607.14990v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14976v1","title":"From Draft to Draft-Free: One-Step Video Object Removal via Privileged Distillation and Fast Planting","abstract":"Video object removal is a fundamental yet challenging task in video editing. Despite recent progress, existing methods typically fall into two categories. Traditional approaches based on optical flow or attention mechanisms often introduce noticeable artifacts and yield unnatural results. In contrast, diffusion-based methods improve visual realism but demand multiple denoising steps, limiting their practicality. To address these issues, we propose From-Draft-to-Draft-Free (D2DF), a framework that distills the ability of transforming coarse drafts into refined videos into a one-step video generation model. Within D2DF, a teacher model is trained to refine low-quality removal results (\"drafts\") into high-fidelity videos by multiple steps. Then, through Prior-Privileged Consistency Distillation (PPCD), we distill this capability into a student model that performs one-step removal conditioned on the draft. To eliminate draft dependency, we introduce a Self-Guided Fast Planting (SGFP) module based on our Temporal Masked Transformer that autonomously generates scene-consistent pseudo-drafts in latent space, enabling a fully draft-free one-step model. Extensive experiments show that both draft-conditioned and draft-free versions achieve state-of-the-art performance on multiple metrics, surpassing traditional and multi-step generative methods in both quality and efficiency. The denoising process for a single video takes only about 1 second.","authors":["Zizhao Chen","Ping Wei","Guang Dai","Jingdong Wang","Mengmeng Wang"],"published":"2026-07-16T13:29:27Z","updated":"2026-07-16T13:29:27Z","abstract_url":"https://arxiv.org/abs/2607.14976v1","html_url":"https://arxiv.org/html/2607.14976v1","pdf_url":"https://arxiv.org/pdf/2607.14976v1.pdf","matched_keywords":["video","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14974v1","title":"On Success and Simplicity: A Second Look at Transferable Vision-Language Attack Pipeline","abstract":"Vision-Language Pre-training Models (VLPMs) are known to be vulnerable to adversarial attacks. Recent transferable attacks on VLPMs have followed a common pipeline with complicated loss functions or multi-stage text/image attacks. However, in this paper, we demonstrate that such a sophisticated attack pipeline can be simpler yet more successful. Specifically, we identify three previously overlooked issues caused by inappropriate cross-modal interactions and excessive operations. To address them, we propose the Simple Vision-Language Attack (SimVLA) pipeline, which observably improves transferability and efficiency. Experiments on four datasets and three downstream tasks validate the superiority of our pipeline. For instance, on Flickr30k text-image retrieval dataset, our SimVLA outperforms the SOTA baseline in R@1 transferability by 8.01\\%-14.71\\%, while consuming only about 35.73\\% of the time and 46.26\\% of the max VRAM. Overall, the superiority of our SimVLA highlights the importance of leveraging domain knowledge (e.g., our proposed cross-modal word identification), while blindly pursuing intricate operations (e.g, complex loss functions and redundant multi-stage designs) may even be harmful. We hope our SimVLA can serve as a simple yet effective backbone for future extensions. Code is available at https://github.com/RYC-98/SimVLA.","authors":["Yuchen Ren","Zhengyu Zhao","Chenhao Lin","Bo Yang","Chao Shen"],"published":"2026-07-16T13:28:59Z","updated":"2026-07-16T13:28:59Z","abstract_url":"https://arxiv.org/abs/2607.14974v1","html_url":"https://arxiv.org/html/2607.14974v1","pdf_url":"https://arxiv.org/pdf/2607.14974v1.pdf","matched_keywords":["retrieval","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14968v1","title":"Stitch-Inferencer: Enhance Endoscopic Video Segmentation and Tracking via Panoramic Reconstruction","abstract":"Surgical video understanding is fundamental to navigation systems. Endoscopic perception is often hindered by a limited field-of-view and frequent instrument occlusions, making spatio-temporal context essential for robust inference. These challenges have motivated video models that aggregate information across frames. However, existing video models typically store past observations implicitly in learned feature representations, often requiring task-specific video training, substantial annotated data, and increased computational cost. We propose Stitch-Inferencer, a real-time, model-agnostic inference framework that replaces implicit feature memory with an explicit image-space panoramic canvas. By stitching valid observations across frames, Stitch-Inferencer preserves previously observed pixels in an online, instrument-free view, expanding the effective field-of-view and providing direct access to regions that are temporarily occluded or absent from the current frame. Downstream segmentation or tracking models are applied to a compact region of interest on the panorama, and their predictions are reprojected to the current frame, enabling existing models to exploit long-range context without retraining. Experiments on anatomy segmentation and point/box tracking demonstrate consistent improvements across diverse baselines while preserving real-time throughput. The stitching module alone runs at over 60 FPS, providing a practical inference-time solution to enhance endoscopic perception in computationally constrained intraoperative environments. Source code will be made publicly available.","authors":["Shunsuke Kikuchi","Atsushi Kouno","Hiroki Matsuzaki"],"published":"2026-07-16T13:24:56Z","updated":"2026-07-16T13:24:56Z","abstract_url":"https://arxiv.org/abs/2607.14968v1","html_url":"https://arxiv.org/html/2607.14968v1","pdf_url":"https://arxiv.org/pdf/2607.14968v1.pdf","matched_keywords":["video","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14966v1","title":"U-shaped Multi-granularity Learning for Vision-Language Models","abstract":"The prompt learning paradigm for vision-language models is effective yet faces a granularity dilemma: global prompts lack fine-grained semantic awareness, while local prompts ignore contextual associations, limiting cross-task generalization. This dilemma exists in dense prediction tasks. Inspired by U-Net, which unifies multi-level representations across granularities, we propose UPrompt, a U-shaped multi-granularity prompt learning framework for vision-language models. Similar to how U-Net integrates fine and coarse features through symmetric encoder-decoder pathways with cross-level connections, UPrompt constructs parallel multi-granularity representations in both visual and textual modalities, where coarse-to-fine cascaded enhancement propagates global context to refine local details, while fine-to-coarse hierarchical supervision ensures semantic consistency across scales. Extensive experiments on 17 benchmarks validate our effectiveness. UPrompt outperforms MAMET and VPKE by 4.1 and 7.3 rSum on MSCOCO, surpasses CoCoA-Mix by 5.09% in base-to-novel generalization, while maintaining competitive performance with minimal overhead (coarse-grained) and matching PSRC with 1/3 cost (medium-grained).","authors":["Biao Chen","Yunqian Yu","Xiangxu Zhao","Zhongshu Chen","Mengmeng Jing","Lin Zuo"],"published":"2026-07-16T13:18:08Z","updated":"2026-07-16T13:18:08Z","abstract_url":"https://arxiv.org/abs/2607.14966v1","html_url":"https://arxiv.org/html/2607.14966v1","pdf_url":"https://arxiv.org/pdf/2607.14966v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14962v1","title":"Multi-Axis Max@K Reinforcement Learning for Representative Diversity in Text-to-Image Generation","abstract":"Text-to-image (T2I) models can synthesize realistic, prompt-aligned images, yet samples generated for the same prompt often cover only a small subset of visually distinct modes. This limits the diversity of images, and for person-centric prompts, can reflect or amplify demographic skew. We formalize this problem as coverage of a predefined set of semantically specified modes, which we call target-mode coverage. We then propose multi-axis max@K, a group-based reinforcement learning objective for improving such coverage in diffusion-based T2I models. Given a group of samples and one score per target category, multi-axis max@K first takes the maximum score across samples for each category and then sums these category-wise maxima. The resulting credit assignment gives a sample positive weight on a category only when it increases that category's group-wise maximum, allowing different samples to contribute to different categories. We first validate the credit-assignment mechanism on a synthetic mixture and on SD3.5-M using deterministic pixel-based color rewards. We then evaluate the same objective on perceived-appearance fairness. Across three automatic evaluators on held-out prompts, multi-axis max@K improves the Fairness Score by 0.23-0.36 relative to the base model, while maintaining image quality and text alignment.","authors":["Ku Onoda","Paavo Parmas","Hiroki Furuta","Soichiro Nishimori","Yuta Oshima","Shohei Taniguchi","Yutaka Matsuo"],"published":"2026-07-16T13:14:21Z","updated":"2026-07-16T13:14:21Z","abstract_url":"https://arxiv.org/abs/2607.14962v1","html_url":"https://arxiv.org/html/2607.14962v1","pdf_url":"https://arxiv.org/pdf/2607.14962v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14945v1","title":"Introspective Attention Modulation for Safe Text-to-Image Generation","abstract":"State-of-the-art flow based text-to-image (T2I) models exhibit remarkable generative abilities but remain vulnerable to producing unsafe content. Prior safety efforts range from concept erasure and prompt filtering to classifier-based gating. However, simple techniques like parameter efficient adaptations of the models easily bypass such guardrails. We introduce a unique principled approach that achieves safety by regulating the model's attention dynamics through inference-time introspection, exhibiting intrinsic robustness. Our method analyzes and rebalances attention activations throughout image synthesis, steering generations away from unsafe concepts while preserving semantic alignment. This introspective control ensures safety of deployed models. Across standard and adversarial safety benchmarks, our approach achieves remarkable safety scores while maintaining or even improving alignment and perceptual quality. Our results reveal that attention-space regulation offers a considerably more promising path to safer diffusion transformer based image generation than the existing concept erasing mechanism.Our code can be accessed at https://basim-azam.github.io/iam/","authors":["Basim Azam","Hossein Rahmani","Naveed Akhtar"],"published":"2026-07-16T12:53:45Z","updated":"2026-07-16T12:53:45Z","abstract_url":"https://arxiv.org/abs/2607.14945v1","html_url":"https://arxiv.org/html/2607.14945v1","pdf_url":"https://arxiv.org/pdf/2607.14945v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14935v1","title":"VideoChat3: Fully Open Video MLLM for Efficient and Generalist Video Understanding","abstract":"Recent advances in video understanding have spanned motion, long video, and streaming interaction, driving this field toward real-world applications. Despite this progress, current open-source models remain limited in several ways. They often struggle to generalize across diverse video types, making them effective only in specific domains. High computational demands further restrict their efficiency and scalability. Moreover, most models are only partially open, with key components such as training code, strategy, or datasets unavailable, which hinders reproducibility and slows community-driven development. To address these issues, we introduce VideoChat3, a fully open, efficient, and generalist video-centric MLLM. VideoChat3 advances video understanding through two complementary designs. For efficiency, we introduce Inflated 3D Vision Transformer (I3D-ViT) and Adaptive Frame Resolution for Streaming Video Perception, which enables efficient spatiotemporal representation and reduces the cost of processing video inputs during training and inference. For effectiveness, we develop a scalable video data synthesis pipeline that curates three diverse, high-quality training datasets: VideoChat3-Academic2M, VideoChat3-LV116K, and VideoChat3-OL617K, covering general, long-form, and streaming video scenarios, improving the model's generalization across domains. By integrating these designs, VideoChat3 achieves a rare balance of broad generalization and computational efficiency. Experiments across general, long-form, and streaming benchmarks demonstrate that VideoChat3 surpasses prior open-source models with equal or larger parameter counts with only 4B parameters and higher efficiency.","authors":["Xinhao Li","Yuhan Zhu","Xiangyu Zeng","Yuhao Dong","Haoning Wu","Zhiqiu Zhang","Yuandong Yang","Changlian Ma","Qingyu Zhang","Yansong Shi","Xinyu Chen","Haoran Chen","Zizheng Huang","Jun Zhang","Kun Ouyang","Lin Sui","Ziang Yan","Yicheng Xu","Chenting Wang","Yinan He","Hongjie Zhang","Yi Wang","Yu Qiao","Yali Wang","Ziwei Liu","Kai Chen","Limin Wang"],"published":"2026-07-16T12:47:59Z","updated":"2026-07-16T12:47:59Z","abstract_url":"https://arxiv.org/abs/2607.14935v1","html_url":"https://arxiv.org/html/2607.14935v1","pdf_url":"https://arxiv.org/pdf/2607.14935v1.pdf","matched_keywords":["video","3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14934v1","title":"Still image and spatial-temporal tomato data enabling detection, segmentation, tracking, and video-instance segmentation using strong and weak labels","abstract":"In this manuscript we release two datasets for visual sensing of tomato plants grown in commercial-like settings and acquired using a robot. The first is BUTom21 which consists of still images and manual annotations. The second is BUTom-ST21 which consists of video-based data and semi-automated annotations through AI-based methods, referred to as pseudo-labels. In both cases, we provide pixel-level labels for the ripeness of the fruit. The aim is to provide the research community a challenging set of real-world imagery to explore methods to sense and estimate the state of tomato plants and their fruit, which is an important horticultural crop. Importantly, the spatial-temporal dataset provides individual fruit count and ripeness information enabling researchers to push the boundaries of field-based phenotyping.","authors":["Michael Halstead","Esra Guclu","Mohamed Farag","Enrico Pallotta","Christian Hund","Ribana Roscher","Maren Bennewitz","Juergen Gall","Cyrill Stachniss","Chris McCool"],"published":"2026-07-16T12:47:55Z","updated":"2026-07-16T12:47:55Z","abstract_url":"https://arxiv.org/abs/2607.14934v1","html_url":"https://arxiv.org/html/2607.14934v1","pdf_url":"https://arxiv.org/pdf/2607.14934v1.pdf","matched_keywords":["video","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14927v1","title":"TanGO: Training-Free 3D Editing via Tangent-Space Guidance and Optimization","abstract":"While recent flow-matching 3D generative models (e.g., VecSet) adopt structured representations, their tokens share global context, causing conventional training-free editing to suffer from semantic artifacts such as collapsed preserved regions or incomplete transformations. To address this, we propose TanGO, a training-free framework that enables adaptive per-token steering in the tangent space of generative dynamics. To realize this selective control, we formulate a one-step optimal control rule and determine the strength of each token's control signal using a von Mises-Fisher inspired directional discrepancy derived from the source and target velocity fields. Experiments show that TanGO substantially reduces structural artifacts and achieves state-of-the-art performance, outperforming existing 3D editing baselines. The code is publicly available at https://github.com/siw00-lim/TanGO.","authors":["Siwoo Lim","Sunjae Yoon","Gwanhyeong Koo","Hyeonseo Yun","Chang D. Yoo"],"published":"2026-07-16T12:42:50Z","updated":"2026-07-16T12:42:50Z","abstract_url":"https://arxiv.org/abs/2607.14927v1","html_url":"https://arxiv.org/html/2607.14927v1","pdf_url":"https://arxiv.org/pdf/2607.14927v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14898v1","title":"FlashDecoder: Real-Time Latent-to-Pixel Streaming Decoder with Transformers","abstract":"Real-time video generation demands fast decoding as much as fast denoising, yet current latent video diffusion models rely on 3D convolutional decoders that are slow and memory-intensive at high resolutions or for long video. We introduce FlashDecoder, a fast, memory-efficient pure-Transformer video decoder that decodes latents to pixels frame by frame. At each step, the current frame attends only to a fixed-size window of past frames through a rolling KV cache. The fixed temporal window keeps decoding fast and memory bounded regardless of video length, enabling constant-latency streaming. Because frames are processed sequentially, temporal causality is enforced without explicit attention masks, enabling training at resolutions up to 1080p and matching the reconstruction quality of convolutional decoders. On the Wan2.1 and Wan2.2 latent spaces, FlashDecoder matches each convolutional decoder in reconstruction quality (e.g., 41.55dB vs. 41.49dB PSNR at 1080p) while decoding 3.6x-4.7x faster with up to 11x less memory on a single H100 GPU. With architecture-aware inference optimizations, the speedup widens to 12x.","authors":["Minguk Kang","Suha Kwak"],"published":"2026-07-16T12:16:12Z","updated":"2026-07-16T12:16:12Z","abstract_url":"https://arxiv.org/abs/2607.14898v1","html_url":"https://arxiv.org/html/2607.14898v1","pdf_url":"https://arxiv.org/pdf/2607.14898v1.pdf","matched_keywords":["video","3d","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14876v1","title":"Rotational Motion-Induced Error Compensation for Phase-Shifting Profilometry-Based Eye Reconstruction","abstract":"With the proliferation of immersive Head-Mounted Displays (HMDs) for Virtual and Augmented Reality (VR/AR), reliable and high-precision eye tracking has become increasingly important. Conventional 2D image-based methods offer low system complexity but remain limited in stability, accuracy, and robustness. Three-dimensional ocular surface reconstruction can provide richer geomet-ric information, and structured light profilometry is particularly attractive because it enables dense and accurate surface measurement. However, Phase-Shifting Profilometry (PSP), which estimates phase from sequentially acquired fringe images, is highly susceptible to motion-induced errors when the eye rotates between frames. This study proposes a rotational motion compensation framework for PSP-based dynamic 3D eye reconstruction. Relative eye rotation is estimated from image-based motion cues using a user-specific 3D eye model in a spherical-coordinate domain. The estimated motion is then used to compensate for camera-pixel mismatch and phase-shift errors caused by inter-frame rotation. A region-wise optimization strategy is further introduced to reduce residual artifacts by inde-pendently refining the compensation strength in different ocular regions. Experiments with a rotating fake eye under non-uniform motion demonstrate that the proposed method substantially suppresses motion-induced deformation and improves reconstruction accuracy. An additional experiment with a non-spherical rigid object indicates that the compensation principle is not restricted to spherical eye geometry. These results establish a practical basis for stable PSP-based dynamic 3D eye reconstruction toward future high-precision eye tracking in immersive environments.","authors":["Seong-Jin An","Sanghoon Jeon","Yatong An","Jae-Sang Hyun"],"published":"2026-07-16T11:46:44Z","updated":"2026-07-16T11:46:44Z","abstract_url":"https://arxiv.org/abs/2607.14876v1","html_url":"https://arxiv.org/html/2607.14876v1","pdf_url":"https://arxiv.org/pdf/2607.14876v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14836v1","title":"Physics-Informed Diffusion for Biomechanically Plausible 3D Sign Language Generation","abstract":"Sign language production, which generates continuous 3D skeletal motion from spoken language input, must simultaneously satisfy two constraints: semantic fidelity, so that a deaf viewer can recognize the intended sequence of glosses, and biomechanical plausibility, so that the generated skeleton respects anatomical constraints. Existing approaches optimize semantic reconstruction through coordinate-based objectives that treat the skeleton as an unstructured vector, thus allowing for bone length drift, joint angle violations, and temporarily locked fingers. We introduce PIDiffSign, a physics-informed diffusion model for gloss-to-pose translation that incorporates anatomical constraints into both the architecture and training objective. The model uses a Transformer encoder-decoder, where the decoder is conditioned on the diffusion time step through adaptive zero-initialized layer normalization and cross-attends to gloss representations. A differentiable geometry module enforces bone length consistency and biologically valid joint angles throughout generation. Training combines anthropomorphic, kinematic, angular, and finger-joint constraints with a contrastive gloss-pose alignment loss and classifier-free guidance for semantically conditioned sampling. Experiments on the PHOENIX14T and CSL-Daily benchmarks show consistent improvements over a strong diffusion baseline in pose accuracy, joint-angle correctness, distributional realism, and back-translation quality. These results demonstrate that physics-informed diffusion improves both motion realism and semantic fidelity for sign language generation.","authors":["Emanuele Colonna","Moises Diaz","Gennaro Vessio","Miguel Angel Ferrer","Giovanna Castellano"],"published":"2026-07-16T11:01:33Z","updated":"2026-07-16T11:01:33Z","abstract_url":"https://arxiv.org/abs/2607.14836v1","html_url":"https://arxiv.org/html/2607.14836v1","pdf_url":"https://arxiv.org/pdf/2607.14836v1.pdf","matched_keywords":["3d","representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14809v1","title":"An LLM-Based Automatic Sportscast Solution for Robot Soccer Matches","abstract":"RoboCup has always been a scenario to develop systems that solve real-world problems. Driven by the main goal of playing against the 2050 FIFA World Cup champions, the RoboCup Soccer leagues need to constantly measure how the research community is progressing. Computing visual statistics from match videos is a crucial way to track this evolution. To address this challenge, this paper introduces a fully autonomous, real-time sports commentator for RoboCup matches. By bridging the gap between raw kinematic tracking and natural language generation, our neuro-symbolic architecture extracts precise statistics from video streams and turns them into fluent, hallucination-free narration. The proposed system is capable of generating statistics and commentary both during live match streaming and in post-game analysis, easily adapting to the new dynamism of the league where different humanoid robots of different sizes share the field. Supplemental materials are available at https://lab-rococo-sapienza.github.io/MARIO/","authors":["Francesco Petri","Michele Brienza","Daniele Nardi","Domenico Daniele Bloisi","Aldo Gangemi","Vincenzo Suriani"],"published":"2026-07-16T10:27:23Z","updated":"2026-07-16T10:27:23Z","abstract_url":"https://arxiv.org/abs/2607.14809v1","html_url":"https://arxiv.org/html/2607.14809v1","pdf_url":"https://arxiv.org/pdf/2607.14809v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14807v1","title":"TAMF-VTON: Texture-Aware Mask-Free Virtual Try-On via High-Fidelity Image Synthesis","abstract":"Recent diffusion-based virtual try-on (VTON) methods remain limited by their reliance on segmentation masks, insufficient preservation of fine-grained textures, and limited support for arbitrary multi-garment compositions. Consequently, existing approaches still face significant challenges in real-world e-commerce deployment. We present TAMF-VTON, a texture-aware, mask-free framework that enables high-fidelity image synthesis under practical unconstrained conditions. Our method requires no human parsing or inpainting masks at inference time and supports diverse garment styles, categories, and quantities, enabling the simultaneous transfer of multiple items while preserving body structure and intricate texture details. This is achieved through a unified generative pipeline with three key components: (1) a lightweight Mixture-of-Experts (MoE) adaptation scheme that enables efficient fine-tuning without compromising the base model's general editing capabilities; (2) a frequency-domain supervision mechanism that explicitly optimizes high-frequency spectral consistency to preserve high-fidelity textures; and (3) a robust data curation pipeline employing an adaptive inpainting strategy to simulate the inverse VTON process for high-quality training pair generation. Extensive experiments demonstrate that our approach outperforms state-of-the-art methods in both quantitative metrics and perceptual quality. Optimized for efficiency, the model achieves inference in under 15 seconds per image on an NVIDIA RTX 4090 with INT4 quantization. By combining mask-free operation, flexible multi-garment composition, faithful texture preservation, and efficient inference on consumer hardware, TAMF-VTON demonstrates a commercially viable solution for scalable deployment in real-world digital fashion scenarios. The project is available at https://www.style3d.ai/ai-photoshoot/virtual-clothing-try-on.","authors":["Jie Wang","Qian He","Gaofeng He","Xiaogang Jin","Huamin Wang"],"published":"2026-07-16T10:26:27Z","updated":"2026-07-16T10:26:27Z","abstract_url":"https://arxiv.org/abs/2607.14807v1","html_url":"https://arxiv.org/html/2607.14807v1","pdf_url":"https://arxiv.org/pdf/2607.14807v1.pdf","matched_keywords":["3d","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14765v1","title":"Rare Concept Generation via Counterfactual Inference in Diffusion Models","abstract":"Rare concept generation focuses on synthesizing customized images conditioned on text prompts that describe objects with unusual attributes. Previous works failed to align the generated images with rare concepts, resulting in incorrect attribute rendering or inconsistent composition of concepts. Such failures, as we observed, stem from the inherent common knowledge bias in the training stage of diffusion models, where objects are strongly associated with their common attributes, making it difficult to break these associations when generating rare concepts. To address such challenges, in this paper, we propose a novel Counterfactual Inference-based Diffusion approach, dubbed CI-Diff. CI-Diff blocks the interference of the model's inherent common knowledge bias and utilizes the Natural Direct Effect to capture the independent influence of the text prompt of rare concepts on image generation so that decoupling the unusual attributes from the rare concepts. To this end, we reformulate the classifier-free guidance mechanism to highlight the atypical attributes. To the best of our knowledge, we are the first to introduce causal inference into the rare concept generation task. Extensive experiments on the RareBench benchmark validate the superiority of CI-Diff over state-of-the-art diffusion models. Our code can be accessed from https://github.com/200204jzy/CI-Diff.","authors":["Zhengyuan Jiang","Haipeng Liu","Meng Wang","Yang Wang"],"published":"2026-07-16T09:49:06Z","updated":"2026-07-16T09:49:06Z","abstract_url":"https://arxiv.org/abs/2607.14765v1","html_url":"https://arxiv.org/html/2607.14765v1","pdf_url":"https://arxiv.org/pdf/2607.14765v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14749v1","title":"WanSong v1.0 Technical Report","abstract":"Music generation foundation models have recently attracted significant industry attention. However, achieving efficient generation and high-fidelity long-form audio while supporting controllability remains challenging. To address these needs, we present \\textbf{WanSong}, a simple yet powerful approach for long-form, commercial-grade song generation. Unlike autoregressive (AR) and cascaded multi-stage pipelines (\\eg, AR followed by diffusion), \\textbf{WanSong} is a pure diffusion-based model that directly generates high-fidelity, multilingual songs up to 5 minutes and outputs dual stems (vocals and background music) in a single run. In addition, our diffusion framework enables faster inference through step-distillation, and offers an efficient pathway for fine-tuning and customization to support downstream editing tasks.","authors":["Binghui Chen","Pandeng Li","Yu Liu","Jingren Zhou"],"published":"2026-07-16T09:34:59Z","updated":"2026-07-16T09:34:59Z","abstract_url":"https://arxiv.org/abs/2607.14749v1","html_url":"https://arxiv.org/html/2607.14749v1","pdf_url":"https://arxiv.org/pdf/2607.14749v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14739v1","title":"FoMoVLA: Bridging Visual Foresight and Motion Guidance for Vision-Language-Action Models","abstract":"Vision-Language-Action (VLA) models have achieved impressive results in visuomotor policy learning, yet remain fundamentally reactive, mapping current observations and language to actions without explicit forward prediction of world dynamics. Existing visual foresight methods predict future visual states but lack explicit motion guidance: they show where to go but not how to get there. We argue that future feature prediction and sparse point tracking are naturally complementary: the former provides the goal state, while the latter captures the continuous motion path toward it. We propose FoMoVLA, a framework that augments VLA representations with explicit spatio-temporal supervision by jointly learning future feature foresight and sparse 2D point tracking, enhancing the continuous action policy. FoMoVLA introduces compact foresight tokens to decode future feature states, decodes sparse temporal 2D point trajectories to model compact geometric motion, and couples both through a lightweight future-conditioned cross-attention module that enables consistent reasoning between anticipated states and point dynamics. Extensive experiments on LIBERO, RoboCasa GR-1 Tabletop, and LIBERO-Plus demonstrate state-of-the-art performance and strong zero-shot generalization. Project page is available at https://liauto-research.github.io/FoMoVLA.","authors":["Wei Li","Peijin Jia","Yuan Ma","Xuefeng Jiang","Titong Jiang","Sheng Sun","Yujian Li","Xin Wen","Han Hong","Zhikang Liu","Bailin Li","Kun Zhan"],"published":"2026-07-16T09:04:50Z","updated":"2026-07-16T09:04:50Z","abstract_url":"https://arxiv.org/abs/2607.14739v1","html_url":"https://arxiv.org/html/2607.14739v1","pdf_url":"https://arxiv.org/pdf/2607.14739v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14737v1","title":"GeoDetect: Geometric Adversarial Detection for VLPs","abstract":"Vision-language pre-trained models (VLPs) are widely used in real-world applications. However, they remain vulnerable to adversarial attacks. Although adversarial detection methods have demonstrated success in single-modality settings (either vision or language), their effectiveness and reliability in multimodal models such as VLPs remain largely unexplored. In this work, we study the geometry of VLP embedding spaces and observe structured anisotropy that differs from unimodal vision models. Our theoretical analysis shows that under this anisotropic structure, adversarial attacks increase the expected geometric separation between clean and adversarial examples (AEs). Specifically, we demonstrate that AEs consistently exhibit greater expected distances to randomly sampled points than their clean counterparts, indicating that AEs tend to push representations out of manifold regions. Building on these insights, we propose GeoDetect, which leverages these off-manifold deviations via geometric scores to identify AEs. Through comprehensive evaluations, we show that our approach reliably detects AEs across diverse VLP architectures and threat settings, covering unimodal and multimodal attacks as well as adaptive attacks, thereby providing a robust and practical approach to improving the safety and reliability of these models.","authors":["Afsaneh Hasanebrahimi","Hanxun Huang","Christopher Leckie","James Bailey","Sarah Erfani"],"published":"2026-07-16T09:02:38Z","updated":"2026-07-16T09:02:38Z","abstract_url":"https://arxiv.org/abs/2607.14737v1","html_url":"https://arxiv.org/html/2607.14737v1","pdf_url":"https://arxiv.org/pdf/2607.14737v1.pdf","matched_keywords":["representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14728v1","title":"VQ-Touch: A Data-Efficient Tactile Generation Framework Across Sensors and Scenarios","abstract":"Tactile image generation significantly reduces the dependency on expensive and wear-prone sensors by synthesizing high-fidelity tactile data, offering an efficient solution for tactile information acquisition in robotic perception and human-machine interaction systems. However, existing methods depend on large-scale, diverse datasets from specific sensors and lack efficient data utilization and robust generalization capabilities, struggling in vision-limited environments. To address this, we introduce VQ-Touch, a tactile generation framework that supports both cross-sensor and multi-scenario applications. Specifically, to efficiently extract complex deformation and texture features from the data, we propose DM-VQGAN, an effective tactile representation learner. Furthermore, we introduce a discrete diffusion decoder with a unified conditioning interface, supporting multimodal generation tasks such as images and labels, and enhances the model's generalization capability through few-shot mixed training, thus achieving compatibility with current mainstream sensors and their variants. Experiments show that VQ-Touch surpasses state-of-the-art methods in multiple tasks.","authors":["Kailin Lyu","Long Xiao","Jianing Zeng","Di Wu","Lin Shu","Jie Hao"],"published":"2026-07-16T08:53:41Z","updated":"2026-07-16T08:53:41Z","abstract_url":"https://arxiv.org/abs/2607.14728v1","html_url":"https://arxiv.org/html/2607.14728v1","pdf_url":"https://arxiv.org/pdf/2607.14728v1.pdf","matched_keywords":["representation","multimodal","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14721v1","title":"Multimodality as Supervision: Self-Supervised Specialization to the Test Environment via Multimodality","abstract":"Cross-modal learning, i.e., learning to predict one modality from another, is a fundamental mechanism for self-supervision via leveraging multimodality. Many practical applications, e.g., deploying a household robot, involve devices that are equipped with a rich set of sensors that enable multimodal sensing in their test environment. This presents an opportunity to apply cross-modal learning to the multimodal data sensed by these devices to learn representations. Findings in developmental psychology also suggest that biological agents leverage it to build an effective representation of their surroundings. To study this, we propose a controlled setup, where we restrict a user device to just a given test environment. It results in a specialization setup where we attempt to develop a performant model for this specific test environment. Under this setup, we develop Test-Space Training (TST), which performs multimodal data collection in the test environment and performs self-supervised pre-training on it. We evaluate these models on various downstream tasks in the same environment. Under this setup, we find various interesting insights, such as collecting rich multimodal data only from the test environment and leveraging cross-modal learning, we can achieve competitive results with generalist models (e.g., DINOv2 and CLIP) pre-trained on large-scale internet datasets. This enables an alternative scenario where the need for external Internet-scale datasets for pre-training models is reduced. We also present a set of analyses and ablations that raise intriguing points on substituting data with (multi)modality, and how varying pre-training data enables a tradeoff between a model's abilities to specialise to a test environment, and generalize to held-out spaces.","authors":["Kunal Pratap Singh","Ali Garjani","Rishubh Singh","Muhammad Uzair Khattak","Efe Tarhan","Jason Toskov","Andrei Atanov","Oğuzhan Fatih Kar","Amir Zamir"],"published":"2026-07-16T08:36:54Z","updated":"2026-07-16T08:36:54Z","abstract_url":"https://arxiv.org/abs/2607.14721v1","html_url":"https://arxiv.org/html/2607.14721v1","pdf_url":"https://arxiv.org/pdf/2607.14721v1.pdf","matched_keywords":["agent","representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14720v1","title":"Causal-Adversarial Probing of Clinical Covariates for Prostate MRI Grading","abstract":"Deep learning models for prostate MRI-based cancer grading may encode clinical covariates that either reflect useful disease-related signal or non-generalising shortcut information, but their role is usually assumed. We propose a causal-reasoning framework for probing covariate dependence in MRI-based International Society of Urological Pathology (ISUP) Grade Group prediction. Rather than treating mpMRI as a direct cause of grade, we model MRI appearance and ISUP grade as observations of latent tumour pathology, and test whether candidate clinical variables act as nuisance correlates, disease-related proxies, or irrelevant covariates in the learned representation. We implement this using an adversarial framework that suppresses the decodability of individual clinical covariate at a time while preserving MRI-based grade prediction. The approach is developed and evaluated on 2,903 prostate MRI examinations, with external validation on 576 patients. We report a set of interesting and previously under-explored imaging-to-clinical-variable interactions in the context of deep learning generalisation. For examples, in binary ISUP Grade Group $\\geq2$ classification, suppressing age, BMI, and alcohol use improved AUC by 1.23%, 0.84%, and 1.42%, respectively (all p < 0.05), suggesting reduced non-generalising covariate information; In contrast, suppressing PSA and prostate volume degraded AUC by 1.91% and 7.61% (all p < 0.001), indicating that these variables carried task-relevant signal. These findings show that adversarial covariate suppression can provide a practical representation-level analysis for distinguishing potentially harmful dependence from informative signal in prostate MRI grading models.","authors":["Yipei Wang","Shiqi Huang","Wen Yan","Weixi Yi","Dean C. Barratt","Mark Emberton","Daniel C. Alexander","Veeru Kasivisvanathan","Yipeng Hu"],"published":"2026-07-16T08:36:34Z","updated":"2026-07-16T08:36:34Z","abstract_url":"https://arxiv.org/abs/2607.14720v1","html_url":"https://arxiv.org/html/2607.14720v1","pdf_url":"https://arxiv.org/pdf/2607.14720v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14711v1","title":"VideoSEMA: a scalable and efficient Mamba-like attention for video understanding","abstract":"We present for video understanding (classification) a split space-time attention model, VideoSEMA, consisting of a scalable and efficient Mamba-like attention (SEMA) block in space and a softmax temporal attention in time. In each frame, SEMA attention applies a local window attention in parallel with a global averaging in a Mamba macro-architecture, which is called Mamba-like. Under certain rank conditions, we prove that the computationally cheaper split space-time attention is equivalent to full space-time attention. On benchmark K400 data sets, VideoSEMA out-performs heavier vision transformer and Mamba models. On benchmark SSv2 data, VideoSEMA leads in top-1 accuracy among models of similar parameter sizes. As image resolution scales up from standard $224^2$ to $1024^2$ on K400 and without fine-tuning, VideoSEMA degrades much more gracefully than VideoMamba in accuracy. It is promising to extend VideoSEMA to longer videos with a dilated/sparse temporal attention.","authors":["Nhat Thanh Tran","Fanghui Xue andShuai Zhang","Jiancheng Lyu","Yunling Zheng","Yingyong Qi","Jack Xin"],"published":"2026-07-16T08:22:08Z","updated":"2026-07-16T08:22:08Z","abstract_url":"https://arxiv.org/abs/2607.14711v1","html_url":"https://arxiv.org/html/2607.14711v1","pdf_url":"https://arxiv.org/pdf/2607.14711v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14710v1","title":"Variational Inference for Bird's Eye View Segmentation in Autonomous Driving","abstract":"The bird's eye view (BEV) has emerged as a pivotal approach for environmental perception in autonomous driving, providing a unified spatial representation for vehicles. Nevertheless, despite BEV's significance in addressing the challenges inherent to autonomous driving, effectively fusing data from multiple camera sensors and operating in complex external driving environments remains a considerable challenge. To mitigate this issue, we recast the BEV segmentation problem within a variational inference framework. In this paper, we propose a novel transformer-based variational flow transformation network for BEV segmentation, denoted as TVB. Our architecture implicitly learns the mapping from multiple camera views to a unified canonical BEV map during training by exploiting posterior BEV supervision. TVB employs a conditional variational auto encoder (CVAE) as its backbone and produces multiple BEV map candidates. To augment the realism of the generated BEV maps, we integrate normalizing flows into the map generation process, enabling the construction of more complex and expressive probability distributions. Furthermore, we design a BEV-attention fusion (BAF) module that harnesses attention mechanisms to adaptively integrate the multiple candidate BEV maps. Experimental results, evaluated on both the nuScenes and OPV2Vdatasets, demonstrate that our proposed method achieves superior performance in multi-camera view BEV segmentation and lane environment perception.","authors":["Jingyue Shi","Huaicheng Li","Junhui Zhao","Yanxiang Jiang"],"published":"2026-07-16T08:20:37Z","updated":"2026-07-16T08:20:37Z","abstract_url":"https://arxiv.org/abs/2607.14710v1","html_url":"https://arxiv.org/html/2607.14710v1","pdf_url":"https://arxiv.org/pdf/2607.14710v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14703v1","title":"Pretraining Multiple Instance Learning Networks with Multi-Teacher Distillation from Pathology Slide Foundation Models","abstract":"Multiple instance learning (MIL) has become the main paradigm for whole-slide image (WSI) analysis in computational pathology. However, existing MIL aggregators are still typically trained from scratch for each downstream task, relying on limited slide-level labels to learn both aggregation mechanisms and downstream discriminative representations simultaneously. As a result, they often suffer from unstable optimization, overfitting, and limited transferability. Similar to pretrained ResNet and Vision Transformer models in natural image learning, MIL also requires reusable pretrained initialization. However, high-quality slide-level pretraining data remain scarce, and MIL models are usually lightweight and weakly supervised, making large-scale pretraining difficult in practice. To address this challenge, we propose a distillation-based pretraining framework for MIL, which leverages two slide-level foundation models, TITAN and CARE, as teachers to transfer their representational knowledge into a diverse set of MIL architectures. To effectively balance supervision from different teachers, we further introduce an angular dispersion normalized distillation loss. The distilled weights are then used as initialization for downstream adaptation. We conduct systematic evaluations on 15 benchmark datasets under both linear probing and full-parameter fine-tuning, and further validate its advantages in few-shot scenarios. Experimental results show that pretraining generally improves MIL aggregators over from scratch training, especially in linear-probing and few-shot settings, while maintaining the computational efficiency of lightweight MIL models. Code is available at https://github.com/fu0201/MIL_Pretrained.","authors":["Mingxi Fu","Jiawen Li","Renao Yan","Jiali Hu","Qiehe Sun","Tian Guan","Yonghong He"],"published":"2026-07-16T08:04:25Z","updated":"2026-07-16T08:04:25Z","abstract_url":"https://arxiv.org/abs/2607.14703v1","html_url":"https://arxiv.org/html/2607.14703v1","pdf_url":"https://arxiv.org/pdf/2607.14703v1.pdf","matched_keywords":["representation","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14702v1","title":"Team RAS in 11th ABAW Competition: Multimodal Ambivalence Recognition Approach","abstract":"Automatic recognition of ambivalence and hesitancy is challenging because these states may be expressed through inconsistent linguistic, acoustic, facial, and contextual patterns, while top-performing systems often rely on computationally expensive ensembles. We present a single text-centered multimodal approach for video-level ambivalence and hesitancy recognition for the 11th Affective & Behavior Analysis in-the-Wild (ABAW) Challenge. The proposed approach combines linguistic, acoustic, facial, and scene features using text-centered multimodal fusion model. Text Residual Fusion treats text as the anchor modality and applies gated residual adjustments based on the other modalities. Experiments on the Behavioural Ambivalence/Hesitancy (BAH) corpus confirm that text is the strongest unimodal modality. The Text Residual Fusion model achieves an average Macro F1-score (MF1) of 75.14% across the Development and Public Test subsets. On the Private Test subset, it reaches an MF1 of 78.24%, outperforming the text model by 4.03%. These results demonstrate that complementary multimodal information can improve recognition performance without requiring a large model ensemble.","authors":["Elena Ryumina","Maxim Markitantov","Alexandr Axyonov","Fedor Shchetinin","Timur Abdulkadirov","Dmitry Ryumin","Alexey Karpov"],"published":"2026-07-16T08:04:23Z","updated":"2026-07-16T08:04:23Z","abstract_url":"https://arxiv.org/abs/2607.14702v1","html_url":"https://arxiv.org/html/2607.14702v1","pdf_url":"https://arxiv.org/pdf/2607.14702v1.pdf","matched_keywords":["video","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14681v1","title":"ReBind: Multi-Reference Video Editing via Structured Instructions with Explicit Reference Relationships","abstract":"Recent diffusion-based video generation models have made significant progress in multi-reference image-conditioned video editing. However, existing methods still struggle to coordinate information from multiple visual sources accurately. We identify a critical deficiency in existing approaches. Existing editing instructions lack explicit reference relationships, and most multimodal large language models (MLLMs) cannot generate them reliably. To address this problem, we propose ReBind, a systematic framework that introduces semantic instructions with embedded reference tokens as the intermediate representation for multi-reference image-conditioned video editing. Our key insight is embedding reference tokens at semantic positions to eliminate ambiguity and establish precise bindings between visual attributes and their sources. We develop ReBind-Instruct, a specialized MLLM that learns to establish explicit bindings between visual attributes and their reference sources through a two-stage progressive scheme for precise reference relationships. We further develop ReBind-Edit, which enables lightweight adaptation of text-to-video models to coordinate multiple references by binding visual attributes to their designated sources. Extensive experiments demonstrate that ReBind substantially outperforms general-purpose MLLMs in instruction quality and achieves state-of-the-art performance among open-source methods on reference image conditioned video editing. Our project webpage: https://rebind-mrv2v.github.io/.","authors":["Xinyu Liu","Shihao Li","Weihong Lin","Xinlong Chen","Yang Shi","Yujin Han","Yiyang Cai","Yanghao Wang","Ruibin Yuan","Yuanxing Zhang","Pengfei Wan","Wenhan Luo","Yike Guo"],"published":"2026-07-16T07:43:27Z","updated":"2026-07-16T07:43:27Z","abstract_url":"https://arxiv.org/abs/2607.14681v1","html_url":"https://arxiv.org/html/2607.14681v1","pdf_url":"https://arxiv.org/pdf/2607.14681v1.pdf","matched_keywords":["video","representation","multimodal","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14660v1","title":"VIABench: A Comprehensive Video Benchmark Collected from Blind Individuals for Visual Impairment Assistance","abstract":"Visually impaired individuals (VIIs) encounter significant daily challenges due to limited access to visual information. Although Multimodal Large Language Models (MLLMs) have achieved impressive results on general vision and language tasks, their practical utility in real-world blind assistance still remains largely underexplored. To fill this gap, we introduce VIABench, a comprehensive video benchmark specifically designed to evaluate MLLMs in Visually Impaired Assistance scenarios using first-person videos recorded or shared by VIIs themselves. VIABench defines three core tasks, each targeting a distinct requirement in visual assistance. Proactive Reminder: Assesses the model's ability to interpret ongoing video content while proactively anticipating and verbally describing upcoming navigation-critical events; Visual Question Answering (VQA): Evaluates the model's capacity to answer user-posed questions about the environment or objects within the video; Vision-Guided Interaction: Tests context-aware reasoning to accomplish intentional interactions between user and environment. To ensure a robust and fair evaluation, we propose a rigorous benchmarking pipeline that supports both online (real-time) and offline settings. Our experiments demonstrate that current MLLMs still struggle to deliver comprehensive support for VIIs, especially in the Proactive Reminder task, which demands accurate anticipation and real-time responsiveness. We hope VIABench will drive future research toward developing customized MLLMs for real-world assistance, ultimately improving navigation and interaction experiences for visually impaired individuals. Code and data will be released at https://github.com/MCG-NJU/VIABench.","authors":["Yunfeng Liu","Yuandong Yang","Jiarui Han","Zhenpeng Huang","Yuqing Tang","Xiangyu Zeng","Gangshan Wu","Limin Wang"],"published":"2026-07-16T07:25:17Z","updated":"2026-07-16T07:25:17Z","abstract_url":"https://arxiv.org/abs/2607.14660v1","html_url":"https://arxiv.org/html/2607.14660v1","pdf_url":"https://arxiv.org/pdf/2607.14660v1.pdf","matched_keywords":["video","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14645v1","title":"Autoregressive Modeling of Film with Applications in Video Montage","abstract":"This work introduces FilmGPT, an autoregressive transformer designed to address the challenge of video montage--turning a collection of raw, \"unwatchable\" footage into coherent cinematic sequences. Inspired by language learning in modern LLMs, we train a long-context autoregressive transformer on a large corpus of movies. The aim is to implicitly capture the \"grammar\" of film directly from data rather than from hand-coded rules. Unlike other generative models, FilmGPT does not generate any new video frames. Instead, at inference time, we introduce a footage-constrained decoding algorithm to select the best next shot from the input raw footage according to the statistical patterns learned from films. We first evaluate these learned statistics directly by using the FilmGPT autoregressive model for next shot prediction on a standard benchmark of shot sequence ordering, outperforming the previous state of the art. We then evaluate our footage-constrained decoding algorithm on the full film editing task via a user study, and find that our FilmGPT-based editing significantly outperforms previous approaches. Finally, we demonstrate the applicability of FilmGPT to a wide range of applications in video montage, from automatic video segment trimming to human-in-the-loop film editing.","authors":["Marcelo Sandoval-Castañeda","Fabian Caba Heilbron","Shiry Ginosar","Bryan Rusell","Josef Sivic","Alexei A. Efros","Greg Shakhnarovich"],"published":"2026-07-16T07:13:54Z","updated":"2026-07-16T07:13:54Z","abstract_url":"https://arxiv.org/abs/2607.14645v1","html_url":"https://arxiv.org/html/2607.14645v1","pdf_url":"https://arxiv.org/pdf/2607.14645v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14635v1","title":"Action QFormer: Structured Representation Shaping under Action Supervision in Vision-Language-Action Models","abstract":"Action supervision in vision-language-action (VLA) models is often treated as a downstream objective for learning action prediction. In this paper, we study it instead as a force that shapes inherited multimodal representations. We show that this shaping has a dual effect: it is necessary for forming action-compatible representations, but when action supervision is applied too directly to the inherited multimodal pathway, it can also destabilize representations that support language-side processing and object grounding. To address this tension, we introduce Action QFormer, a query-based action-facing interface that uses instruction-conditioned queries to reorganize inherited multimodal information into action-facing representations before downstream action generation. In zero-shot sim-to-real navigation, Action QFormer improves average closed-loop task success from 18.8% to 56.3%, raises fixed-instruction action-generation correctness from 22.5% to 75.5%, and nearly eliminates out-of-distribution instruction generations. Further analyses show that Action QFormer changes how action supervision shapes inherited multimodal representations, reducing broad upstream rewriting while preserving targeted and sometimes constructive action-supervised adaptation. These results suggest that improving VLA performance requires not only stronger pretrained backbones, but also better ways of selecting and organizing inherited multimodal information while controlling how it is shaped under action supervision.","authors":["Yufeng Ji","Wenhao Tang","Haoyi Niu","Koushil Sreenath","Yi Wu","Zhongyu Li"],"published":"2026-07-16T06:59:39Z","updated":"2026-07-16T06:59:39Z","abstract_url":"https://arxiv.org/abs/2607.14635v1","html_url":"https://arxiv.org/html/2607.14635v1","pdf_url":"https://arxiv.org/pdf/2607.14635v1.pdf","matched_keywords":["representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14631v1","title":"Knowing You at First Glance: Inferring Apparent Personality from Faces","abstract":"Inferring apparent personality from facial images is important in social scenarios for embodied agents in human-robot interaction. Unlike inferring intrinsic personality traits via conversation, this task models first-impression personality perception based solely on facial appearance before interaction begins. Existing studies mainly focus on the Big Five personality model and often rely on language or multimodal inputs. As a result, it remains unclear whether facial cues alone can support meaningful associations with perceived personality traits. This question is particularly relevant for MBTI types, which are widely used in practice and more readily interpretable by large language models. To this end, we propose \\textbf{GlanceFace}, an end-to-end framework for apparent personality inference leveraging vision-language models to introduce semantic priors and a semantic-enhanced facial representation module to capture subtle personality-related cues, together with an uncertainty-aware learning strategy to handle noisy and subjective annotations. Extensive experiments demonstrate strong performance on MBTI-based apparent personality benchmarks and reveal relationships between facial characteristics and perceived personality traits, highlighting its potential to support adaptive initial interaction strategies for embodied agents. The code and dataset are available at https://github.com/MrHuan3/GlanceFace.","authors":["Shuhuan Chen","Xiangyu Zhu","Weisong Zhao","Haichao Shi","Xiao-Yu Zhang","Zhen Lei"],"published":"2026-07-16T06:48:11Z","updated":"2026-07-16T06:48:11Z","abstract_url":"https://arxiv.org/abs/2607.14631v1","html_url":"https://arxiv.org/html/2607.14631v1","pdf_url":"https://arxiv.org/pdf/2607.14631v1.pdf","matched_keywords":["agent","representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14595v1","title":"MagicPrompt: Ultra-Lightweight Prompt Tuning for Video Generation","abstract":"Large-scale video diffusion models (VDMs) deliver strong generation performance, but full fine-tuning for downstream tasks incurs prohibitive computational costs. Existing parameter-efficient fine-tuning (PEFT) methods have two critical flaws on billion-scale models: they still require substantial trainable parameters, and reward-based training suffers from noise-induced optimization instability in condition-guided tasks. We propose MagicPrompt, a lightweight framework that achieves extreme parameter efficiency and stable reward optimization. It first adopts Attention-Embedded Prompt Tuning, which steers generation via lightweight soft prompts with orders of magnitude fewer parameters while preserving pre-trained knowledge. It further introduces Dual-Space Reward Feedback Optimization, which uses self-supervised latent objectives to improve condition-guided reward training. Experiments show MagicPrompt reaches competitive performance with less than 1\\% trainable parameters and notably reduces training costs.","authors":["Yinhan Zhang","Dinwei Tan","Xianghao Kong","Yue Ma","Yeying Jin","Anyi Rao"],"published":"2026-07-16T05:46:59Z","updated":"2026-07-16T05:46:59Z","abstract_url":"https://arxiv.org/abs/2607.14595v1","html_url":"https://arxiv.org/html/2607.14595v1","pdf_url":"https://arxiv.org/pdf/2607.14595v1.pdf","matched_keywords":["video","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14581v1","title":"Multi-LLM Collaborative MRI Report Generation for Visual Instruction Tuning in Brain Oncology","abstract":"Recent advances in large language models (LLMs) and their extension to vision-language models (VLMs) have made it easier to combine text and images for tasks such as report generation. Existing VLMs in medicine typically focus on 2D images (chest X-rays), and their extension to 3D imaging has been difficult because of the lack of paired 3D imaging-text data. Thus, we introduce a new method for creating a 3D image-text dataset for brain oncology using 3D MRI scans of glioma and meningioma cases. We use a cooperative system in which several LLMs work together to generate and check reports, ensuring that they are accurate and clear. By leveraging the new 3D MRI-text dataset, we further build a VLM that converts MRI scans into tokens and aligns them with text instructions. Our VLM performed better in report generation and visual question answering tasks than other 2D and 3D methods. Our method not only improves the quality of reports but also helps with better diagnosis and treatment in brain oncology.","authors":["Sinyoung Ra","Jonghun Kim","Hyunjin Park"],"published":"2026-07-16T05:21:47Z","updated":"2026-07-16T05:21:47Z","abstract_url":"https://arxiv.org/abs/2607.14581v1","html_url":"https://arxiv.org/html/2607.14581v1","pdf_url":"https://arxiv.org/pdf/2607.14581v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14580v1","title":"Advanced Image Generation: Negative Prompt Optimization and Latent Classifier Guidance","abstract":"We present a novel system that integrates negative prompt optimization via a fine-tuned sequence-to-sequence LLM and latent-space classifier guidance to improve the quality of images generated by Stable Diffusion. Our approach automatically generates optimized negative prompts, and employs a CNN-RNN hybrid classifier to evaluate and guide diffusion steps, rolling back low-quality latent updates. Experimental results demonstrate that our dual-guidance framework reduces artifacts and improves semantic fidelity compared to baseline diffusion.","authors":["Vaddi Charan Sai Nandan Reddy","Harini B","Chandana M S"],"published":"2026-07-16T05:21:17Z","updated":"2026-07-16T05:21:17Z","abstract_url":"https://arxiv.org/abs/2607.14580v1","html_url":"https://arxiv.org/html/2607.14580v1","pdf_url":"https://arxiv.org/pdf/2607.14580v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14579v1","title":"Skeleton: Visual Authoring of Non-visual Data Experiences","abstract":"When sighted practitioners author accessible data visualizations, they build navigation structures (the nodes, edges, and input bindings that govern how assistive technologies traverse an interface) entirely in code, with no visual representation. Without a representation to react to, practitioners cannot develop judgment about what makes navigation good or bad, and the quality ceiling of non-visual experiences is set by the absence of a feedback loop. We address this problem through longitudinal co-design with practitioners across cartography, design systems, and open-source visualization, and make three contributions. First, we introduce an Inspector that renders navigation graphs as interactive node-link diagrams, and a Dimensions API that expresses navigation in terms of data dimensions rather than explicit graph construction. Second we present Skeleton, a direct-manipulation authoring environment in which the properties of an accessible navigation structure are translated into visual representations authors can observe and manipulate. Key techniques include a dual-view editor that simultaneously shows the system's navigation model and the end user's spatial experience, a scaffolding engine that automates spatial node placement by repurposing a visualization rendering pipeline, a live label-template editor with real-time screen-reader-output preview, and a testing mode that makes traversal sequence visually trackable. Third, we evaluate Skeleton through an in-situ study with 8 practitioners across visualization design, engineering, and research. Making navigation structure visible changed how practitioners engaged with accessible design: they reconsidered the architecture of their own visualizations, attended to a broader range of input modalities, and shifted from treating accessibility as a compliance task to treating it as a design problem. (abstract shortened for arxiv)","authors":["Frank Elavsky","Chieri Nnadozie","Lucas Nadolskis","Patrick Carrington","Dominik Moritz"],"published":"2026-07-16T05:16:17Z","updated":"2026-07-16T05:16:17Z","abstract_url":"https://arxiv.org/abs/2607.14579v1","html_url":"https://arxiv.org/html/2607.14579v1","pdf_url":"https://arxiv.org/pdf/2607.14579v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14560v1","title":"Breaking the Model Forgetting Cycle in Long-Incremental 3D Object Detection","abstract":"Incremental 3D object detection requires a detector to learn novel object classes while remembering previously learned ones over sequentially arriving data. Previous methods, primarily based on pseudo-labeling, perform reasonably in short-incremental stages but still suffer from severe model forgetting when dealing with long-incremental sequences. We investigate this failure and reveal a detrimental self-reinforcing cycle: data distribution shift of novel classes causes model forgetting on old classes, which further produces accumulated error in pseudo-labeling that exacerbates model degradation. To address this issue, we draw inspiration from the human learning process and propose the \\emph{Learning-Dynamics-driven Memory and Review} (LDMR) framework. LDMR monitors per-class detection quality at periodic training checkpoints and uses these learning-dynamics signals to drive two innovative mechanisms, namely (i) human-like intra-stage review that divides each incremental stage into multiple sub-stages' training and concentrates on remembering the most-forgotten objects, and (ii) scene-aware cross-stage memory evolution that evolves a memory bank to transfer knowledge between two consecutive stages by jointly considering scene learnability and diversity. Extensive experiments across multiple long-incremental protocols on indoor benchmarks SUN RGB-D and ScanNetV2 show that LDMR substantially mitigates the model forgetting and outperforms all baselines by a clear margin. Code is available at https://github.com/qianpeisheng/LDMR.","authors":["Peisheng Qian","Jie Xu","Xulei Yang","Na Zhao"],"published":"2026-07-16T04:39:35Z","updated":"2026-07-16T04:39:35Z","abstract_url":"https://arxiv.org/abs/2607.14560v1","html_url":"https://arxiv.org/html/2607.14560v1","pdf_url":"https://arxiv.org/pdf/2607.14560v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14548v1","title":"HyMobileAgent: Data-Environment Co-Scaling for Efficient GUI Agents","abstract":"As large multimodal models move from understanding content to operating on digital environments, mobile GUI has emerged as a challenging and consequential testbed for digital embodied intelligence. Mobile agents operate under three coupled constraints: precise perception of complex interfaces, scalable acquisition of high-quality interaction data, and robust long-horizon decision making under compounding execution errors. This report presents HyMobileAgent, a mobile GUI agent built on Hy3.0-VL-A3B, a vision-native foundation model featuring native any-resolution input, an A3B-scale deployment budget, and a 32K context window to model extended interaction histories. Rather than relying solely on model scaling, we develop a joint data and environment centric scaling framework to address the key bottlenecks of mobile interaction. Our framework integrates a GUI perception flywheel combining mock-interface synthesis, rejection sampling, and icon-specific augmentation; a knowledge pipeline that transforms tutorial videos into structured interaction data; a million-scale action data pipeline deployed across more than 2000 sandbox and real-device instances with automated failure attribution; the PhoneWorld Mock App Factory, providing a resettable training environment with 34 mock applications and over 34000 tasks; and a structured Planning-and-Reflection mechanism with explicit dead-loop detection for reliable long-horizon execution. We also introduce a progressive training recipe consisting of mid-training, supervised fine-tuning, and reinforcement learning with task-specific reward designs.","authors":["Hy Vision Team","Huawen Shen","Zhengyang Tang","Shangpin Peng","Liang Wu","Anran Zhang","Weinong Wang","Yiduo Guo","Chenxin Li","Zhengyao Fang","Yang Ding","Junyi Li","Fei Tang","Zheng Ruan","Yi Zhang","Xingran Zhou","Dingchen Yang","Sunqi Fan","Zhiyi Wan","Han Hu","Xin Lai","Pengyuan Lyu","Chengquan Zhang"],"published":"2026-07-16T04:12:42Z","updated":"2026-07-16T04:12:42Z","abstract_url":"https://arxiv.org/abs/2607.14548v1","html_url":"https://arxiv.org/html/2607.14548v1","pdf_url":"https://arxiv.org/pdf/2607.14548v1.pdf","matched_keywords":["video","agent","instance","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14547v1","title":"AdaTurn: Budget-Aware Test-Time Scaling for Active Visual Perception Agents","abstract":"Active visual agents solve fine-grained image tasks by interleaving reasoning with image-grounding actions across multiple turns. However, deployment-time rollout budgets are rarely fixed: some requests permit long rollouts, while others require the agent to act under a tight turn limit. Existing methods train the policy as if the rollout budget were hidden, so when the available budget is smaller than the trajectory the agent prefers, the interaction is often truncated before any valid answer is produced; we term this failure \\emph{catastrophic truncation}. To overcome this challenge, we present AdaTurn, a budget-aware framework that conditions the agent on the allowed number of turns and explicitly trains the boundary behavior induced by the budget. Our key component, Forced-Answer DAPO (FA-DAPO), converts the over-budget event from a masked or penalized failure into a trainable final-decision step, teaching the model to synthesize partial evidence when further tool use is no longer possible. We further randomize rollout budgets during both training and inference and introduce a load-balanced scheduler that makes such operations practical. AdaTurn substantially improves low-budget accuracy, for example raising VisualProbe-Medium from 36.7% to 47.6% at four turns, while preserving strong scaling at larger budgets and transferring effectively to multiple backbones and general multimodal benchmarks.","authors":["Susan Liang","Chao Huang","Filippos Bellos","Jing Bi","Jason J Corso","Chenliang Xu"],"published":"2026-07-16T04:07:22Z","updated":"2026-07-16T04:07:22Z","abstract_url":"https://arxiv.org/abs/2607.14547v1","html_url":"https://arxiv.org/html/2607.14547v1","pdf_url":"https://arxiv.org/pdf/2607.14547v1.pdf","matched_keywords":["agent","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14544v1","title":"3D Geometric Tooth Alignment Planning via Deep Reinforcement Learning","abstract":"3D geometric tooth alignment planning, which determines sequential trajectories from initial malocclusion to the final target alignment, is a cornerstone of modern digital orthodontics. This paper presents a novel deep reinforcement learning (DRL) framework to automate the generation of these alignment paths. We formulate the planning process as a Markov Decision Process (MDP) to capture its sequential decision-making nature, focusing on optimizing geometric trajectories while integrating essential spatial constraints, such as inter-dental collision avoidance and path efficiency. The proposed method leverages the Deep Deterministic Policy Gradient (DDPG) algorithm, enhanced by three key innovations: (1) a Transformer-based agent to model complex spatial interactions between teeth and manage high-dimensional state-action spaces; (2) a dynamic masking scheme that restricts movement to a sparse subset of teeth per step, better reflecting the clinical logic of sequential alignment; and (3) a two-stage curriculum learning strategy that gradually increases task difficulty to ensure training stability and efficient path discovery. We evaluate our approach on a dataset of 10K expert-designed treatment plans based on clinical data. Experimental results demonstrate that our method outperforms existing baselines in terms of path safety and geometric efficiency, providing a robust and automated solution for 3D geometric orthodontic alignment planning.","authors":["Yong Li","Jianwen Lou","Jiayue Ma","Yao-Xiang Ding","Youyi Zheng","Haihua Zhu"],"published":"2026-07-16T04:00:05Z","updated":"2026-07-16T04:00:05Z","abstract_url":"https://arxiv.org/abs/2607.14544v1","html_url":"https://arxiv.org/html/2607.14544v1","pdf_url":"https://arxiv.org/pdf/2607.14544v1.pdf","matched_keywords":["3d","agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14521v1","title":"Uni-AdaVD: Universal Concept Erasure for Visual Generation via Orthogonal Value Decomposition","abstract":"Visual generative models inevitably absorb undesirable concepts from uncurated pretraining data, making concept erasure essential for safe deployment. Existing erasure methods, however, are often architecture-specific and struggle to remove target concepts while preserving non-target content and generative priors. We present Uni-AdaVD, a universal inference-time concept erasure framework for visual generation. Uni-AdaVD treats the value space of multimodal attention as a unified intervention space and introduces encoder-aware target representation construction to localize target semantics across heterogeneous text encoders. It further combines orthogonal value decomposition with an adaptive erasing shift to suppress target semantic directions without updating the original model weights. Extensive experiments on U-Net-, DiT-, and autoregressive image generators, as well as text-to-video models, demonstrate strong performance on single- and multi-concept erasure while preserving non-target priors. These results suggest that Uni-AdaVD provides an efficient and adaptable safety mechanism for modern visual generative models. Our code is available at https://github.com/QifanZhou/Uni-AdaVD.","authors":["Qifan Zhou","Yuan Wang","Yanbin Hao","Xiang Wang","Kuien Liu","Richang Hong","Meng Wang"],"published":"2026-07-16T03:16:51Z","updated":"2026-07-16T03:16:51Z","abstract_url":"https://arxiv.org/abs/2607.14521v1","html_url":"https://arxiv.org/html/2607.14521v1","pdf_url":"https://arxiv.org/pdf/2607.14521v1.pdf","matched_keywords":["video","representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14514v1","title":"VTM-Nav: Hierarchical Visual-Topological Memory for Cross-Episode Object-Goal Navigation","abstract":"Object-goal navigation requires an embodied agent to locate and reach an instance of a specified object category in an indoor environment. Recent training-free approaches leverage vision-language models (VLMs) for open-vocabulary semantic reasoning, but are typically evaluated under an episodic protocol that resets all scene-specific state after each episode. We introduce Cross-Episode Object-Goal Navigation, in which an agent repeatedly operates in the same scene, retains only self-acquired experience, and keeps its model parameters fixed. To support experience reuse, we present \\method, a training-free VLM navigation framework with a persistent hierarchical Visual-Topological Memory (VTM). The VTM organizes scene knowledge at room and object levels and retrieves relevant experience through coarse-to-fine matching, providing memory as soft guidance only when it agrees with current observations. A conservative execution guard further mitigates oscillations, blocked motions, and premature stopping. Under a controlled same-scene protocol, we evaluate \\method{} on three benchmarks, HM3D v0.1, HM3D v0.2, and MP3D, and compare it with a strengthened WMNav baseline augmented with cross-episode textual memory, while keeping the VLM backbone and action pipeline identical. \\method{} achieves the best performance across all three benchmarks, demonstrating the effectiveness and robustness of structured visual-topological experience reuse across datasets.","authors":["Xiaoran Xu","Yupeng Wu","Tianyu Xue","Yifan Xu","Xuanran Dong","Xiaoshan Yang","Changsheng Xu"],"published":"2026-07-16T03:11:37Z","updated":"2026-07-16T03:11:37Z","abstract_url":"https://arxiv.org/abs/2607.14514v1","html_url":"https://arxiv.org/html/2607.14514v1","pdf_url":"https://arxiv.org/pdf/2607.14514v1.pdf","matched_keywords":["3d","agent","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14513v1","title":"Compression of 3D Gaussian Splatting Data Using GPU-friendly Graphics Texture Coding","abstract":"Techniques for modeling 3D scenes from image collections, such as 3D Gaussian Splatting (3DGS), are capable of generating high-quality novel views by leveraging graphics primitives with view-dependent appearance. In 3DGS, spherical harmonic (SH) are employed to model view-dependent color, resulting in a large number of SH coefficients per primitive and large memory requirements. While compression approaches have been proposed to mitigate this problem, they do not exploit the capabilities of modern Graphics Processing Units (GPUs) for parallel decoding and rendering. In this paper, we propose a method for compressing SH color coefficients using texture compression schemes specifically designed for efficient parallel GPU decoding and supported by dedicated hardware acceleration. It is shown that those methods can compress color coefficients more effectively than 2D textures by exploiting the fact that primitives can be locally grouped and reordered according to color. Furthermore, we introduce a bit-rate control strategy that preserves random access, enabling large-scale parallelization without compromising rendering performance. Experimental results using BC1 and BC7 texture compression formats show that GPU-based decompression can be achieved with negligible or imperceptible degradation in the visual quality of rendered 3DGS scenes.","authors":["Amir Said","Randall Rauwendaal"],"published":"2026-07-16T03:10:27Z","updated":"2026-07-16T03:10:27Z","abstract_url":"https://arxiv.org/abs/2607.14513v1","html_url":"https://arxiv.org/html/2607.14513v1","pdf_url":"https://arxiv.org/pdf/2607.14513v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14509v1","title":"Multi-Scale ViT Inference with Habitat-Fit Priors and kNN Retrieval for Multi-Species Plant Identification","abstract":"This paper describes DS@GT ARC's third-place solution to the PlantCLEF 2026 challenge on multi-species plant identification in vegetation quadrat images, where systems must predict every species present in high-resolution (~3000 x 3000 pixel) plot photographs while training only on single-label images of individual plants. The pipeline is built around a fine-tuned DINOv2 ViT-L/14 classifier applied over a multi-scale tile decomposition of each quadrat, with per-tile predictions blended with a FAISS kNN retriever and post-processed by source-aware temporal fusion across repeated plot visits, a habitat-fit demotion that injects geographic and altitude priors from the training data, and a South-Western Europe geographic mask. Habitat-fit demotion and multi-scale aggregation are the largest individual contributors in the ablations. Two complementary training-centric directions, a cross-region transformer with noisy-student distillation on the LUCAS dataset and a label-as-query transformer decoder over synthetic CLS-domain pseudo-quadrats, yielded null results. An inference-time augmentation with instance-aware segmentation crops also did not improve performance. The selected submission reaches a private-leaderboard macro-F1 of 0.43902 (third place; public 0.51096); an unselected configuration of the same pipeline scored above 0.45 on the private set. Code: https://github.com/dsgt-arc/plantclef-2026.","authors":["Alper Erten","Murilo Gustineli","Adrian Cheung"],"published":"2026-07-16T02:47:38Z","updated":"2026-07-16T02:47:38Z","abstract_url":"https://arxiv.org/abs/2607.14509v1","html_url":"https://arxiv.org/html/2607.14509v1","pdf_url":"https://arxiv.org/pdf/2607.14509v1.pdf","matched_keywords":["retrieval","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14497v1","title":"Reinforcing Egocentric Spatial Perception in Multimodal Large Language Models via Ego Scene Augmentation","abstract":"Egocentric Visual Question Answering (VQA) has attracted widespread attention as an important task for enabling Multimodal Large Language Models (MLLMs) to interact with the real world. However, existing MLLMs struggle to perform effective spatial reasoning in complex egocentric scenes due to their limited spatial perception capabilities. To this end, we introduce Ego Scene Augmentation (ESA), an egocentric spatial perception framework, which actively enhances the spatial perception capabilities from the egocentric perspective, powered by the proposed Ego-element Graph. Our core insight is leveraging the Ego-element Graph as an intermediary representation to augment the egocentric spatial perception of MLLMs via visual foundational models. Specifically, we 1) construct the Ego-element Graph, which encapsulates and integrates egocentric spatial features enabled by visual foundational models; 2) enhance the spatial perception capabilities of MLLMs via the Ego-element Graph for ego-perspective scenes. Our proposed ESA framework presents significant performance improvement on the EgoTextVQA benchmark. We achieve an 8.14% gain on the indoor setting and an 8.72% gain on the outdoor setting. Furthermore, our ESA shows the most impressive performance improvement in the shopping subset of the indoor setting. The project code is publicly available.","authors":["Chi Kit Wong","Ye Pan","Yuanhuiyi Lyu","Xu Zheng","Zidong Cao","Lutao Jiang","Zixin Zhang","Huiyu Zhou","Xuming Hu"],"published":"2026-07-16T02:22:26Z","updated":"2026-07-16T02:22:26Z","abstract_url":"https://arxiv.org/abs/2607.14497v1","html_url":"https://arxiv.org/html/2607.14497v1","pdf_url":"https://arxiv.org/pdf/2607.14497v1.pdf","matched_keywords":["representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14481v1","title":"Immediate 3D Gaussian Splat Reconstruction of Unordered Input with Global Consistency","abstract":"3D Gaussian Splatting (3DGS) has become the method of choice for reconstructing and real-time rendering of captured scenes. To capture a scene with good visual quality, continuous image sequences are usually combined with out-of-order shots for better scene coverage. Structure from motion can reconstruct such captures, but only after they are all available and often with high computational cost. Incremental reconstruction methods -- often derived from SLAM solutions -- provide immediate feedback, but cannot handle the out-of-order capture we require. We provide the first immediate feedback solution for such radiance field capture that provides global consistency. We first introduce a method for fast matching in out-of-order sequences, by repurposing visual place recognition models and a covisibility graph, and provide an efficient way to find highly connected keyframes, improving quality even for ordered sequences. We show how these steps -- together with GPU optimization and careful Gaussian primitive placement -- provide fast local reconstruction, in our challenging radiance field reconstruction case. We then introduce a novel cluster-based method, again using the covisibility graph, to provide efficient loop closure that does not require sequential input. Finally, to handle large scenes in our context, we introduce a progressive hierarchy that allows our method to scale to large environments, without compromising efficiency. Our results show we provide immediate feedback 3DGS reconstruction with good visual quality in several datasets, with up to thousands of input images.","authors":["Andreas Meuleman","Linus Franke","Boris Zhestiankin","Camille Montemagni","George Drettakis"],"published":"2026-07-16T01:53:13Z","updated":"2026-07-16T01:53:13Z","abstract_url":"https://arxiv.org/abs/2607.14481v1","html_url":"https://arxiv.org/html/2607.14481v1","pdf_url":"https://arxiv.org/pdf/2607.14481v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14470v1","title":"G$^2$SR: Geometric Methods for Fast and Memory-Efficient Gaussian-based Surface Reconstruction","abstract":"Few-view surface reconstruction recovers the visible surfaces of a scene from a few posed RGB images, providing the 3D models that robots need to explore and interact online. On mobile platforms, the reconstruction must be fast and geometrically accurate while keeping a small memory footprint to ensure safe and efficient operation. 3D Gaussian Splatting (3DGS) offers a high-fidelity scene representation, but building it from a few views is ill-posed, as many distinct surfaces reproduce the same images, making traditional photometric methods prone to \"floater\" artifacts. End-to-end methods resolve the ambiguity by regressing splats with large, usually Transformer-based, networks that require heavy compute and memory while generalizing poorly to new scenes. We propose G2SR, which exploits a well-posed core of the task: given cross-view 2D splat correspondences, 3D splats follow analytically from multi-view geometry. G2SR employs a lightweight neural frontend to detect and track 2D Gaussian splats on the image plane and an analytic backend to triangulate each into a metric-scale 3D splat. On ScanNet, Replica, and DTU, G2SR matches or exceeds the geometric accuracy of state-of-the-art end-to-end methods while running at 69-89 reconstructions per second within 203 MB of GPU memory (5-107x less) for 2- and 3-view inputs at 384 x 512 resolution, offering a practical path to online Gaussian-based surface reconstruction.","authors":["Dasong Gao","Vivienne Sze","Sertac Karaman"],"published":"2026-07-16T01:33:37Z","updated":"2026-07-16T01:33:37Z","abstract_url":"https://arxiv.org/abs/2607.14470v1","html_url":"https://arxiv.org/html/2607.14470v1","pdf_url":"https://arxiv.org/pdf/2607.14470v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14463v1","title":"Depth-Dependent Hidden-State Collapse in Dynamical System Autoencoders for LiDAR Point-Cloud Classification","abstract":"We study Dynamical System Autoencoders (DSAE) for LiDAR point-cloud classification using spatial coordinates and Product Coefficient feature augmentations. The experiments compare separately trained DSAE architectures at encoder depths $K=1,\\ldots,5$ and evaluate the resulting hidden representations with Random Forest, kNN, and a majority-class Dummy baseline. The main finding is a hidden-state collapse at $K=5$. For both xyz and xyz plus Product Coefficient inputs, the hidden-state standard deviation falls to the order of $10^{-5}$, while all three classifiers attain the same macro F1 score of $0.224688$. We prove that between-class hidden scatter is bounded by total hidden scatter, which in turn is controlled by the reported hidden-state variance. Thus a nearly constant hidden representation cannot retain substantial class-separating structure. Product Coefficients neither improve pre-collapse macro F1 nor prevent the $K=5$ collapse in the present DSAE setting. These results identify large-depth representation collapse as a concrete failure mode for DSAE LiDAR classification.","authors":["Patricia Medina","Hy P. G. Lam"],"published":"2026-07-16T01:20:42Z","updated":"2026-07-16T01:20:42Z","abstract_url":"https://arxiv.org/abs/2607.14463v1","html_url":"https://arxiv.org/html/2607.14463v1","pdf_url":"https://arxiv.org/pdf/2607.14463v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14445v1","title":"Cotton-SF YOLO: Learning Structural and Frequency Cues for Early Cotton Square Detection in Complex Field Environments","abstract":"Cotton squares are important phenotypic indicators of the early reproductive growth of cotton, and automatic field detection of cotton squares provides an important basis for cotton growth monitoring and precision cultivation management. However, early cotton square detection in complex field environments remains insufficiently explored, as cotton squares are small, frequently occluded, easily blurred, subject to illumination variations, and exhibit low contrast against surrounding cotton leaves. To address these challenges, we propose a task-oriented framework based on YOLO26m, named Cotton-SF YOLO, for cotton square detection under natural field conditions. To improve the perception of small and irregular cotton square boundaries, we introduce Dynamic Snake Convolution into the detector, enabling adaptive extraction of deformable edge features. Furthermore, a frequency-domain feature modulation module is designed by incorporating spectral enhancement into the C2f structure, which recalibrate frequency-domain representations and strengthen discriminative edge and texture cues while reducing interference from complex cotton leaf backgrounds. Trained and evaluated on our newly constructed and annotated field dataset with manually annotated cotton squares, the proposed model achieves mAP$_{50}$, mAP$_{50:95}$, and recall values of 0.8196, 0.4942, and 0.7939, improving over the baseline YOLO26m by 1.25%, 3.45%, and 2.96%, respectively. Ablation experiments and visualization demonstrate that the best performance is achieved with the complementary effects of structural and frequency cues.","authors":["Chengjia Zhang","Yu Li","Feiri Ali","Yan Zhang","Xin Chen","Longke He","Daokun Ma","Liting Gao"],"published":"2026-07-16T00:40:59Z","updated":"2026-07-16T00:40:59Z","abstract_url":"https://arxiv.org/abs/2607.14445v1","html_url":"https://arxiv.org/html/2607.14445v1","pdf_url":"https://arxiv.org/pdf/2607.14445v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14423v1","title":"Emergent Region-Level Facial Correspondence in Frozen Vision Foundation Models","abstract":"Frozen self-supervised vision models can align parts of generic objects, but it remains unclear whether this correspondence extends to human faces, where global layout is shared while identity-specific appearance varies sharply. We test whether frozen DINOv3 features define a region-level facial coordinate system: a feature space in which eyes, brows, nose, mouth, skin, and hair remain distinguishable across people and across time without face-specific training. Using DINOv3 ViT-L/16 patch embeddings and FaRL only as a face-part labeling interface, we evaluate cross-identity nearest-neighbor matching and temporal label propagation on 200 CelebDF-v2 real videos. DINOv3 achieves 83.0% region-level semantic accuracy under unconstrained cross-identity matching, compared with a 23.0% area-weighted random baseline, and 95.5% temporal tracking accuracy without a learned temporal module. A no-FaRL control collapses to 0.9%, showing that FaRL supplies semantic initialization while DINOv3 supplies dense spatial correspondence. The strongest correspondence appears at an intermediate layer: block 18 gives a 4.93x same-region versus cross-region discrimination ratio, compared with 1.48x at the final block. Against CLIP ViT-L/14, DINOv3 shows only a small aggregate advantage but a +16.8 pp gain on anatomical regions, indicating that image-level contrastive supervision captures coarse facial layout but not fine-grained anatomical identity. These results establish frozen DINOv3 as a strong zero-shot representation for region-level facial correspondence and identify intermediate self-supervised features as the most useful layer for dense face analysis.","authors":["Izaldein Al-Zyoud","Abdulmotaleb El Saddik"],"published":"2026-07-15T23:23:28Z","updated":"2026-07-15T23:23:28Z","abstract_url":"https://arxiv.org/abs/2607.14423v1","html_url":"https://arxiv.org/html/2607.14423v1","pdf_url":"https://arxiv.org/pdf/2607.14423v1.pdf","matched_keywords":["video","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14415v1","title":"$K$-NeAS: Scalable Multi-Material CT Reconstruction Using Neural SDFs","abstract":"Computed Tomography (CT) carries significant ionizing radiation risks, driving the need for sparse-view reconstruction. Implicit scene representations (ISRs) address this by recovering continuous volumetric attenuation fields directly from sparse projections, and recent geometry-aware extensions jointly model surface geometry alongside attenuation to improve fidelity and enable clean tissue segmentation without manual thresholding. However, these methods remain limited by manually tuned attenuation bounds and rigid two-material constraints. This paper proposes $K$-NeAS, a unified and scalable architecture for automated, multi-material surface reconstruction. We replace independent material networks with a shared latent backbone and introduce a fully differentiable $K$-material sequential soft selector to model an arbitrary number of overlapping tissues. To eliminate manual tuning, we automate attenuation bounding using a Gaussian Mixture Model (GMM) and implement a scheduled auxiliary floater loss to mitigate geometric hallucinations common under extreme sparsity. Evaluated across four clinical Cone-Beam CT (CBCT) datasets, $K$-NeAS successfully scales to arbitrary material counts, achieving superior 3D volumetric fidelity at $K=3$ materials on complex multi-tissue regions such as the Abdomen ($33.28\\text{ dB}$ 3D PSNR vs. $31.40\\text{ dB}$ single-material NeAS baseline, a $+1.88\\text{ dB}$ improvement). Furthermore, our model exhibits enhanced robustness under sparse-sampling conditions, outperforming baseline 3D PSNR by up to $1.17\\text{ dB}$ under 5- and 10-view constraints.","authors":["Daksh K. Shah","Emmanouil Nikolakakis","Razvan V. Marinescu"],"published":"2026-07-15T23:08:45Z","updated":"2026-07-15T23:08:45Z","abstract_url":"https://arxiv.org/abs/2607.14415v1","html_url":"https://arxiv.org/html/2607.14415v1","pdf_url":"https://arxiv.org/pdf/2607.14415v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"}],"favorites":[],"latest":{"generated_at_utc":"2026-07-17T03:56:55+00:00","category":"cs.CV","keywords":["video","retrieval","3d","agent","representation","instance","multimodal","diffusion"],"fetch_window_hours":72,"daily_window_hours":30,"match_count":70,"new_or_recent_papers":[{"id":"2607.15278v1","title":"Hierarchical Denoising For Multi-Step Visual Reasoning","abstract":"Video models are evolving into vision foundation models, yet they still lack human-like multi-step reasoning. Streaming autoregressive diffusion models are efficient but limited in reasoning, while bidirectional diffusion enables global revision with high inference costs due to dense frame-level denoising. Both paradigms struggle to achieve logical consistency and low-latency streaming for complex reasoning tasks. We propose HDR (Hierarchical Denoising for Visual Reasoning), a unified framework that integrates hierarchical latents into causal video generation for multi-step reasoning. HDR organizes video latents into a tree-structured hierarchy, enabling coarse-to-fine reasoning before streaming output. Coarse denoising layers preserve uncertain hypotheses for global planning, while finer layers progressively refine them into concrete visual states. A sparse hierarchical attention pattern (SHAP) further reduces temporal attention costs. We introduce a level-stratified multi-step video reasoning benchmark with out-of-distribution cases, covering six tasks: maze navigation, Tower of Hanoi, one-line drawing, sliding puzzle, Sokoban, and water pouring. Compared with streaming autoregressive diffusion baselines, HDR improves success from 34.22 to 60.29 (76.2% relative gain) and increases average progress from 76.00 to 89.56, demonstrating more consistent reasoning trajectories. HDR maintains low-latency streaming at 0.70 seconds per latent, achieving 54.2 times faster inference than bidirectional diffusion. It also retains 82.9% of full-data performance with only 2% training data, compared with 52.0% for bidirectional diffusion. Real-world robot experiments further demonstrate HDR's potential for physical interaction and world modeling. Project demo: https://hierarchical-diffusion-reasoning.github.io/.","authors":["Zezhong Qian","Xiaowei Chi","Chak-Wing Mak","Tianze Zhou","Ruibin Yuan","Yuhan Rui","Hengzhe Sun","Zhuoqun Wu","Yuming Li","Siyuan Qian","Sirui Han","Shanghang Zhang"],"published":"2026-07-16T17:59:57Z","updated":"2026-07-16T17:59:57Z","abstract_url":"https://arxiv.org/abs/2607.15278v1","html_url":"https://arxiv.org/html/2607.15278v1","pdf_url":"https://arxiv.org/pdf/2607.15278v1.pdf","matched_keywords":["video","diffusion"],"source_used":"html","source_text_chars":100103,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, diffusion 相关；摘要显示其主要贡献为：Video models are evolving into vision foundation models, yet they still lack human-like multi-step reasoning. Streaming autoregressive diffusion models are efficient but limited in reasoning, while bidirectional diffusion enables global revision with high inf...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:56:59+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15273v1","title":"MeanFlowNFT: Bringing Forward-Process RL to Average-Velocity Generators","abstract":"MeanFlow generators achieve fast few-step sampling by predicting average velocities over time intervals, making them attractive for efficient generation. Reinforcement learning (RL) has become a powerful way to align diffusion and flow models with human preferences and task-specific objectives. In particular, DiffusionNFT offers an efficient forward-process RL framework that does not require reverse-process trajectories or likelihood estimation. However, applying such RL methods to MeanFlow remains underexplored. DiffusionNFT optimizes instantaneous velocities, whereas MeanFlow samples with average velocities. To bridge this gap, we introduce MeanFlowNFT. Inspired by the MeanFlow identity, which bridges average and instantaneous velocities, we construct an induced instantaneous-velocity predictor. We apply the DiffusionNFT objective to this predictor, making reward optimization well-defined for MeanFlow. Sampling remains based on the average velocity, preserving MeanFlow's fast few-step generation. We further prove that MeanFlowNFT inherits DiffusionNFT's strict policy-improvement guarantee. Experiments on image and video generation show that MeanFlowNFT consistently improves baselines. Moreover, it outperforms prior state-of-the-art RL-tuned few-step generators on most metrics ($6$ of $8$ on SD3.5-M), and can even surpass multi-step RL-tuned diffusion while using only a few sampling steps. For instance, on Wan 2.1, $4$-step MeanFlowNFT reaches a VBench score of $84.33$, surpassing $50$-step LongCat-Video RL ($82.57$).","authors":["Yushi Huang","Xiangxin Zhou","Jun Zhang","Liefeng Bo","Tianyu Pang"],"published":"2026-07-16T17:59:02Z","updated":"2026-07-16T17:59:02Z","abstract_url":"https://arxiv.org/abs/2607.15273v1","html_url":"https://arxiv.org/html/2607.15273v1","pdf_url":"https://arxiv.org/pdf/2607.15273v1.pdf","matched_keywords":["video","instance","diffusion"],"source_used":"html","source_text_chars":101845,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, instance, diffusion 相关；摘要显示其主要贡献为：MeanFlow generators achieve fast few-step sampling by predicting average velocities over time intervals, making them attractive for efficient generation. Reinforcement learning (RL) has become a powerful way to align diffusion and flow models with human prefe...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:56:59+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15271v1","title":"Online Neural Space Time Memory for Dynamic Novel View Synthesis","abstract":"Online novel view synthesis from multi-view streaming videos faces a fundamental trade-off: maintaining a persistent, long-horizon memory to reconstruct temporarily occluded regions while operating under strict real-time constraints. While Test-Time Training (TTT) offers a powerful memory mechanism, standard models mandate gradient-based memory updates at every frame to adapt to the changing motion in dynamic scenes. The computational cost of heavy memory updates precludes real-time application and can lead to instability over long contexts. Given that memory updates are more demanding than memory application and video content is largely redundant, we propose to decouple the frequencies of these two processes. Our approach performs periodic memory updates while applying the memory on a per-frame basis, using cross-view attention to manage deformations between the prior memory state and the current frame. To lock in the historical context, we introduce two critical mechanisms: an auxiliary Memory Loss that forces persistent internalization of the scene, and a Memory Caching strategy that regularizes active weights against catastrophic drift. Our method demonstrates real-time, state-of-the-art performance on scenes with dynamic human motion as well as minute-scale online memorization.","authors":["Baback Elmieh","Lynn Tsai","Zeman Li","Srinivas Kaza","Tiancheng Sun","Gabor Csapo","Ali Behrouz","Yuan Deng","Stephen Lombardi","Steven M. Seitz","Xuan Luo"],"published":"2026-07-16T17:58:18Z","updated":"2026-07-16T17:58:18Z","abstract_url":"https://arxiv.org/abs/2607.15271v1","html_url":"https://arxiv.org/html/2607.15271v1","pdf_url":"https://arxiv.org/pdf/2607.15271v1.pdf","matched_keywords":["video"],"source_used":"html","source_text_chars":73968,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video 相关；摘要显示其主要贡献为：Online novel view synthesis from multi-view streaming videos faces a fundamental trade-off: maintaining a persistent, long-horizon memory to reconstruct temporarily occluded regions while operating under strict real-time constraints. While Test-Time Training...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:00+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15268v1","title":"Motion-Conditioned Multi-View Fusion for Myocardial Infarction Localization from Echocardiography","abstract":"Myocardial infarction (MI) remains a leading cause of mortality worldwide. Echocardiography (Echo) is a widely available modality for MI assessment, where regional wall motion abnormality is a key indicator. Prior learning based methods for myocardial motion analysis often use handcrafted descriptors or densely supervised estimation, but the need for extensive annotation limits applicability. Foundation models have recently improved vision-based Echo analysis; however, most methods operate on single views and segment-level localization remains unreliable under view-dependent ambiguity, especially in apical views. To address this, we propose MCF-Net, a novel motion-guided multi-view fusion framework that fuses myocardial motion cues with foundation model representations to localize infarction. Visual features are extracted using EchoPrime, a pretrained Echo foundation model shared across dual views. Cardiac motion is modeled with extremely sparse supervision: a single annotated template frame is transferred across videos to initialize point tracking, avoiding dense labels. Motion-derived segment-aware soft masks provide coarse spatial priors that selectively enhance features for challenging myocardial segments. A motion-conditioned fusion mechanism then integrates motion and vision across views, refining predictions without overriding strong appearance cues. On segment-level MI localization, MCF-Net achieves 72.4\\% F1 and 84.9\\% accuracy, outperforming state-of-the-art motion-only, vision-only, and fusion baselines.","authors":["Guang Yang","Wentian Xu","Siyu Wang","Betty Raman","Lei Li","Vicente Grau"],"published":"2026-07-16T17:56:56Z","updated":"2026-07-16T17:56:56Z","abstract_url":"https://arxiv.org/abs/2607.15268v1","html_url":"https://arxiv.org/html/2607.15268v1","pdf_url":"https://arxiv.org/pdf/2607.15268v1.pdf","matched_keywords":["video","representation"],"source_used":"html","source_text_chars":32830,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, representation 相关；摘要显示其主要贡献为：Myocardial infarction (MI) remains a leading cause of mortality worldwide. Echocardiography (Echo) is a widely available modality for MI assessment, where regional wall motion abnormality is a key indicator. Prior learning based methods for myocardial motion...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:00+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15265v1","title":"SceneBind: Binding What and Where Across Vision, Audio and Language","abstract":"We present SceneBind, an omni-modal representation of realistic scenes with joint semantic and 3D spatial understanding across vision, audio and language. Existing omni-modal encoders excel at instance-level semantics (i.e., what is present), but often lack explicit spatial structure (i.e., where it is). SceneBind addresses this gap by representing each scene as a semantic-spatial entity, combining a global semantic embedding with object-centric semantic-spatial slots. This representation explicitly captures object-level semantics, spatial attributes, and uncertainty. We further propose SceneBind Matching, a semantic-spatial matching scheme that integrates global scene similarity with object alignment, supporting cross-modal scene retrieval and object grounding. To train and evaluate SceneBind, we curate a novel real-world binaural audio-visual dataset with structured semantic and spatial annotations, and propose a training protocol for aligning semantic and spatial signals across modalities. SceneBind is compatible with large-scale pretrained semantic encoders, adds lightweight spatial modeling with only a few additional tokens. It achieves state-of-the-art scene and spatial retrieval while enabling strong zero-shot transfer to downstream tasks such as audio-visual localization.","authors":["Mingfei Chen","Zijun Cui","Ruoke Zhang","Hyeonggon Ryu","Eli Shlizerman"],"published":"2026-07-16T17:55:15Z","updated":"2026-07-16T17:55:15Z","abstract_url":"https://arxiv.org/abs/2607.15265v1","html_url":"https://arxiv.org/html/2607.15265v1","pdf_url":"https://arxiv.org/pdf/2607.15265v1.pdf","matched_keywords":["retrieval","3d","representation","instance"],"source_used":"html","source_text_chars":120625,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 retrieval, 3d, representation, instance 相关；摘要显示其主要贡献为：We present SceneBind, an omni-modal representation of realistic scenes with joint semantic and 3D spatial understanding across vision, audio and language. Existing omni-modal encoders excel at instance-level semantics (i.e., what is present), but often lack e...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:00+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15246v1","title":"ARMOR++: Agentic Orchestration of a Multi-Domain Primitive Set for Transferable Attacks on Deepfake Detectors","abstract":"The reliability of deepfake detectors frequently degrades under black-box adversarial transfer, as these models often rely on fragile, architecture-dependent forensic cues. Existing transfer attacks often lack semantic awareness and struggle to maintain effectiveness under strict no-query constraints, particularly when perturbations are transferred from convolutional surrogates to transformer-based targets. To address these limitations, this paper introduces ARMOR++, a robust multi-agent framework designed for high-transferability deepfake evasion. The framework leverages the Qwen2.5-VL Vision-Language Model (VLM) to supply spatial semantic priors, while the Qwen3 Large Language Model (LLM) orchestrates primitive selection, adaptive hyperparameter reparameterization, and entropy-regularized perturbation mixing. By integrating five complementary primitives, spanning dense optimization, saliency-based methods, spatial transformations, frequency-domain perturbations, and block-structured modifications, ARMOR++ effectively targets heterogeneous inductive biases. Rigorous evaluation on the AADD-2025 benchmark demonstrates that ARMOR++ significantly outperforms existing agentic and non-agentic baselines across both low- and high-quality image regimes. Statistical analysis confirms a substantial gain in blind-target Attack Success Rate (ASR) over the state-of-the-art agentic baseline, with further performance advantages evidenced against non-agentic benchmarks and under robust defensive configurations. These findings highlight a significant residual reliability gap in current deepfake detector deployments and demonstrate the efficacy of agentic orchestration in identifying latent vulnerabilities.","authors":["Christos Korgialas","Gabriel Lee Jun Rong","Dion Jia Xu Ho","Pai Chet Ng","Xiaoxiao Miao","Konstantinos N. Plataniotis"],"published":"2026-07-16T17:45:13Z","updated":"2026-07-16T17:45:13Z","abstract_url":"https://arxiv.org/abs/2607.15246v1","html_url":"https://arxiv.org/html/2607.15246v1","pdf_url":"https://arxiv.org/pdf/2607.15246v1.pdf","matched_keywords":["agent"],"source_used":"html","source_text_chars":110140,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 agent 相关；摘要显示其主要贡献为：The reliability of deepfake detectors frequently degrades under black-box adversarial transfer, as these models often rely on fragile, architecture-dependent forensic cues. Existing transfer attacks often lack semantic awareness and struggle to maintain effec...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:00+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15241v1","title":"Beyond the Leaderboard: Design Lessons for Trustworthy Multimodal VQA","abstract":"Healthcare multimodal AI must combine visual and textual evidence while remaining reliable and interpretable. Using MediaEval Medico 2025 as a retrospective GI endoscopy case study, we analyze design choices across nine documented systems for question answering and explanation quality. Parameter-efficient adaptation of pretrained backbones provides strong challenge performance, but answer-level gains do not consistently translate into faithful and complete clinical reasoning. Methods enforcing structured reasoning and explicit grounding show more reliable behavior across heterogeneous question types, although the evidence is correlational rather than ablation-based. These results motivate evaluation beyond lexical overlap, standardized evidence-linked explanations, leakage-aware data governance, and lightweight robustness and calibration checks. The findings support trustworthy multimodal healthcare AI based on data fusion, explainability, and resilient evaluation.","authors":["Sushant Gautam","Vajira Thambawita","Michael A. Riegler","Pål Halvorsen","Steven A. Hicks"],"published":"2026-07-16T17:38:19Z","updated":"2026-07-16T17:38:19Z","abstract_url":"https://arxiv.org/abs/2607.15241v1","html_url":"https://arxiv.org/html/2607.15241v1","pdf_url":"https://arxiv.org/pdf/2607.15241v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":45166,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：Healthcare multimodal AI must combine visual and textual evidence while remaining reliable and interpretable. Using MediaEval Medico 2025 as a retrospective GI endoscopy case study, we analyze design choices across nine documented systems for question answeri...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:00+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15220v1","title":"Structural-Semantic Reciprocal Learning for Unsupervised Visible-Infrared Person Re-Identification","abstract":"Unsupervised visible-infrared person re-identification (USVI-ReID) is challenging due to the large modality gap and the lack of cross-modal identity annotations. Progressive association paradigms have been proposed to gradually bridge the gap, but they suffer from two critical bottlenecks: reliance on ambiguous global representations and unchecked propagation of pseudo-label noise in an open-loop manner. To address these issues, we propose Structural-Semantic Reciprocal Learning (SSRL), a framework that transforms open-loop association into a self-correcting closed-loop system. Structurally, we introduce Fine-grained Structural Decoupling (FSD) to extract discriminative body-part primitives as reliable spatial anchors, complementing ambiguous holistic silhouettes with spatially consistent structural details. Semantically, we design a Closed-loop Semantic Calibration (CSC) mechanism that reconstructs shared semantic prototypes at each epoch and feeds them back into the training loop, effectively filtering pseudo-label noise before the next clustering cycle. Through the reciprocal interaction between structural and semantic learning, SSRL achieves robust cross-modal representation. Extensive experiments demonstrate the competitive performance of SSRL against state-of-the-art USVI-ReID methods on both SYSU-MM01 and RegDB, notably surpassing several supervised counterparts on RegDB.","authors":["Moyao Tian","Shijia Liu","Yan Yang","Xin Yuan","Minshi Chen","Wei Wang","Xiao Wang"],"published":"2026-07-16T17:22:51Z","updated":"2026-07-16T17:22:51Z","abstract_url":"https://arxiv.org/abs/2607.15220v1","html_url":"https://arxiv.org/html/2607.15220v1","pdf_url":"https://arxiv.org/pdf/2607.15220v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":64232,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：Unsupervised visible-infrared person re-identification (USVI-ReID) is challenging due to the large modality gap and the lack of cross-modal identity annotations. Progressive association paradigms have been proposed to gradually bridge the gap, but they suffer...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:00+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15216v1","title":"Symbal: Detecting Systematic Misalignments in Model-Generated Captions","abstract":"Multimodal large language models (MLLMs) often introduce errors when generating image captions, resulting in misaligned image-text pairs. Our work focuses on a class of captioning errors that we refer to as systematic misalignments, where a recurring error in MLLM-generated captions is closely associated with the presence of a specific visual feature in the paired image. Given a vision-language dataset with MLLM-generated captions, our aim in this work is to detect such errors, a task we refer to as systematic misalignment detection. As our first key contribution, we present Symbal, which utilizes a structured, dual-stage setup with off-the-shelf foundation models to identify systematic misalignments and summarize results in natural language. As our second key contribution, we introduce SymbalBench, a benchmark designed to evaluate automated methods on our proposed task. SymbalBench consists of 1.7 million image-text pairs from two domains (natural and medical images), organized into 420 vision-language datasets with annotated systematic misalignments. Symbal exhibits strong performance on this benchmark, correctly identifying systematic misalignments in 63.8% of datasets, a nearly 4x improvement over the closest baseline. We supplement our evaluations on SymbalBench with real-world evaluations, showing that (1) Symbal can accurately surface systematic misalignments in captions generated by four MLLMs and (2) Symbal is a powerful tool for auditing off-the-shelf image-caption datasets. Ultimately, our novel task, method, and benchmark can aid users with auditing MLLM-generated captions and identifying critical errors, without requiring access to the underlying MLLM. Code is available at https://github.com/Stanford-AIMI/Symbal.","authors":["Maya Varma","Jean-Benoit Delbrouck","Sophie Ostmeier","Akshay Chaudhari","Curtis Langlotz"],"published":"2026-07-16T17:18:37Z","updated":"2026-07-16T17:18:37Z","abstract_url":"https://arxiv.org/abs/2607.15216v1","html_url":"https://arxiv.org/html/2607.15216v1","pdf_url":"https://arxiv.org/pdf/2607.15216v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":108408,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：Multimodal large language models (MLLMs) often introduce errors when generating image captions, resulting in misaligned image-text pairs. Our work focuses on a class of captioning errors that we refer to as systematic misalignments, where a recurring error in...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:00+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15211v1","title":"MAGiSt3R: Multi-Agent Feed-forward 3D Reconstruction from Monocular RGB Videos","abstract":"This paper presents MAGiSt3R, a multi-agent 3D reconstruction framework performing reconstruction and camera tracking for monocular RGB videos at almost 10 FPS. MAGiSt3R relies on a feed-forward model from the 3R family to process RGB videos and regress local point maps, and on a merging model, MAGMA, that combines local maps at both intra-agent and inter-agent levels to obtain the final global point map. Furthermore, MAGiSt3R performs pose graph optimization to mitigate cumulative camera drift occurring along the feed-forward pipeline. We evaluate MAGiSt3R on both synthetic and real-world datasets, demonstrating its superior reconstruction and camera tracking accuracy compared to state-of-the-art approaches.","authors":["Ziren Gong","Xiaohan Li","Fabio Tosi","Ninghui Xu","Stefano Mattoccia","Jianfei Cai","Matteo Poggi"],"published":"2026-07-16T17:12:58Z","updated":"2026-07-16T17:12:58Z","abstract_url":"https://arxiv.org/abs/2607.15211v1","html_url":"https://arxiv.org/html/2607.15211v1","pdf_url":"https://arxiv.org/pdf/2607.15211v1.pdf","matched_keywords":["video","3d","agent"],"source_used":"html","source_text_chars":50528,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, 3d, agent 相关；摘要显示其主要贡献为：This paper presents MAGiSt3R, a multi-agent 3D reconstruction framework performing reconstruction and camera tracking for monocular RGB videos at almost 10 FPS. MAGiSt3R relies on a feed-forward model from the 3R family to process RGB videos and regress local...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:00+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15128v1","title":"DAPGNet: Dynamic Adaptive Physics-Guided Graph Diffusion Network for Hyperspectral Image Classification","abstract":"Hyperspectral image (HSI) classification requires reliable pixel-relation modeling under spectral variability, mixed pixels, and heterogeneous boundaries. Existing graph-based HSI classifiers usually construct graph topology from spatial proximity, superpixel connectivity, or learned feature affinity. However, the spectral physical prior carried by contiguous bands has limited influence on topology estimation and message propagation. This paper presents DAPGNet, a dynamic adaptive physics-guided graph diffusion network that injects a structure-constrained physical prior into relation-level graph learning. DAPGNet first encodes contiguous spectral responses into node-wise multiscale physical-prior representations. A two-stage graph constructor then combines spectral-spatial affinity, physical-prior consistency, and spatial distance to form a physical-prior-aware sparse topology. During graph diffusion, learned edge weights are transformed into additive attention biases, while a physical gate performs node-wise and feature-wise interpolation between graph-aggregated features and projected physical-prior features. Cross-scale fusion integrates node states from different diffusion depths, and the network is optimized with main classification, auxiliary supervision, and second-order spectral smoothness regularization. Experiments on Indian Pines, WHU-Hi-LongKou, Houston2013, and Houston2018 show that DAPGNet achieves the best OA, AA, and Kappa among representative CNN-, Transformer-, Mamba-, and graph-based baselines. It improves AA over the strongest competing method by 3.64 to 7.31 percentage points across the four datasets. Ablation and sensitivity analyses further support the complementary effects of physical-prior extraction, prior-aware topology construction, physics-gated propagation, and spectral smoothness regularization.","authors":["Pengkun Wang","Weijia Cao","Ning Wang","Xiaofei Yang"],"published":"2026-07-16T15:37:32Z","updated":"2026-07-16T15:37:32Z","abstract_url":"https://arxiv.org/abs/2607.15128v1","html_url":"https://arxiv.org/html/2607.15128v1","pdf_url":"https://arxiv.org/pdf/2607.15128v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"html","source_text_chars":101087,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation, diffusion 相关；摘要显示其主要贡献为：Hyperspectral image (HSI) classification requires reliable pixel-relation modeling under spectral variability, mixed pixels, and heterogeneous boundaries. Existing graph-based HSI classifiers usually construct graph topology from spatial proximity, superpixel...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:00+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15097v1","title":"QuReC: All-in-One Image Restoration with Query-Specific Guidance and Local-Global Response Calibration","abstract":"All-in-one image restoration aims to recover clean images degraded by multiple corruption types using a single unified model. Existing methods typically rely on image-level prompts or shared guidance to handle diverse degradations. However, such a paradigm becomes inadequate when degradations are spatially heterogeneous or even coexist in mixed forms within a single image. Yet spatially adaptive guidance alone is not sufficient, since accurate restoration also requires each spatial query to reliably aggregate complementary information from local neighborhoods and global contexts. To this end, we propose QuReC, a unified framework for all-in-one image restoration. QuReC consists of a Degradation-Guided Query Reconstruction Module (DQRM) and a Local-Global Response Calibration Module (LGRCM). Specifically, DQRM matches each spatial query against a degradation prototype space to reconstruct a query-specific degradation-aware representation, thereby providing fine-grained spatially adaptive restoration guidance. To further stabilize this query-wise matching process, we introduce a weakly supervised prototype matching learning strategy to improve optimization stability and degradation semantic consistency. Meanwhile, LGRCM performs local-global dual-branch aggregation and calibrates the aggregated responses with learnable priors, improving the reliability of feature aggregation and the coordination between local detail modeling and global context modeling. Extensive experiments demonstrate that QuReC achieves superior performance on multiple all-in-one image restoration benchmarks. The code is released at https://github.com/zhoushen1/QuReC.","authors":["Shen Zhou","Jinghui Zhang","Wenbo Huang","Xuwei Qian","Zhen Wu","Guangwen Peng","Zhiyuan Li","Ding Ding","Dian Shen","Fang Dong"],"published":"2026-07-16T15:10:00Z","updated":"2026-07-16T15:10:00Z","abstract_url":"https://arxiv.org/abs/2607.15097v1","html_url":"https://arxiv.org/html/2607.15097v1","pdf_url":"https://arxiv.org/pdf/2607.15097v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":101576,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：All-in-one image restoration aims to recover clean images degraded by multiple corruption types using a single unified model. Existing methods typically rely on image-level prompts or shared guidance to handle diverse degradations. However, such a paradigm be...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:01+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15094v1","title":"AlphaWiSE: Adaptive Weight Interpolation for Continual Multimodal Representation Learning","abstract":"Multimodal models such as CLIP learn a shared embedding space for cross-modal retrieval, but continual adaptation to sequentially arriving data can disrupt the cross-modal alignment acquired from earlier phases. Conventional continual-learning methods return a single checkpoint, which commits every retrieval direction to the same stability-plasticity trade-off. We propose AlphaWiSE, a post-hoc weight-space interpolation method that composes two frozen source checkpoints. For each aligned parameter tensor identified by its checkpoint key, AlphaWiSE fits one scalar interpolation coefficient shared by all tensor entries. The coefficients are fitted on a smaller exemplar memory and used to materialize one interpolated checkpoint. The deployed model has the same architecture and parameter count as either source checkpoint, which does not require additional inference time. Extensive experiments on audio-image-text retrieval show consistent improvements over strong continual-learning baselines across multiple retrieval directions and evaluation metrics.","authors":["Sarthak Jain","Qiran Hu","Zhen Zhu","Yaoyao Liu"],"published":"2026-07-16T15:07:23Z","updated":"2026-07-16T15:07:23Z","abstract_url":"https://arxiv.org/abs/2607.15094v1","html_url":"https://arxiv.org/html/2607.15094v1","pdf_url":"https://arxiv.org/pdf/2607.15094v1.pdf","matched_keywords":["retrieval","representation","multimodal"],"source_used":"html","source_text_chars":62534,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 retrieval, representation, multimodal 相关；摘要显示其主要贡献为：Multimodal models such as CLIP learn a shared embedding space for cross-modal retrieval, but continual adaptation to sequentially arriving data can disrupt the cross-modal alignment acquired from earlier phases. Conventional continual-learning methods return...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:01+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15082v1","title":"Towards Hierarchical Structure Understanding of Newspaper Images","abstract":"Understanding newspaper images remains a challenging task due to their complex, nested hierarchical structures and dense, heterogeneous layouts. In this paper, we explore two complementary approaches for newspaper structure understanding. First, we present a modular bottom-up pipeline that combines state-of-the-art open-source models: YOLO for layout detection, LayoutReader for reading order prediction, and a custom algorithm for article segmentation. This approach leverages existing robust components while maintaining flexibility and interpretability. Second, we introduce Tiramisu (Tiered Transformers for Hierarchical Structure Understanding), a novel end-to-end transformer-based architecture that explicitly models document hierarchy through an iterative tiered process. Tiramisu performs section and article separation, block localization, semantic categorization, and reading order prediction using highly parallelized attention mechanisms. Finally, we release Finlam La Liberté, a new dataset designed specifically for evaluating hierarchical information retrieval in historical newspapers. Experimental results demonstrate the effectiveness of both approaches in reconstructing complex newspaper hierarchies, with comparative analysis highlighting their respective strengths for scalable document digitization. The Tiramisu training code, including the synthetic newspaper generator, is available at https://git.litislab.fr/tiramisu/tiramisu-newspaper-articles-extractor.","authors":["William Mocaër","Solène Tarride","Thomas Constum","Merveilles Agbeti-Messan","Tom Simon","Clément Chatelain","Stéphane Nicolas","Pierrick Tranouez","Sébastien Cretin","Thierry Paquet"],"published":"2026-07-16T14:52:08Z","updated":"2026-07-16T14:52:08Z","abstract_url":"https://arxiv.org/abs/2607.15082v1","html_url":"https://arxiv.org/html/2607.15082v1","pdf_url":"https://arxiv.org/pdf/2607.15082v1.pdf","matched_keywords":["retrieval"],"source_used":"html","source_text_chars":47630,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 retrieval 相关；摘要显示其主要贡献为：Understanding newspaper images remains a challenging task due to their complex, nested hierarchical structures and dense, heterogeneous layouts. In this paper, we explore two complementary approaches for newspaper structure understanding. First, we present a...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:01+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15065v1","title":"DriftWorld: Fast World Modeling through Drifting","abstract":"Predictive world models enable robots to plan by imagining the outcomes of their actions, but their value for control hinges on generating many rollouts quickly. This creates a bottleneck for diffusion-based world models: multistep sampling makes each rollout expensive, limiting large-scale action search at inference time. We introduce DriftWorld, an action-conditioned world model based on drifting generative models. Rather than denoising iteratively at inference, DriftWorld learns an action-conditioned drift during training, allowing it to generate future frames from the current observation and a candidate action sequence in a single forward pass at 30+ fps, which is 17x faster on average than diffusion based baselines. We evaluate DriftWorld on standard vision-based robotic manipulation benchmarks, including Bridge-V2, RT-1, Language Table, Push-T, and Robomimic. By producing rollouts that are both accurate and fast, DriftWorld achieves state-of-the-art decision-making performance with far less inference time than diffusion-based world model baselines. Beyond online control, DriftWorld can also serve as an offline simulator for ranking real-world robot policies, with rollout-based scores correlating with ground truth at up to 0.99. These results show that drifting models are a strong fit for robot world modeling, where fast, high-quality imagination directly supports planning and policy evaluation.","authors":["Susie Lu","Haonan Chen","Weirui Ye","Yilun Du"],"published":"2026-07-16T14:37:43Z","updated":"2026-07-16T14:37:43Z","abstract_url":"https://arxiv.org/abs/2607.15065v1","html_url":"https://arxiv.org/html/2607.15065v1","pdf_url":"https://arxiv.org/pdf/2607.15065v1.pdf","matched_keywords":["diffusion"],"source_used":"html","source_text_chars":65469,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 diffusion 相关；摘要显示其主要贡献为：Predictive world models enable robots to plan by imagining the outcomes of their actions, but their value for control hinges on generating many rollouts quickly. This creates a bottleneck for diffusion-based world models: multistep sampling makes each rollout...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:01+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15058v1","title":"SUFLECA: Scaling Up Feature Learning for CAD-to-image Alignment","abstract":"CAD-to-image alignment aims to estimate an object's 9D pose (rotation, translation, and anisotropic scale) from a single RGB image, enabling applications in robotics and augmented reality. Recent zero-shot methods use visual foundation models to match image regions to CAD models, yet typically their correspondences are appearance-driven and degrade under occlusion or sim-to-real domain shift. To address these limitations, we introduce SUFLECA (Scaling Up Feature LEarning for CAD Alignment), a weakly-supervised framework for zero-shot CAD alignment with two key contributions. First, SUFLECA scales up geometry-grounded feature learning from pretrained visual representations through Normalized Object Coordinates (NOCs) supervision on 674K images spanning 12 real and synthetic datasets, learning compact geometry-aware features that generalize across domains. Second, we propose a geometrically consistent matching algorithm that establishes reliable one-to-one CAD-to-image correspondences. Together, these contributions enable accurate, sub-second alignment per object instance without iterative pose refinement. On ScanNet25k, SUFLECA achieves 33.4%/42.3% category/instance accuracy, outperforming, with a smaller computational footprint, the strongest zero-shot baseline by 10.3/12.2 percentage points and, for the first time on this benchmark, even surpassing fully supervised methods. Code is available at: https://github.com/snt-arg/SUFLECA","authors":["Saad Ejaz","Miguel Fernandez-Cortizas","Javier Civera","Holger Voos","Jose Luis Sanchez-Lopez"],"published":"2026-07-16T14:32:34Z","updated":"2026-07-16T14:32:34Z","abstract_url":"https://arxiv.org/abs/2607.15058v1","html_url":"https://arxiv.org/html/2607.15058v1","pdf_url":"https://arxiv.org/pdf/2607.15058v1.pdf","matched_keywords":["representation","instance"],"source_used":"html","source_text_chars":52909,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation, instance 相关；摘要显示其主要贡献为：CAD-to-image alignment aims to estimate an object's 9D pose (rotation, translation, and anisotropic scale) from a single RGB image, enabling applications in robotics and augmented reality. Recent zero-shot methods use visual foundation models to match image r...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:01+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15054v1","title":"Beyond Single Expert: Harmonizing Diverse Visual Priors in MLLMs for Spatial Understanding","abstract":"Multimodal Large Language Models (MLLMs) have demonstrated substantial promise in spatial understanding. Existing works typically incorporate prior knowledge extracted from a pre-trained foundation model to further enhance the spatial awareness of MLLMs. In this paper, we first reveal that when integrating diverse foundation models into MLLMs, different models provide complementary spatial priors that benefit different tasks. Motivated by this, we propose $\\textbf{ViPS}$, a novel multi-model prior framework designed to fully unleash the potential of incorporating multiple $\\textbf{Vi}$sual $\\textbf{P}$riors from diverse models into MLLMs for $\\textbf{S}$patial understanding. Specifically, ViPS introduces an Efficient Prior Proxy to generate multiple foundational priors with minimal inference overhead, and a Dynamic Prior Fusion mechanism to achieve harmonious and context-aware prior fusion and injection from the prior proxies. Extensive experiments demonstrate that ViPS successfully harmonizes diverse visual priors, establishing new state-of-the-art performance across multiple complex spatial reasoning and 3D spatial understanding benchmarks. Project page: https://visual-ai.github.io/vips","authors":["Xiao Lin","Xiaohu Huang","Kai Han"],"published":"2026-07-16T14:31:16Z","updated":"2026-07-16T14:31:16Z","abstract_url":"https://arxiv.org/abs/2607.15054v1","html_url":"https://arxiv.org/html/2607.15054v1","pdf_url":"https://arxiv.org/pdf/2607.15054v1.pdf","matched_keywords":["3d","multimodal"],"source_used":"html","source_text_chars":61994,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, multimodal 相关；摘要显示其主要贡献为：Multimodal Large Language Models (MLLMs) have demonstrated substantial promise in spatial understanding. Existing works typically incorporate prior knowledge extracted from a pre-trained foundation model to further enhance the spatial awareness of MLLMs. In t...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:01+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15048v1","title":"RoGS: Adaptive Meshgrid Gaussian for Large-Scale Road Surface Mapping","abstract":"Road surface mapping plays a crucial role in autonomous driving, supporting high-definition map generation, lane-level perception, and automatic road annotation. Recent mesh-based road surface reconstruction methods have shown promising results, but they still suffer from limited reconstruction quality and high optimization cost, especially in large-scale driving scenarios. To address these limitations, we propose ROADGS-T, a robust and efficient large-scale road surface mapping framework based on adaptive meshgrid Gaussian representation. Specifically, we model the road surface by placing 2D Gaussian surfels on a meshgrid, where each surfel explicitly stores color, semantic, and geometric information. Compared with conventional mesh-based representations and 3D Gaussian primitives, the proposed meshgrid Gaussian representation better matches the thin-surface property of roads while significantly reducing redundant primitives and overlap during optimization. To further improve representation efficiency and structural fidelity, we introduce a road-structure-aware adaptive meshgrid strategy, which allocates denser Gaussian surfels to geometrically or semantically complex regions, such as lane markings, road boundaries, and height discontinuities, while maintaining a compact representation in flat road areas. Moreover, instead of relying on a single nearest vehicle pose, we design a trajectory-consistency-guided pose-robust refinement strategy, which estimates local surface priors from multiple neighboring poses and adaptively weights pose-guided height regularization according to their geometric consistency.","authors":["Tianchen Deng","Zhiheng Feng","Wenhua Wu","Ziming Li","Siting Zhu","Hesheng Wang"],"published":"2026-07-16T14:26:52Z","updated":"2026-07-16T14:26:52Z","abstract_url":"https://arxiv.org/abs/2607.15048v1","html_url":"https://arxiv.org/html/2607.15048v1","pdf_url":"https://arxiv.org/pdf/2607.15048v1.pdf","matched_keywords":["3d","representation"],"source_used":"html","source_text_chars":62151,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, representation 相关；摘要显示其主要贡献为：Road surface mapping plays a crucial role in autonomous driving, supporting high-definition map generation, lane-level perception, and automatic road annotation. Recent mesh-based road surface reconstruction methods have shown promising results, but they stil...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:01+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15041v1","title":"Weakly-Supervised RGB-D Salient Object Detection via SAM-driven Pseudo Annotation and State Space Interaction-based Diffusion","abstract":"Weakly-supervised RGB-D Salient Object Detection (SOD) is explored to reduce the heavy burden of pixel-level annotations. But scribble annotations lack the structure and details of objects, resulting in inaccurate saliency maps. In this paper, we propose a novel scribble-supervised RGB-D SOD method, consisting of a Segment Anything Model (SAM)-driven pseudo annotation generation method (\\emph{SAM-PAG}) and a state space interaction-based conditional diffusion model (\\emph{$S^2$Diff}). Specifically, SAM-PAG is tailored to address the issue of sparse supervision information. In SAM-PAG, we adopt the advanced SAM to expand sparse scribbles to dense pixel-level pseudo annotations through the dual-branch structure and the consistency of segmentation masks. In $S^2$Diff, we adopt the diffusion model to iteratively refine the noisy saliency maps with the guidance of conditional information, generating accurate saliency maps. Naturally, the core of our $S^2$Diff lies in the acquisition of conditional features and the denoising of saliency maps. For the former, we employ a cross-modal conditional generation module to interweave cross-modal features through frequency integration and implicit-explicit state space interaction, effectively achieving global conditional features. For the latter, we employ a context injection module to mitigate noise interference and to enhance object information with the conditional context. With the close cooperation of SAM-PAG and $S^2$Diff, our method outperforms relevant scribble-supervised methods and achieves competitive performance compared to fully-supervised methods on seven datasets. The code and results of our method are available at https://github.com/Switch457/WeakS2Diff_SOD.","authors":["Wenqi Si","Gongyang Li","Shixiang Shi","Weisi Lin"],"published":"2026-07-16T14:21:12Z","updated":"2026-07-16T14:21:12Z","abstract_url":"https://arxiv.org/abs/2607.15041v1","html_url":"https://arxiv.org/html/2607.15041v1","pdf_url":"https://arxiv.org/pdf/2607.15041v1.pdf","matched_keywords":["diffusion"],"source_used":"html","source_text_chars":84621,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 diffusion 相关；摘要显示其主要贡献为：Weakly-supervised RGB-D Salient Object Detection (SOD) is explored to reduce the heavy burden of pixel-level annotations. But scribble annotations lack the structure and details of objects, resulting in inaccurate saliency maps. In this paper, we propose a no...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:01+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.15038v1","title":"Video = World + Event Stream","abstract":"We present Wan-Streamer v0.3, which reframes our native-streaming interaction model under a single organizing view: a video is a world plus an event stream. The world is the persistent context in which a video unfolds, including the environment, scene, subjects, ambient acoustic conditions, voice characteristics, and other relatively stable conditions. The event stream is everything that changes over time within that world, including scene or environmental changes, subject behavior, speech, and other sounds. This yields a general-purpose pretraining task over large amounts of real video: given a world and incoming input, predict how the world moves, changes, and responds in real time. The resulting competence can be specialized to a broad family of real-time downstream tasks. We instantiate it on real-time full-duplex audio-visual interaction, where the event stream is the agent's speech together with free-form behavior. Functionally, the model's multimodal understanding process is vision-language-action-like: it maps multimodal user input to language-form speech and behavior actions. Wan-Streamer v0.3 preserves the v0.2 operating point: 640x368 video at 25 FPS, a 160 ms streaming unit, approximately 200 ms model-side response latency, and approximately 550 ms total interaction latency under a 350 ms bidirectional network budget.","authors":["Lianghua Huang","Zhi-Fan Wu","Yupeng Shi","Wei Wang","Mengyang Feng","Cheng Yu","Chen Liang","Junjie He","Chen-Wei Xie","Yu Liu","Jingren Zhou","Ang Wang","Bang Zhang","Baole Ai","Chongyang Zhong","Jinwei Qi","Kai Zhu","Pandeng Li","Peng Zhang","Wenyuan Zhang","Xinhua Cheng","Yitong Huang","Yun Zheng","Yuxiang Bao","Yuzheng Wang","Zhiwei Lin","Zoubin Bi"],"published":"2026-07-16T14:19:42Z","updated":"2026-07-16T14:19:42Z","abstract_url":"https://arxiv.org/abs/2607.15038v1","html_url":"https://arxiv.org/html/2607.15038v1","pdf_url":"https://arxiv.org/pdf/2607.15038v1.pdf","matched_keywords":["video","agent","multimodal"],"source_used":"html","source_text_chars":21545,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, agent, multimodal 相关；摘要显示其主要贡献为：We present Wan-Streamer v0.3, which reframes our native-streaming interaction model under a single organizing view: a video is a world plus an event stream. The world is the persistent context in which a video unfolds, including the environment, scene, subjec...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-17T03:57:01+00:00","status":"fallback"},"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14990v1","title":"JADE-GS: Joint Alternating Deblurring Guided by Events in 3D Gaussian Splatting","abstract":"When a camera moves fast during exposure, blur destroys the intra-exposure motion a 3D model needs to recover the sharp scene, while event cameras capture exactly this signal at microsecond resolution. Turning them into reliable 3D supervision faces two obstacles. First, the two restoration priors fail in opposite ways: physics-based event-integration priors preserve edges but accumulate drift; learned networks recover texture but distort boundaries. Second, existing pipelines run in one direction only, so raw event noise or the biases of fixed 2D pseudo-labels pass uncorrected into the geometry. JADE-GS addresses both: a pixel-adaptive routing gate fuses the complementary priors, and the resulting 2D restorer is coupled to a 3D Gaussian Splatting student in a bidirectional loop, where detached, multi-view-consistent renders and a physics-based reblurring constraint regularize the restorer, turning a fixed preprocessor into a geometry-aware predictor. Across synthetic and real benchmarks, JADE-GS attains the best perceptual quality, leading LPIPS and CLIP-IQA on both benchmarks with competitive PSNR and SSIM, and trainsin about one hour under 5 GB on a single consumer GPU while preserving real-time rendering.","authors":["Haoyu Fu","Jiafeng Huang","Yuchen Wang","Shengjie Zhao"],"published":"2026-07-16T13:40:13Z","updated":"2026-07-16T13:40:13Z","abstract_url":"https://arxiv.org/abs/2607.14990v1","html_url":"https://arxiv.org/html/2607.14990v1","pdf_url":"https://arxiv.org/pdf/2607.14990v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14976v1","title":"From Draft to Draft-Free: One-Step Video Object Removal via Privileged Distillation and Fast Planting","abstract":"Video object removal is a fundamental yet challenging task in video editing. Despite recent progress, existing methods typically fall into two categories. Traditional approaches based on optical flow or attention mechanisms often introduce noticeable artifacts and yield unnatural results. In contrast, diffusion-based methods improve visual realism but demand multiple denoising steps, limiting their practicality. To address these issues, we propose From-Draft-to-Draft-Free (D2DF), a framework that distills the ability of transforming coarse drafts into refined videos into a one-step video generation model. Within D2DF, a teacher model is trained to refine low-quality removal results (\"drafts\") into high-fidelity videos by multiple steps. Then, through Prior-Privileged Consistency Distillation (PPCD), we distill this capability into a student model that performs one-step removal conditioned on the draft. To eliminate draft dependency, we introduce a Self-Guided Fast Planting (SGFP) module based on our Temporal Masked Transformer that autonomously generates scene-consistent pseudo-drafts in latent space, enabling a fully draft-free one-step model. Extensive experiments show that both draft-conditioned and draft-free versions achieve state-of-the-art performance on multiple metrics, surpassing traditional and multi-step generative methods in both quality and efficiency. The denoising process for a single video takes only about 1 second.","authors":["Zizhao Chen","Ping Wei","Guang Dai","Jingdong Wang","Mengmeng Wang"],"published":"2026-07-16T13:29:27Z","updated":"2026-07-16T13:29:27Z","abstract_url":"https://arxiv.org/abs/2607.14976v1","html_url":"https://arxiv.org/html/2607.14976v1","pdf_url":"https://arxiv.org/pdf/2607.14976v1.pdf","matched_keywords":["video","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14974v1","title":"On Success and Simplicity: A Second Look at Transferable Vision-Language Attack Pipeline","abstract":"Vision-Language Pre-training Models (VLPMs) are known to be vulnerable to adversarial attacks. Recent transferable attacks on VLPMs have followed a common pipeline with complicated loss functions or multi-stage text/image attacks. However, in this paper, we demonstrate that such a sophisticated attack pipeline can be simpler yet more successful. Specifically, we identify three previously overlooked issues caused by inappropriate cross-modal interactions and excessive operations. To address them, we propose the Simple Vision-Language Attack (SimVLA) pipeline, which observably improves transferability and efficiency. Experiments on four datasets and three downstream tasks validate the superiority of our pipeline. For instance, on Flickr30k text-image retrieval dataset, our SimVLA outperforms the SOTA baseline in R@1 transferability by 8.01\\%-14.71\\%, while consuming only about 35.73\\% of the time and 46.26\\% of the max VRAM. Overall, the superiority of our SimVLA highlights the importance of leveraging domain knowledge (e.g., our proposed cross-modal word identification), while blindly pursuing intricate operations (e.g, complex loss functions and redundant multi-stage designs) may even be harmful. We hope our SimVLA can serve as a simple yet effective backbone for future extensions. Code is available at https://github.com/RYC-98/SimVLA.","authors":["Yuchen Ren","Zhengyu Zhao","Chenhao Lin","Bo Yang","Chao Shen"],"published":"2026-07-16T13:28:59Z","updated":"2026-07-16T13:28:59Z","abstract_url":"https://arxiv.org/abs/2607.14974v1","html_url":"https://arxiv.org/html/2607.14974v1","pdf_url":"https://arxiv.org/pdf/2607.14974v1.pdf","matched_keywords":["retrieval","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14968v1","title":"Stitch-Inferencer: Enhance Endoscopic Video Segmentation and Tracking via Panoramic Reconstruction","abstract":"Surgical video understanding is fundamental to navigation systems. Endoscopic perception is often hindered by a limited field-of-view and frequent instrument occlusions, making spatio-temporal context essential for robust inference. These challenges have motivated video models that aggregate information across frames. However, existing video models typically store past observations implicitly in learned feature representations, often requiring task-specific video training, substantial annotated data, and increased computational cost. We propose Stitch-Inferencer, a real-time, model-agnostic inference framework that replaces implicit feature memory with an explicit image-space panoramic canvas. By stitching valid observations across frames, Stitch-Inferencer preserves previously observed pixels in an online, instrument-free view, expanding the effective field-of-view and providing direct access to regions that are temporarily occluded or absent from the current frame. Downstream segmentation or tracking models are applied to a compact region of interest on the panorama, and their predictions are reprojected to the current frame, enabling existing models to exploit long-range context without retraining. Experiments on anatomy segmentation and point/box tracking demonstrate consistent improvements across diverse baselines while preserving real-time throughput. The stitching module alone runs at over 60 FPS, providing a practical inference-time solution to enhance endoscopic perception in computationally constrained intraoperative environments. Source code will be made publicly available.","authors":["Shunsuke Kikuchi","Atsushi Kouno","Hiroki Matsuzaki"],"published":"2026-07-16T13:24:56Z","updated":"2026-07-16T13:24:56Z","abstract_url":"https://arxiv.org/abs/2607.14968v1","html_url":"https://arxiv.org/html/2607.14968v1","pdf_url":"https://arxiv.org/pdf/2607.14968v1.pdf","matched_keywords":["video","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14966v1","title":"U-shaped Multi-granularity Learning for Vision-Language Models","abstract":"The prompt learning paradigm for vision-language models is effective yet faces a granularity dilemma: global prompts lack fine-grained semantic awareness, while local prompts ignore contextual associations, limiting cross-task generalization. This dilemma exists in dense prediction tasks. Inspired by U-Net, which unifies multi-level representations across granularities, we propose UPrompt, a U-shaped multi-granularity prompt learning framework for vision-language models. Similar to how U-Net integrates fine and coarse features through symmetric encoder-decoder pathways with cross-level connections, UPrompt constructs parallel multi-granularity representations in both visual and textual modalities, where coarse-to-fine cascaded enhancement propagates global context to refine local details, while fine-to-coarse hierarchical supervision ensures semantic consistency across scales. Extensive experiments on 17 benchmarks validate our effectiveness. UPrompt outperforms MAMET and VPKE by 4.1 and 7.3 rSum on MSCOCO, surpasses CoCoA-Mix by 5.09% in base-to-novel generalization, while maintaining competitive performance with minimal overhead (coarse-grained) and matching PSRC with 1/3 cost (medium-grained).","authors":["Biao Chen","Yunqian Yu","Xiangxu Zhao","Zhongshu Chen","Mengmeng Jing","Lin Zuo"],"published":"2026-07-16T13:18:08Z","updated":"2026-07-16T13:18:08Z","abstract_url":"https://arxiv.org/abs/2607.14966v1","html_url":"https://arxiv.org/html/2607.14966v1","pdf_url":"https://arxiv.org/pdf/2607.14966v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14962v1","title":"Multi-Axis Max@K Reinforcement Learning for Representative Diversity in Text-to-Image Generation","abstract":"Text-to-image (T2I) models can synthesize realistic, prompt-aligned images, yet samples generated for the same prompt often cover only a small subset of visually distinct modes. This limits the diversity of images, and for person-centric prompts, can reflect or amplify demographic skew. We formalize this problem as coverage of a predefined set of semantically specified modes, which we call target-mode coverage. We then propose multi-axis max@K, a group-based reinforcement learning objective for improving such coverage in diffusion-based T2I models. Given a group of samples and one score per target category, multi-axis max@K first takes the maximum score across samples for each category and then sums these category-wise maxima. The resulting credit assignment gives a sample positive weight on a category only when it increases that category's group-wise maximum, allowing different samples to contribute to different categories. We first validate the credit-assignment mechanism on a synthetic mixture and on SD3.5-M using deterministic pixel-based color rewards. We then evaluate the same objective on perceived-appearance fairness. Across three automatic evaluators on held-out prompts, multi-axis max@K improves the Fairness Score by 0.23-0.36 relative to the base model, while maintaining image quality and text alignment.","authors":["Ku Onoda","Paavo Parmas","Hiroki Furuta","Soichiro Nishimori","Yuta Oshima","Shohei Taniguchi","Yutaka Matsuo"],"published":"2026-07-16T13:14:21Z","updated":"2026-07-16T13:14:21Z","abstract_url":"https://arxiv.org/abs/2607.14962v1","html_url":"https://arxiv.org/html/2607.14962v1","pdf_url":"https://arxiv.org/pdf/2607.14962v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14945v1","title":"Introspective Attention Modulation for Safe Text-to-Image Generation","abstract":"State-of-the-art flow based text-to-image (T2I) models exhibit remarkable generative abilities but remain vulnerable to producing unsafe content. Prior safety efforts range from concept erasure and prompt filtering to classifier-based gating. However, simple techniques like parameter efficient adaptations of the models easily bypass such guardrails. We introduce a unique principled approach that achieves safety by regulating the model's attention dynamics through inference-time introspection, exhibiting intrinsic robustness. Our method analyzes and rebalances attention activations throughout image synthesis, steering generations away from unsafe concepts while preserving semantic alignment. This introspective control ensures safety of deployed models. Across standard and adversarial safety benchmarks, our approach achieves remarkable safety scores while maintaining or even improving alignment and perceptual quality. Our results reveal that attention-space regulation offers a considerably more promising path to safer diffusion transformer based image generation than the existing concept erasing mechanism.Our code can be accessed at https://basim-azam.github.io/iam/","authors":["Basim Azam","Hossein Rahmani","Naveed Akhtar"],"published":"2026-07-16T12:53:45Z","updated":"2026-07-16T12:53:45Z","abstract_url":"https://arxiv.org/abs/2607.14945v1","html_url":"https://arxiv.org/html/2607.14945v1","pdf_url":"https://arxiv.org/pdf/2607.14945v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14935v1","title":"VideoChat3: Fully Open Video MLLM for Efficient and Generalist Video Understanding","abstract":"Recent advances in video understanding have spanned motion, long video, and streaming interaction, driving this field toward real-world applications. Despite this progress, current open-source models remain limited in several ways. They often struggle to generalize across diverse video types, making them effective only in specific domains. High computational demands further restrict their efficiency and scalability. Moreover, most models are only partially open, with key components such as training code, strategy, or datasets unavailable, which hinders reproducibility and slows community-driven development. To address these issues, we introduce VideoChat3, a fully open, efficient, and generalist video-centric MLLM. VideoChat3 advances video understanding through two complementary designs. For efficiency, we introduce Inflated 3D Vision Transformer (I3D-ViT) and Adaptive Frame Resolution for Streaming Video Perception, which enables efficient spatiotemporal representation and reduces the cost of processing video inputs during training and inference. For effectiveness, we develop a scalable video data synthesis pipeline that curates three diverse, high-quality training datasets: VideoChat3-Academic2M, VideoChat3-LV116K, and VideoChat3-OL617K, covering general, long-form, and streaming video scenarios, improving the model's generalization across domains. By integrating these designs, VideoChat3 achieves a rare balance of broad generalization and computational efficiency. Experiments across general, long-form, and streaming benchmarks demonstrate that VideoChat3 surpasses prior open-source models with equal or larger parameter counts with only 4B parameters and higher efficiency.","authors":["Xinhao Li","Yuhan Zhu","Xiangyu Zeng","Yuhao Dong","Haoning Wu","Zhiqiu Zhang","Yuandong Yang","Changlian Ma","Qingyu Zhang","Yansong Shi","Xinyu Chen","Haoran Chen","Zizheng Huang","Jun Zhang","Kun Ouyang","Lin Sui","Ziang Yan","Yicheng Xu","Chenting Wang","Yinan He","Hongjie Zhang","Yi Wang","Yu Qiao","Yali Wang","Ziwei Liu","Kai Chen","Limin Wang"],"published":"2026-07-16T12:47:59Z","updated":"2026-07-16T12:47:59Z","abstract_url":"https://arxiv.org/abs/2607.14935v1","html_url":"https://arxiv.org/html/2607.14935v1","pdf_url":"https://arxiv.org/pdf/2607.14935v1.pdf","matched_keywords":["video","3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14934v1","title":"Still image and spatial-temporal tomato data enabling detection, segmentation, tracking, and video-instance segmentation using strong and weak labels","abstract":"In this manuscript we release two datasets for visual sensing of tomato plants grown in commercial-like settings and acquired using a robot. The first is BUTom21 which consists of still images and manual annotations. The second is BUTom-ST21 which consists of video-based data and semi-automated annotations through AI-based methods, referred to as pseudo-labels. In both cases, we provide pixel-level labels for the ripeness of the fruit. The aim is to provide the research community a challenging set of real-world imagery to explore methods to sense and estimate the state of tomato plants and their fruit, which is an important horticultural crop. Importantly, the spatial-temporal dataset provides individual fruit count and ripeness information enabling researchers to push the boundaries of field-based phenotyping.","authors":["Michael Halstead","Esra Guclu","Mohamed Farag","Enrico Pallotta","Christian Hund","Ribana Roscher","Maren Bennewitz","Juergen Gall","Cyrill Stachniss","Chris McCool"],"published":"2026-07-16T12:47:55Z","updated":"2026-07-16T12:47:55Z","abstract_url":"https://arxiv.org/abs/2607.14934v1","html_url":"https://arxiv.org/html/2607.14934v1","pdf_url":"https://arxiv.org/pdf/2607.14934v1.pdf","matched_keywords":["video","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14927v1","title":"TanGO: Training-Free 3D Editing via Tangent-Space Guidance and Optimization","abstract":"While recent flow-matching 3D generative models (e.g., VecSet) adopt structured representations, their tokens share global context, causing conventional training-free editing to suffer from semantic artifacts such as collapsed preserved regions or incomplete transformations. To address this, we propose TanGO, a training-free framework that enables adaptive per-token steering in the tangent space of generative dynamics. To realize this selective control, we formulate a one-step optimal control rule and determine the strength of each token's control signal using a von Mises-Fisher inspired directional discrepancy derived from the source and target velocity fields. Experiments show that TanGO substantially reduces structural artifacts and achieves state-of-the-art performance, outperforming existing 3D editing baselines. The code is publicly available at https://github.com/siw00-lim/TanGO.","authors":["Siwoo Lim","Sunjae Yoon","Gwanhyeong Koo","Hyeonseo Yun","Chang D. Yoo"],"published":"2026-07-16T12:42:50Z","updated":"2026-07-16T12:42:50Z","abstract_url":"https://arxiv.org/abs/2607.14927v1","html_url":"https://arxiv.org/html/2607.14927v1","pdf_url":"https://arxiv.org/pdf/2607.14927v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14898v1","title":"FlashDecoder: Real-Time Latent-to-Pixel Streaming Decoder with Transformers","abstract":"Real-time video generation demands fast decoding as much as fast denoising, yet current latent video diffusion models rely on 3D convolutional decoders that are slow and memory-intensive at high resolutions or for long video. We introduce FlashDecoder, a fast, memory-efficient pure-Transformer video decoder that decodes latents to pixels frame by frame. At each step, the current frame attends only to a fixed-size window of past frames through a rolling KV cache. The fixed temporal window keeps decoding fast and memory bounded regardless of video length, enabling constant-latency streaming. Because frames are processed sequentially, temporal causality is enforced without explicit attention masks, enabling training at resolutions up to 1080p and matching the reconstruction quality of convolutional decoders. On the Wan2.1 and Wan2.2 latent spaces, FlashDecoder matches each convolutional decoder in reconstruction quality (e.g., 41.55dB vs. 41.49dB PSNR at 1080p) while decoding 3.6x-4.7x faster with up to 11x less memory on a single H100 GPU. With architecture-aware inference optimizations, the speedup widens to 12x.","authors":["Minguk Kang","Suha Kwak"],"published":"2026-07-16T12:16:12Z","updated":"2026-07-16T12:16:12Z","abstract_url":"https://arxiv.org/abs/2607.14898v1","html_url":"https://arxiv.org/html/2607.14898v1","pdf_url":"https://arxiv.org/pdf/2607.14898v1.pdf","matched_keywords":["video","3d","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14876v1","title":"Rotational Motion-Induced Error Compensation for Phase-Shifting Profilometry-Based Eye Reconstruction","abstract":"With the proliferation of immersive Head-Mounted Displays (HMDs) for Virtual and Augmented Reality (VR/AR), reliable and high-precision eye tracking has become increasingly important. Conventional 2D image-based methods offer low system complexity but remain limited in stability, accuracy, and robustness. Three-dimensional ocular surface reconstruction can provide richer geomet-ric information, and structured light profilometry is particularly attractive because it enables dense and accurate surface measurement. However, Phase-Shifting Profilometry (PSP), which estimates phase from sequentially acquired fringe images, is highly susceptible to motion-induced errors when the eye rotates between frames. This study proposes a rotational motion compensation framework for PSP-based dynamic 3D eye reconstruction. Relative eye rotation is estimated from image-based motion cues using a user-specific 3D eye model in a spherical-coordinate domain. The estimated motion is then used to compensate for camera-pixel mismatch and phase-shift errors caused by inter-frame rotation. A region-wise optimization strategy is further introduced to reduce residual artifacts by inde-pendently refining the compensation strength in different ocular regions. Experiments with a rotating fake eye under non-uniform motion demonstrate that the proposed method substantially suppresses motion-induced deformation and improves reconstruction accuracy. An additional experiment with a non-spherical rigid object indicates that the compensation principle is not restricted to spherical eye geometry. These results establish a practical basis for stable PSP-based dynamic 3D eye reconstruction toward future high-precision eye tracking in immersive environments.","authors":["Seong-Jin An","Sanghoon Jeon","Yatong An","Jae-Sang Hyun"],"published":"2026-07-16T11:46:44Z","updated":"2026-07-16T11:46:44Z","abstract_url":"https://arxiv.org/abs/2607.14876v1","html_url":"https://arxiv.org/html/2607.14876v1","pdf_url":"https://arxiv.org/pdf/2607.14876v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14836v1","title":"Physics-Informed Diffusion for Biomechanically Plausible 3D Sign Language Generation","abstract":"Sign language production, which generates continuous 3D skeletal motion from spoken language input, must simultaneously satisfy two constraints: semantic fidelity, so that a deaf viewer can recognize the intended sequence of glosses, and biomechanical plausibility, so that the generated skeleton respects anatomical constraints. Existing approaches optimize semantic reconstruction through coordinate-based objectives that treat the skeleton as an unstructured vector, thus allowing for bone length drift, joint angle violations, and temporarily locked fingers. We introduce PIDiffSign, a physics-informed diffusion model for gloss-to-pose translation that incorporates anatomical constraints into both the architecture and training objective. The model uses a Transformer encoder-decoder, where the decoder is conditioned on the diffusion time step through adaptive zero-initialized layer normalization and cross-attends to gloss representations. A differentiable geometry module enforces bone length consistency and biologically valid joint angles throughout generation. Training combines anthropomorphic, kinematic, angular, and finger-joint constraints with a contrastive gloss-pose alignment loss and classifier-free guidance for semantically conditioned sampling. Experiments on the PHOENIX14T and CSL-Daily benchmarks show consistent improvements over a strong diffusion baseline in pose accuracy, joint-angle correctness, distributional realism, and back-translation quality. These results demonstrate that physics-informed diffusion improves both motion realism and semantic fidelity for sign language generation.","authors":["Emanuele Colonna","Moises Diaz","Gennaro Vessio","Miguel Angel Ferrer","Giovanna Castellano"],"published":"2026-07-16T11:01:33Z","updated":"2026-07-16T11:01:33Z","abstract_url":"https://arxiv.org/abs/2607.14836v1","html_url":"https://arxiv.org/html/2607.14836v1","pdf_url":"https://arxiv.org/pdf/2607.14836v1.pdf","matched_keywords":["3d","representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14809v1","title":"An LLM-Based Automatic Sportscast Solution for Robot Soccer Matches","abstract":"RoboCup has always been a scenario to develop systems that solve real-world problems. Driven by the main goal of playing against the 2050 FIFA World Cup champions, the RoboCup Soccer leagues need to constantly measure how the research community is progressing. Computing visual statistics from match videos is a crucial way to track this evolution. To address this challenge, this paper introduces a fully autonomous, real-time sports commentator for RoboCup matches. By bridging the gap between raw kinematic tracking and natural language generation, our neuro-symbolic architecture extracts precise statistics from video streams and turns them into fluent, hallucination-free narration. The proposed system is capable of generating statistics and commentary both during live match streaming and in post-game analysis, easily adapting to the new dynamism of the league where different humanoid robots of different sizes share the field. Supplemental materials are available at https://lab-rococo-sapienza.github.io/MARIO/","authors":["Francesco Petri","Michele Brienza","Daniele Nardi","Domenico Daniele Bloisi","Aldo Gangemi","Vincenzo Suriani"],"published":"2026-07-16T10:27:23Z","updated":"2026-07-16T10:27:23Z","abstract_url":"https://arxiv.org/abs/2607.14809v1","html_url":"https://arxiv.org/html/2607.14809v1","pdf_url":"https://arxiv.org/pdf/2607.14809v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14807v1","title":"TAMF-VTON: Texture-Aware Mask-Free Virtual Try-On via High-Fidelity Image Synthesis","abstract":"Recent diffusion-based virtual try-on (VTON) methods remain limited by their reliance on segmentation masks, insufficient preservation of fine-grained textures, and limited support for arbitrary multi-garment compositions. Consequently, existing approaches still face significant challenges in real-world e-commerce deployment. We present TAMF-VTON, a texture-aware, mask-free framework that enables high-fidelity image synthesis under practical unconstrained conditions. Our method requires no human parsing or inpainting masks at inference time and supports diverse garment styles, categories, and quantities, enabling the simultaneous transfer of multiple items while preserving body structure and intricate texture details. This is achieved through a unified generative pipeline with three key components: (1) a lightweight Mixture-of-Experts (MoE) adaptation scheme that enables efficient fine-tuning without compromising the base model's general editing capabilities; (2) a frequency-domain supervision mechanism that explicitly optimizes high-frequency spectral consistency to preserve high-fidelity textures; and (3) a robust data curation pipeline employing an adaptive inpainting strategy to simulate the inverse VTON process for high-quality training pair generation. Extensive experiments demonstrate that our approach outperforms state-of-the-art methods in both quantitative metrics and perceptual quality. Optimized for efficiency, the model achieves inference in under 15 seconds per image on an NVIDIA RTX 4090 with INT4 quantization. By combining mask-free operation, flexible multi-garment composition, faithful texture preservation, and efficient inference on consumer hardware, TAMF-VTON demonstrates a commercially viable solution for scalable deployment in real-world digital fashion scenarios. The project is available at https://www.style3d.ai/ai-photoshoot/virtual-clothing-try-on.","authors":["Jie Wang","Qian He","Gaofeng He","Xiaogang Jin","Huamin Wang"],"published":"2026-07-16T10:26:27Z","updated":"2026-07-16T10:26:27Z","abstract_url":"https://arxiv.org/abs/2607.14807v1","html_url":"https://arxiv.org/html/2607.14807v1","pdf_url":"https://arxiv.org/pdf/2607.14807v1.pdf","matched_keywords":["3d","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14765v1","title":"Rare Concept Generation via Counterfactual Inference in Diffusion Models","abstract":"Rare concept generation focuses on synthesizing customized images conditioned on text prompts that describe objects with unusual attributes. Previous works failed to align the generated images with rare concepts, resulting in incorrect attribute rendering or inconsistent composition of concepts. Such failures, as we observed, stem from the inherent common knowledge bias in the training stage of diffusion models, where objects are strongly associated with their common attributes, making it difficult to break these associations when generating rare concepts. To address such challenges, in this paper, we propose a novel Counterfactual Inference-based Diffusion approach, dubbed CI-Diff. CI-Diff blocks the interference of the model's inherent common knowledge bias and utilizes the Natural Direct Effect to capture the independent influence of the text prompt of rare concepts on image generation so that decoupling the unusual attributes from the rare concepts. To this end, we reformulate the classifier-free guidance mechanism to highlight the atypical attributes. To the best of our knowledge, we are the first to introduce causal inference into the rare concept generation task. Extensive experiments on the RareBench benchmark validate the superiority of CI-Diff over state-of-the-art diffusion models. Our code can be accessed from https://github.com/200204jzy/CI-Diff.","authors":["Zhengyuan Jiang","Haipeng Liu","Meng Wang","Yang Wang"],"published":"2026-07-16T09:49:06Z","updated":"2026-07-16T09:49:06Z","abstract_url":"https://arxiv.org/abs/2607.14765v1","html_url":"https://arxiv.org/html/2607.14765v1","pdf_url":"https://arxiv.org/pdf/2607.14765v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14749v1","title":"WanSong v1.0 Technical Report","abstract":"Music generation foundation models have recently attracted significant industry attention. However, achieving efficient generation and high-fidelity long-form audio while supporting controllability remains challenging. To address these needs, we present \\textbf{WanSong}, a simple yet powerful approach for long-form, commercial-grade song generation. Unlike autoregressive (AR) and cascaded multi-stage pipelines (\\eg, AR followed by diffusion), \\textbf{WanSong} is a pure diffusion-based model that directly generates high-fidelity, multilingual songs up to 5 minutes and outputs dual stems (vocals and background music) in a single run. In addition, our diffusion framework enables faster inference through step-distillation, and offers an efficient pathway for fine-tuning and customization to support downstream editing tasks.","authors":["Binghui Chen","Pandeng Li","Yu Liu","Jingren Zhou"],"published":"2026-07-16T09:34:59Z","updated":"2026-07-16T09:34:59Z","abstract_url":"https://arxiv.org/abs/2607.14749v1","html_url":"https://arxiv.org/html/2607.14749v1","pdf_url":"https://arxiv.org/pdf/2607.14749v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14739v1","title":"FoMoVLA: Bridging Visual Foresight and Motion Guidance for Vision-Language-Action Models","abstract":"Vision-Language-Action (VLA) models have achieved impressive results in visuomotor policy learning, yet remain fundamentally reactive, mapping current observations and language to actions without explicit forward prediction of world dynamics. Existing visual foresight methods predict future visual states but lack explicit motion guidance: they show where to go but not how to get there. We argue that future feature prediction and sparse point tracking are naturally complementary: the former provides the goal state, while the latter captures the continuous motion path toward it. We propose FoMoVLA, a framework that augments VLA representations with explicit spatio-temporal supervision by jointly learning future feature foresight and sparse 2D point tracking, enhancing the continuous action policy. FoMoVLA introduces compact foresight tokens to decode future feature states, decodes sparse temporal 2D point trajectories to model compact geometric motion, and couples both through a lightweight future-conditioned cross-attention module that enables consistent reasoning between anticipated states and point dynamics. Extensive experiments on LIBERO, RoboCasa GR-1 Tabletop, and LIBERO-Plus demonstrate state-of-the-art performance and strong zero-shot generalization. Project page is available at https://liauto-research.github.io/FoMoVLA.","authors":["Wei Li","Peijin Jia","Yuan Ma","Xuefeng Jiang","Titong Jiang","Sheng Sun","Yujian Li","Xin Wen","Han Hong","Zhikang Liu","Bailin Li","Kun Zhan"],"published":"2026-07-16T09:04:50Z","updated":"2026-07-16T09:04:50Z","abstract_url":"https://arxiv.org/abs/2607.14739v1","html_url":"https://arxiv.org/html/2607.14739v1","pdf_url":"https://arxiv.org/pdf/2607.14739v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14737v1","title":"GeoDetect: Geometric Adversarial Detection for VLPs","abstract":"Vision-language pre-trained models (VLPs) are widely used in real-world applications. However, they remain vulnerable to adversarial attacks. Although adversarial detection methods have demonstrated success in single-modality settings (either vision or language), their effectiveness and reliability in multimodal models such as VLPs remain largely unexplored. In this work, we study the geometry of VLP embedding spaces and observe structured anisotropy that differs from unimodal vision models. Our theoretical analysis shows that under this anisotropic structure, adversarial attacks increase the expected geometric separation between clean and adversarial examples (AEs). Specifically, we demonstrate that AEs consistently exhibit greater expected distances to randomly sampled points than their clean counterparts, indicating that AEs tend to push representations out of manifold regions. Building on these insights, we propose GeoDetect, which leverages these off-manifold deviations via geometric scores to identify AEs. Through comprehensive evaluations, we show that our approach reliably detects AEs across diverse VLP architectures and threat settings, covering unimodal and multimodal attacks as well as adaptive attacks, thereby providing a robust and practical approach to improving the safety and reliability of these models.","authors":["Afsaneh Hasanebrahimi","Hanxun Huang","Christopher Leckie","James Bailey","Sarah Erfani"],"published":"2026-07-16T09:02:38Z","updated":"2026-07-16T09:02:38Z","abstract_url":"https://arxiv.org/abs/2607.14737v1","html_url":"https://arxiv.org/html/2607.14737v1","pdf_url":"https://arxiv.org/pdf/2607.14737v1.pdf","matched_keywords":["representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14728v1","title":"VQ-Touch: A Data-Efficient Tactile Generation Framework Across Sensors and Scenarios","abstract":"Tactile image generation significantly reduces the dependency on expensive and wear-prone sensors by synthesizing high-fidelity tactile data, offering an efficient solution for tactile information acquisition in robotic perception and human-machine interaction systems. However, existing methods depend on large-scale, diverse datasets from specific sensors and lack efficient data utilization and robust generalization capabilities, struggling in vision-limited environments. To address this, we introduce VQ-Touch, a tactile generation framework that supports both cross-sensor and multi-scenario applications. Specifically, to efficiently extract complex deformation and texture features from the data, we propose DM-VQGAN, an effective tactile representation learner. Furthermore, we introduce a discrete diffusion decoder with a unified conditioning interface, supporting multimodal generation tasks such as images and labels, and enhances the model's generalization capability through few-shot mixed training, thus achieving compatibility with current mainstream sensors and their variants. Experiments show that VQ-Touch surpasses state-of-the-art methods in multiple tasks.","authors":["Kailin Lyu","Long Xiao","Jianing Zeng","Di Wu","Lin Shu","Jie Hao"],"published":"2026-07-16T08:53:41Z","updated":"2026-07-16T08:53:41Z","abstract_url":"https://arxiv.org/abs/2607.14728v1","html_url":"https://arxiv.org/html/2607.14728v1","pdf_url":"https://arxiv.org/pdf/2607.14728v1.pdf","matched_keywords":["representation","multimodal","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14721v1","title":"Multimodality as Supervision: Self-Supervised Specialization to the Test Environment via Multimodality","abstract":"Cross-modal learning, i.e., learning to predict one modality from another, is a fundamental mechanism for self-supervision via leveraging multimodality. Many practical applications, e.g., deploying a household robot, involve devices that are equipped with a rich set of sensors that enable multimodal sensing in their test environment. This presents an opportunity to apply cross-modal learning to the multimodal data sensed by these devices to learn representations. Findings in developmental psychology also suggest that biological agents leverage it to build an effective representation of their surroundings. To study this, we propose a controlled setup, where we restrict a user device to just a given test environment. It results in a specialization setup where we attempt to develop a performant model for this specific test environment. Under this setup, we develop Test-Space Training (TST), which performs multimodal data collection in the test environment and performs self-supervised pre-training on it. We evaluate these models on various downstream tasks in the same environment. Under this setup, we find various interesting insights, such as collecting rich multimodal data only from the test environment and leveraging cross-modal learning, we can achieve competitive results with generalist models (e.g., DINOv2 and CLIP) pre-trained on large-scale internet datasets. This enables an alternative scenario where the need for external Internet-scale datasets for pre-training models is reduced. We also present a set of analyses and ablations that raise intriguing points on substituting data with (multi)modality, and how varying pre-training data enables a tradeoff between a model's abilities to specialise to a test environment, and generalize to held-out spaces.","authors":["Kunal Pratap Singh","Ali Garjani","Rishubh Singh","Muhammad Uzair Khattak","Efe Tarhan","Jason Toskov","Andrei Atanov","Oğuzhan Fatih Kar","Amir Zamir"],"published":"2026-07-16T08:36:54Z","updated":"2026-07-16T08:36:54Z","abstract_url":"https://arxiv.org/abs/2607.14721v1","html_url":"https://arxiv.org/html/2607.14721v1","pdf_url":"https://arxiv.org/pdf/2607.14721v1.pdf","matched_keywords":["agent","representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14720v1","title":"Causal-Adversarial Probing of Clinical Covariates for Prostate MRI Grading","abstract":"Deep learning models for prostate MRI-based cancer grading may encode clinical covariates that either reflect useful disease-related signal or non-generalising shortcut information, but their role is usually assumed. We propose a causal-reasoning framework for probing covariate dependence in MRI-based International Society of Urological Pathology (ISUP) Grade Group prediction. Rather than treating mpMRI as a direct cause of grade, we model MRI appearance and ISUP grade as observations of latent tumour pathology, and test whether candidate clinical variables act as nuisance correlates, disease-related proxies, or irrelevant covariates in the learned representation. We implement this using an adversarial framework that suppresses the decodability of individual clinical covariate at a time while preserving MRI-based grade prediction. The approach is developed and evaluated on 2,903 prostate MRI examinations, with external validation on 576 patients. We report a set of interesting and previously under-explored imaging-to-clinical-variable interactions in the context of deep learning generalisation. For examples, in binary ISUP Grade Group $\\geq2$ classification, suppressing age, BMI, and alcohol use improved AUC by 1.23%, 0.84%, and 1.42%, respectively (all p < 0.05), suggesting reduced non-generalising covariate information; In contrast, suppressing PSA and prostate volume degraded AUC by 1.91% and 7.61% (all p < 0.001), indicating that these variables carried task-relevant signal. These findings show that adversarial covariate suppression can provide a practical representation-level analysis for distinguishing potentially harmful dependence from informative signal in prostate MRI grading models.","authors":["Yipei Wang","Shiqi Huang","Wen Yan","Weixi Yi","Dean C. Barratt","Mark Emberton","Daniel C. Alexander","Veeru Kasivisvanathan","Yipeng Hu"],"published":"2026-07-16T08:36:34Z","updated":"2026-07-16T08:36:34Z","abstract_url":"https://arxiv.org/abs/2607.14720v1","html_url":"https://arxiv.org/html/2607.14720v1","pdf_url":"https://arxiv.org/pdf/2607.14720v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14711v1","title":"VideoSEMA: a scalable and efficient Mamba-like attention for video understanding","abstract":"We present for video understanding (classification) a split space-time attention model, VideoSEMA, consisting of a scalable and efficient Mamba-like attention (SEMA) block in space and a softmax temporal attention in time. In each frame, SEMA attention applies a local window attention in parallel with a global averaging in a Mamba macro-architecture, which is called Mamba-like. Under certain rank conditions, we prove that the computationally cheaper split space-time attention is equivalent to full space-time attention. On benchmark K400 data sets, VideoSEMA out-performs heavier vision transformer and Mamba models. On benchmark SSv2 data, VideoSEMA leads in top-1 accuracy among models of similar parameter sizes. As image resolution scales up from standard $224^2$ to $1024^2$ on K400 and without fine-tuning, VideoSEMA degrades much more gracefully than VideoMamba in accuracy. It is promising to extend VideoSEMA to longer videos with a dilated/sparse temporal attention.","authors":["Nhat Thanh Tran","Fanghui Xue andShuai Zhang","Jiancheng Lyu","Yunling Zheng","Yingyong Qi","Jack Xin"],"published":"2026-07-16T08:22:08Z","updated":"2026-07-16T08:22:08Z","abstract_url":"https://arxiv.org/abs/2607.14711v1","html_url":"https://arxiv.org/html/2607.14711v1","pdf_url":"https://arxiv.org/pdf/2607.14711v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14710v1","title":"Variational Inference for Bird's Eye View Segmentation in Autonomous Driving","abstract":"The bird's eye view (BEV) has emerged as a pivotal approach for environmental perception in autonomous driving, providing a unified spatial representation for vehicles. Nevertheless, despite BEV's significance in addressing the challenges inherent to autonomous driving, effectively fusing data from multiple camera sensors and operating in complex external driving environments remains a considerable challenge. To mitigate this issue, we recast the BEV segmentation problem within a variational inference framework. In this paper, we propose a novel transformer-based variational flow transformation network for BEV segmentation, denoted as TVB. Our architecture implicitly learns the mapping from multiple camera views to a unified canonical BEV map during training by exploiting posterior BEV supervision. TVB employs a conditional variational auto encoder (CVAE) as its backbone and produces multiple BEV map candidates. To augment the realism of the generated BEV maps, we integrate normalizing flows into the map generation process, enabling the construction of more complex and expressive probability distributions. Furthermore, we design a BEV-attention fusion (BAF) module that harnesses attention mechanisms to adaptively integrate the multiple candidate BEV maps. Experimental results, evaluated on both the nuScenes and OPV2Vdatasets, demonstrate that our proposed method achieves superior performance in multi-camera view BEV segmentation and lane environment perception.","authors":["Jingyue Shi","Huaicheng Li","Junhui Zhao","Yanxiang Jiang"],"published":"2026-07-16T08:20:37Z","updated":"2026-07-16T08:20:37Z","abstract_url":"https://arxiv.org/abs/2607.14710v1","html_url":"https://arxiv.org/html/2607.14710v1","pdf_url":"https://arxiv.org/pdf/2607.14710v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14703v1","title":"Pretraining Multiple Instance Learning Networks with Multi-Teacher Distillation from Pathology Slide Foundation Models","abstract":"Multiple instance learning (MIL) has become the main paradigm for whole-slide image (WSI) analysis in computational pathology. However, existing MIL aggregators are still typically trained from scratch for each downstream task, relying on limited slide-level labels to learn both aggregation mechanisms and downstream discriminative representations simultaneously. As a result, they often suffer from unstable optimization, overfitting, and limited transferability. Similar to pretrained ResNet and Vision Transformer models in natural image learning, MIL also requires reusable pretrained initialization. However, high-quality slide-level pretraining data remain scarce, and MIL models are usually lightweight and weakly supervised, making large-scale pretraining difficult in practice. To address this challenge, we propose a distillation-based pretraining framework for MIL, which leverages two slide-level foundation models, TITAN and CARE, as teachers to transfer their representational knowledge into a diverse set of MIL architectures. To effectively balance supervision from different teachers, we further introduce an angular dispersion normalized distillation loss. The distilled weights are then used as initialization for downstream adaptation. We conduct systematic evaluations on 15 benchmark datasets under both linear probing and full-parameter fine-tuning, and further validate its advantages in few-shot scenarios. Experimental results show that pretraining generally improves MIL aggregators over from scratch training, especially in linear-probing and few-shot settings, while maintaining the computational efficiency of lightweight MIL models. Code is available at https://github.com/fu0201/MIL_Pretrained.","authors":["Mingxi Fu","Jiawen Li","Renao Yan","Jiali Hu","Qiehe Sun","Tian Guan","Yonghong He"],"published":"2026-07-16T08:04:25Z","updated":"2026-07-16T08:04:25Z","abstract_url":"https://arxiv.org/abs/2607.14703v1","html_url":"https://arxiv.org/html/2607.14703v1","pdf_url":"https://arxiv.org/pdf/2607.14703v1.pdf","matched_keywords":["representation","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14702v1","title":"Team RAS in 11th ABAW Competition: Multimodal Ambivalence Recognition Approach","abstract":"Automatic recognition of ambivalence and hesitancy is challenging because these states may be expressed through inconsistent linguistic, acoustic, facial, and contextual patterns, while top-performing systems often rely on computationally expensive ensembles. We present a single text-centered multimodal approach for video-level ambivalence and hesitancy recognition for the 11th Affective & Behavior Analysis in-the-Wild (ABAW) Challenge. The proposed approach combines linguistic, acoustic, facial, and scene features using text-centered multimodal fusion model. Text Residual Fusion treats text as the anchor modality and applies gated residual adjustments based on the other modalities. Experiments on the Behavioural Ambivalence/Hesitancy (BAH) corpus confirm that text is the strongest unimodal modality. The Text Residual Fusion model achieves an average Macro F1-score (MF1) of 75.14% across the Development and Public Test subsets. On the Private Test subset, it reaches an MF1 of 78.24%, outperforming the text model by 4.03%. These results demonstrate that complementary multimodal information can improve recognition performance without requiring a large model ensemble.","authors":["Elena Ryumina","Maxim Markitantov","Alexandr Axyonov","Fedor Shchetinin","Timur Abdulkadirov","Dmitry Ryumin","Alexey Karpov"],"published":"2026-07-16T08:04:23Z","updated":"2026-07-16T08:04:23Z","abstract_url":"https://arxiv.org/abs/2607.14702v1","html_url":"https://arxiv.org/html/2607.14702v1","pdf_url":"https://arxiv.org/pdf/2607.14702v1.pdf","matched_keywords":["video","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14681v1","title":"ReBind: Multi-Reference Video Editing via Structured Instructions with Explicit Reference Relationships","abstract":"Recent diffusion-based video generation models have made significant progress in multi-reference image-conditioned video editing. However, existing methods still struggle to coordinate information from multiple visual sources accurately. We identify a critical deficiency in existing approaches. Existing editing instructions lack explicit reference relationships, and most multimodal large language models (MLLMs) cannot generate them reliably. To address this problem, we propose ReBind, a systematic framework that introduces semantic instructions with embedded reference tokens as the intermediate representation for multi-reference image-conditioned video editing. Our key insight is embedding reference tokens at semantic positions to eliminate ambiguity and establish precise bindings between visual attributes and their sources. We develop ReBind-Instruct, a specialized MLLM that learns to establish explicit bindings between visual attributes and their reference sources through a two-stage progressive scheme for precise reference relationships. We further develop ReBind-Edit, which enables lightweight adaptation of text-to-video models to coordinate multiple references by binding visual attributes to their designated sources. Extensive experiments demonstrate that ReBind substantially outperforms general-purpose MLLMs in instruction quality and achieves state-of-the-art performance among open-source methods on reference image conditioned video editing. Our project webpage: https://rebind-mrv2v.github.io/.","authors":["Xinyu Liu","Shihao Li","Weihong Lin","Xinlong Chen","Yang Shi","Yujin Han","Yiyang Cai","Yanghao Wang","Ruibin Yuan","Yuanxing Zhang","Pengfei Wan","Wenhan Luo","Yike Guo"],"published":"2026-07-16T07:43:27Z","updated":"2026-07-16T07:43:27Z","abstract_url":"https://arxiv.org/abs/2607.14681v1","html_url":"https://arxiv.org/html/2607.14681v1","pdf_url":"https://arxiv.org/pdf/2607.14681v1.pdf","matched_keywords":["video","representation","multimodal","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14660v1","title":"VIABench: A Comprehensive Video Benchmark Collected from Blind Individuals for Visual Impairment Assistance","abstract":"Visually impaired individuals (VIIs) encounter significant daily challenges due to limited access to visual information. Although Multimodal Large Language Models (MLLMs) have achieved impressive results on general vision and language tasks, their practical utility in real-world blind assistance still remains largely underexplored. To fill this gap, we introduce VIABench, a comprehensive video benchmark specifically designed to evaluate MLLMs in Visually Impaired Assistance scenarios using first-person videos recorded or shared by VIIs themselves. VIABench defines three core tasks, each targeting a distinct requirement in visual assistance. Proactive Reminder: Assesses the model's ability to interpret ongoing video content while proactively anticipating and verbally describing upcoming navigation-critical events; Visual Question Answering (VQA): Evaluates the model's capacity to answer user-posed questions about the environment or objects within the video; Vision-Guided Interaction: Tests context-aware reasoning to accomplish intentional interactions between user and environment. To ensure a robust and fair evaluation, we propose a rigorous benchmarking pipeline that supports both online (real-time) and offline settings. Our experiments demonstrate that current MLLMs still struggle to deliver comprehensive support for VIIs, especially in the Proactive Reminder task, which demands accurate anticipation and real-time responsiveness. We hope VIABench will drive future research toward developing customized MLLMs for real-world assistance, ultimately improving navigation and interaction experiences for visually impaired individuals. Code and data will be released at https://github.com/MCG-NJU/VIABench.","authors":["Yunfeng Liu","Yuandong Yang","Jiarui Han","Zhenpeng Huang","Yuqing Tang","Xiangyu Zeng","Gangshan Wu","Limin Wang"],"published":"2026-07-16T07:25:17Z","updated":"2026-07-16T07:25:17Z","abstract_url":"https://arxiv.org/abs/2607.14660v1","html_url":"https://arxiv.org/html/2607.14660v1","pdf_url":"https://arxiv.org/pdf/2607.14660v1.pdf","matched_keywords":["video","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14645v1","title":"Autoregressive Modeling of Film with Applications in Video Montage","abstract":"This work introduces FilmGPT, an autoregressive transformer designed to address the challenge of video montage--turning a collection of raw, \"unwatchable\" footage into coherent cinematic sequences. Inspired by language learning in modern LLMs, we train a long-context autoregressive transformer on a large corpus of movies. The aim is to implicitly capture the \"grammar\" of film directly from data rather than from hand-coded rules. Unlike other generative models, FilmGPT does not generate any new video frames. Instead, at inference time, we introduce a footage-constrained decoding algorithm to select the best next shot from the input raw footage according to the statistical patterns learned from films. We first evaluate these learned statistics directly by using the FilmGPT autoregressive model for next shot prediction on a standard benchmark of shot sequence ordering, outperforming the previous state of the art. We then evaluate our footage-constrained decoding algorithm on the full film editing task via a user study, and find that our FilmGPT-based editing significantly outperforms previous approaches. Finally, we demonstrate the applicability of FilmGPT to a wide range of applications in video montage, from automatic video segment trimming to human-in-the-loop film editing.","authors":["Marcelo Sandoval-Castañeda","Fabian Caba Heilbron","Shiry Ginosar","Bryan Rusell","Josef Sivic","Alexei A. Efros","Greg Shakhnarovich"],"published":"2026-07-16T07:13:54Z","updated":"2026-07-16T07:13:54Z","abstract_url":"https://arxiv.org/abs/2607.14645v1","html_url":"https://arxiv.org/html/2607.14645v1","pdf_url":"https://arxiv.org/pdf/2607.14645v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14635v1","title":"Action QFormer: Structured Representation Shaping under Action Supervision in Vision-Language-Action Models","abstract":"Action supervision in vision-language-action (VLA) models is often treated as a downstream objective for learning action prediction. In this paper, we study it instead as a force that shapes inherited multimodal representations. We show that this shaping has a dual effect: it is necessary for forming action-compatible representations, but when action supervision is applied too directly to the inherited multimodal pathway, it can also destabilize representations that support language-side processing and object grounding. To address this tension, we introduce Action QFormer, a query-based action-facing interface that uses instruction-conditioned queries to reorganize inherited multimodal information into action-facing representations before downstream action generation. In zero-shot sim-to-real navigation, Action QFormer improves average closed-loop task success from 18.8% to 56.3%, raises fixed-instruction action-generation correctness from 22.5% to 75.5%, and nearly eliminates out-of-distribution instruction generations. Further analyses show that Action QFormer changes how action supervision shapes inherited multimodal representations, reducing broad upstream rewriting while preserving targeted and sometimes constructive action-supervised adaptation. These results suggest that improving VLA performance requires not only stronger pretrained backbones, but also better ways of selecting and organizing inherited multimodal information while controlling how it is shaped under action supervision.","authors":["Yufeng Ji","Wenhao Tang","Haoyi Niu","Koushil Sreenath","Yi Wu","Zhongyu Li"],"published":"2026-07-16T06:59:39Z","updated":"2026-07-16T06:59:39Z","abstract_url":"https://arxiv.org/abs/2607.14635v1","html_url":"https://arxiv.org/html/2607.14635v1","pdf_url":"https://arxiv.org/pdf/2607.14635v1.pdf","matched_keywords":["representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14631v1","title":"Knowing You at First Glance: Inferring Apparent Personality from Faces","abstract":"Inferring apparent personality from facial images is important in social scenarios for embodied agents in human-robot interaction. Unlike inferring intrinsic personality traits via conversation, this task models first-impression personality perception based solely on facial appearance before interaction begins. Existing studies mainly focus on the Big Five personality model and often rely on language or multimodal inputs. As a result, it remains unclear whether facial cues alone can support meaningful associations with perceived personality traits. This question is particularly relevant for MBTI types, which are widely used in practice and more readily interpretable by large language models. To this end, we propose \\textbf{GlanceFace}, an end-to-end framework for apparent personality inference leveraging vision-language models to introduce semantic priors and a semantic-enhanced facial representation module to capture subtle personality-related cues, together with an uncertainty-aware learning strategy to handle noisy and subjective annotations. Extensive experiments demonstrate strong performance on MBTI-based apparent personality benchmarks and reveal relationships between facial characteristics and perceived personality traits, highlighting its potential to support adaptive initial interaction strategies for embodied agents. The code and dataset are available at https://github.com/MrHuan3/GlanceFace.","authors":["Shuhuan Chen","Xiangyu Zhu","Weisong Zhao","Haichao Shi","Xiao-Yu Zhang","Zhen Lei"],"published":"2026-07-16T06:48:11Z","updated":"2026-07-16T06:48:11Z","abstract_url":"https://arxiv.org/abs/2607.14631v1","html_url":"https://arxiv.org/html/2607.14631v1","pdf_url":"https://arxiv.org/pdf/2607.14631v1.pdf","matched_keywords":["agent","representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14595v1","title":"MagicPrompt: Ultra-Lightweight Prompt Tuning for Video Generation","abstract":"Large-scale video diffusion models (VDMs) deliver strong generation performance, but full fine-tuning for downstream tasks incurs prohibitive computational costs. Existing parameter-efficient fine-tuning (PEFT) methods have two critical flaws on billion-scale models: they still require substantial trainable parameters, and reward-based training suffers from noise-induced optimization instability in condition-guided tasks. We propose MagicPrompt, a lightweight framework that achieves extreme parameter efficiency and stable reward optimization. It first adopts Attention-Embedded Prompt Tuning, which steers generation via lightweight soft prompts with orders of magnitude fewer parameters while preserving pre-trained knowledge. It further introduces Dual-Space Reward Feedback Optimization, which uses self-supervised latent objectives to improve condition-guided reward training. Experiments show MagicPrompt reaches competitive performance with less than 1\\% trainable parameters and notably reduces training costs.","authors":["Yinhan Zhang","Dinwei Tan","Xianghao Kong","Yue Ma","Yeying Jin","Anyi Rao"],"published":"2026-07-16T05:46:59Z","updated":"2026-07-16T05:46:59Z","abstract_url":"https://arxiv.org/abs/2607.14595v1","html_url":"https://arxiv.org/html/2607.14595v1","pdf_url":"https://arxiv.org/pdf/2607.14595v1.pdf","matched_keywords":["video","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14581v1","title":"Multi-LLM Collaborative MRI Report Generation for Visual Instruction Tuning in Brain Oncology","abstract":"Recent advances in large language models (LLMs) and their extension to vision-language models (VLMs) have made it easier to combine text and images for tasks such as report generation. Existing VLMs in medicine typically focus on 2D images (chest X-rays), and their extension to 3D imaging has been difficult because of the lack of paired 3D imaging-text data. Thus, we introduce a new method for creating a 3D image-text dataset for brain oncology using 3D MRI scans of glioma and meningioma cases. We use a cooperative system in which several LLMs work together to generate and check reports, ensuring that they are accurate and clear. By leveraging the new 3D MRI-text dataset, we further build a VLM that converts MRI scans into tokens and aligns them with text instructions. Our VLM performed better in report generation and visual question answering tasks than other 2D and 3D methods. Our method not only improves the quality of reports but also helps with better diagnosis and treatment in brain oncology.","authors":["Sinyoung Ra","Jonghun Kim","Hyunjin Park"],"published":"2026-07-16T05:21:47Z","updated":"2026-07-16T05:21:47Z","abstract_url":"https://arxiv.org/abs/2607.14581v1","html_url":"https://arxiv.org/html/2607.14581v1","pdf_url":"https://arxiv.org/pdf/2607.14581v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14580v1","title":"Advanced Image Generation: Negative Prompt Optimization and Latent Classifier Guidance","abstract":"We present a novel system that integrates negative prompt optimization via a fine-tuned sequence-to-sequence LLM and latent-space classifier guidance to improve the quality of images generated by Stable Diffusion. Our approach automatically generates optimized negative prompts, and employs a CNN-RNN hybrid classifier to evaluate and guide diffusion steps, rolling back low-quality latent updates. Experimental results demonstrate that our dual-guidance framework reduces artifacts and improves semantic fidelity compared to baseline diffusion.","authors":["Vaddi Charan Sai Nandan Reddy","Harini B","Chandana M S"],"published":"2026-07-16T05:21:17Z","updated":"2026-07-16T05:21:17Z","abstract_url":"https://arxiv.org/abs/2607.14580v1","html_url":"https://arxiv.org/html/2607.14580v1","pdf_url":"https://arxiv.org/pdf/2607.14580v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14579v1","title":"Skeleton: Visual Authoring of Non-visual Data Experiences","abstract":"When sighted practitioners author accessible data visualizations, they build navigation structures (the nodes, edges, and input bindings that govern how assistive technologies traverse an interface) entirely in code, with no visual representation. Without a representation to react to, practitioners cannot develop judgment about what makes navigation good or bad, and the quality ceiling of non-visual experiences is set by the absence of a feedback loop. We address this problem through longitudinal co-design with practitioners across cartography, design systems, and open-source visualization, and make three contributions. First, we introduce an Inspector that renders navigation graphs as interactive node-link diagrams, and a Dimensions API that expresses navigation in terms of data dimensions rather than explicit graph construction. Second we present Skeleton, a direct-manipulation authoring environment in which the properties of an accessible navigation structure are translated into visual representations authors can observe and manipulate. Key techniques include a dual-view editor that simultaneously shows the system's navigation model and the end user's spatial experience, a scaffolding engine that automates spatial node placement by repurposing a visualization rendering pipeline, a live label-template editor with real-time screen-reader-output preview, and a testing mode that makes traversal sequence visually trackable. Third, we evaluate Skeleton through an in-situ study with 8 practitioners across visualization design, engineering, and research. Making navigation structure visible changed how practitioners engaged with accessible design: they reconsidered the architecture of their own visualizations, attended to a broader range of input modalities, and shifted from treating accessibility as a compliance task to treating it as a design problem. (abstract shortened for arxiv)","authors":["Frank Elavsky","Chieri Nnadozie","Lucas Nadolskis","Patrick Carrington","Dominik Moritz"],"published":"2026-07-16T05:16:17Z","updated":"2026-07-16T05:16:17Z","abstract_url":"https://arxiv.org/abs/2607.14579v1","html_url":"https://arxiv.org/html/2607.14579v1","pdf_url":"https://arxiv.org/pdf/2607.14579v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14560v1","title":"Breaking the Model Forgetting Cycle in Long-Incremental 3D Object Detection","abstract":"Incremental 3D object detection requires a detector to learn novel object classes while remembering previously learned ones over sequentially arriving data. Previous methods, primarily based on pseudo-labeling, perform reasonably in short-incremental stages but still suffer from severe model forgetting when dealing with long-incremental sequences. We investigate this failure and reveal a detrimental self-reinforcing cycle: data distribution shift of novel classes causes model forgetting on old classes, which further produces accumulated error in pseudo-labeling that exacerbates model degradation. To address this issue, we draw inspiration from the human learning process and propose the \\emph{Learning-Dynamics-driven Memory and Review} (LDMR) framework. LDMR monitors per-class detection quality at periodic training checkpoints and uses these learning-dynamics signals to drive two innovative mechanisms, namely (i) human-like intra-stage review that divides each incremental stage into multiple sub-stages' training and concentrates on remembering the most-forgotten objects, and (ii) scene-aware cross-stage memory evolution that evolves a memory bank to transfer knowledge between two consecutive stages by jointly considering scene learnability and diversity. Extensive experiments across multiple long-incremental protocols on indoor benchmarks SUN RGB-D and ScanNetV2 show that LDMR substantially mitigates the model forgetting and outperforms all baselines by a clear margin. Code is available at https://github.com/qianpeisheng/LDMR.","authors":["Peisheng Qian","Jie Xu","Xulei Yang","Na Zhao"],"published":"2026-07-16T04:39:35Z","updated":"2026-07-16T04:39:35Z","abstract_url":"https://arxiv.org/abs/2607.14560v1","html_url":"https://arxiv.org/html/2607.14560v1","pdf_url":"https://arxiv.org/pdf/2607.14560v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14548v1","title":"HyMobileAgent: Data-Environment Co-Scaling for Efficient GUI Agents","abstract":"As large multimodal models move from understanding content to operating on digital environments, mobile GUI has emerged as a challenging and consequential testbed for digital embodied intelligence. Mobile agents operate under three coupled constraints: precise perception of complex interfaces, scalable acquisition of high-quality interaction data, and robust long-horizon decision making under compounding execution errors. This report presents HyMobileAgent, a mobile GUI agent built on Hy3.0-VL-A3B, a vision-native foundation model featuring native any-resolution input, an A3B-scale deployment budget, and a 32K context window to model extended interaction histories. Rather than relying solely on model scaling, we develop a joint data and environment centric scaling framework to address the key bottlenecks of mobile interaction. Our framework integrates a GUI perception flywheel combining mock-interface synthesis, rejection sampling, and icon-specific augmentation; a knowledge pipeline that transforms tutorial videos into structured interaction data; a million-scale action data pipeline deployed across more than 2000 sandbox and real-device instances with automated failure attribution; the PhoneWorld Mock App Factory, providing a resettable training environment with 34 mock applications and over 34000 tasks; and a structured Planning-and-Reflection mechanism with explicit dead-loop detection for reliable long-horizon execution. We also introduce a progressive training recipe consisting of mid-training, supervised fine-tuning, and reinforcement learning with task-specific reward designs.","authors":["Hy Vision Team","Huawen Shen","Zhengyang Tang","Shangpin Peng","Liang Wu","Anran Zhang","Weinong Wang","Yiduo Guo","Chenxin Li","Zhengyao Fang","Yang Ding","Junyi Li","Fei Tang","Zheng Ruan","Yi Zhang","Xingran Zhou","Dingchen Yang","Sunqi Fan","Zhiyi Wan","Han Hu","Xin Lai","Pengyuan Lyu","Chengquan Zhang"],"published":"2026-07-16T04:12:42Z","updated":"2026-07-16T04:12:42Z","abstract_url":"https://arxiv.org/abs/2607.14548v1","html_url":"https://arxiv.org/html/2607.14548v1","pdf_url":"https://arxiv.org/pdf/2607.14548v1.pdf","matched_keywords":["video","agent","instance","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14547v1","title":"AdaTurn: Budget-Aware Test-Time Scaling for Active Visual Perception Agents","abstract":"Active visual agents solve fine-grained image tasks by interleaving reasoning with image-grounding actions across multiple turns. However, deployment-time rollout budgets are rarely fixed: some requests permit long rollouts, while others require the agent to act under a tight turn limit. Existing methods train the policy as if the rollout budget were hidden, so when the available budget is smaller than the trajectory the agent prefers, the interaction is often truncated before any valid answer is produced; we term this failure \\emph{catastrophic truncation}. To overcome this challenge, we present AdaTurn, a budget-aware framework that conditions the agent on the allowed number of turns and explicitly trains the boundary behavior induced by the budget. Our key component, Forced-Answer DAPO (FA-DAPO), converts the over-budget event from a masked or penalized failure into a trainable final-decision step, teaching the model to synthesize partial evidence when further tool use is no longer possible. We further randomize rollout budgets during both training and inference and introduce a load-balanced scheduler that makes such operations practical. AdaTurn substantially improves low-budget accuracy, for example raising VisualProbe-Medium from 36.7% to 47.6% at four turns, while preserving strong scaling at larger budgets and transferring effectively to multiple backbones and general multimodal benchmarks.","authors":["Susan Liang","Chao Huang","Filippos Bellos","Jing Bi","Jason J Corso","Chenliang Xu"],"published":"2026-07-16T04:07:22Z","updated":"2026-07-16T04:07:22Z","abstract_url":"https://arxiv.org/abs/2607.14547v1","html_url":"https://arxiv.org/html/2607.14547v1","pdf_url":"https://arxiv.org/pdf/2607.14547v1.pdf","matched_keywords":["agent","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14544v1","title":"3D Geometric Tooth Alignment Planning via Deep Reinforcement Learning","abstract":"3D geometric tooth alignment planning, which determines sequential trajectories from initial malocclusion to the final target alignment, is a cornerstone of modern digital orthodontics. This paper presents a novel deep reinforcement learning (DRL) framework to automate the generation of these alignment paths. We formulate the planning process as a Markov Decision Process (MDP) to capture its sequential decision-making nature, focusing on optimizing geometric trajectories while integrating essential spatial constraints, such as inter-dental collision avoidance and path efficiency. The proposed method leverages the Deep Deterministic Policy Gradient (DDPG) algorithm, enhanced by three key innovations: (1) a Transformer-based agent to model complex spatial interactions between teeth and manage high-dimensional state-action spaces; (2) a dynamic masking scheme that restricts movement to a sparse subset of teeth per step, better reflecting the clinical logic of sequential alignment; and (3) a two-stage curriculum learning strategy that gradually increases task difficulty to ensure training stability and efficient path discovery. We evaluate our approach on a dataset of 10K expert-designed treatment plans based on clinical data. Experimental results demonstrate that our method outperforms existing baselines in terms of path safety and geometric efficiency, providing a robust and automated solution for 3D geometric orthodontic alignment planning.","authors":["Yong Li","Jianwen Lou","Jiayue Ma","Yao-Xiang Ding","Youyi Zheng","Haihua Zhu"],"published":"2026-07-16T04:00:05Z","updated":"2026-07-16T04:00:05Z","abstract_url":"https://arxiv.org/abs/2607.14544v1","html_url":"https://arxiv.org/html/2607.14544v1","pdf_url":"https://arxiv.org/pdf/2607.14544v1.pdf","matched_keywords":["3d","agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14521v1","title":"Uni-AdaVD: Universal Concept Erasure for Visual Generation via Orthogonal Value Decomposition","abstract":"Visual generative models inevitably absorb undesirable concepts from uncurated pretraining data, making concept erasure essential for safe deployment. Existing erasure methods, however, are often architecture-specific and struggle to remove target concepts while preserving non-target content and generative priors. We present Uni-AdaVD, a universal inference-time concept erasure framework for visual generation. Uni-AdaVD treats the value space of multimodal attention as a unified intervention space and introduces encoder-aware target representation construction to localize target semantics across heterogeneous text encoders. It further combines orthogonal value decomposition with an adaptive erasing shift to suppress target semantic directions without updating the original model weights. Extensive experiments on U-Net-, DiT-, and autoregressive image generators, as well as text-to-video models, demonstrate strong performance on single- and multi-concept erasure while preserving non-target priors. These results suggest that Uni-AdaVD provides an efficient and adaptable safety mechanism for modern visual generative models. Our code is available at https://github.com/QifanZhou/Uni-AdaVD.","authors":["Qifan Zhou","Yuan Wang","Yanbin Hao","Xiang Wang","Kuien Liu","Richang Hong","Meng Wang"],"published":"2026-07-16T03:16:51Z","updated":"2026-07-16T03:16:51Z","abstract_url":"https://arxiv.org/abs/2607.14521v1","html_url":"https://arxiv.org/html/2607.14521v1","pdf_url":"https://arxiv.org/pdf/2607.14521v1.pdf","matched_keywords":["video","representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14514v1","title":"VTM-Nav: Hierarchical Visual-Topological Memory for Cross-Episode Object-Goal Navigation","abstract":"Object-goal navigation requires an embodied agent to locate and reach an instance of a specified object category in an indoor environment. Recent training-free approaches leverage vision-language models (VLMs) for open-vocabulary semantic reasoning, but are typically evaluated under an episodic protocol that resets all scene-specific state after each episode. We introduce Cross-Episode Object-Goal Navigation, in which an agent repeatedly operates in the same scene, retains only self-acquired experience, and keeps its model parameters fixed. To support experience reuse, we present \\method, a training-free VLM navigation framework with a persistent hierarchical Visual-Topological Memory (VTM). The VTM organizes scene knowledge at room and object levels and retrieves relevant experience through coarse-to-fine matching, providing memory as soft guidance only when it agrees with current observations. A conservative execution guard further mitigates oscillations, blocked motions, and premature stopping. Under a controlled same-scene protocol, we evaluate \\method{} on three benchmarks, HM3D v0.1, HM3D v0.2, and MP3D, and compare it with a strengthened WMNav baseline augmented with cross-episode textual memory, while keeping the VLM backbone and action pipeline identical. \\method{} achieves the best performance across all three benchmarks, demonstrating the effectiveness and robustness of structured visual-topological experience reuse across datasets.","authors":["Xiaoran Xu","Yupeng Wu","Tianyu Xue","Yifan Xu","Xuanran Dong","Xiaoshan Yang","Changsheng Xu"],"published":"2026-07-16T03:11:37Z","updated":"2026-07-16T03:11:37Z","abstract_url":"https://arxiv.org/abs/2607.14514v1","html_url":"https://arxiv.org/html/2607.14514v1","pdf_url":"https://arxiv.org/pdf/2607.14514v1.pdf","matched_keywords":["3d","agent","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14513v1","title":"Compression of 3D Gaussian Splatting Data Using GPU-friendly Graphics Texture Coding","abstract":"Techniques for modeling 3D scenes from image collections, such as 3D Gaussian Splatting (3DGS), are capable of generating high-quality novel views by leveraging graphics primitives with view-dependent appearance. In 3DGS, spherical harmonic (SH) are employed to model view-dependent color, resulting in a large number of SH coefficients per primitive and large memory requirements. While compression approaches have been proposed to mitigate this problem, they do not exploit the capabilities of modern Graphics Processing Units (GPUs) for parallel decoding and rendering. In this paper, we propose a method for compressing SH color coefficients using texture compression schemes specifically designed for efficient parallel GPU decoding and supported by dedicated hardware acceleration. It is shown that those methods can compress color coefficients more effectively than 2D textures by exploiting the fact that primitives can be locally grouped and reordered according to color. Furthermore, we introduce a bit-rate control strategy that preserves random access, enabling large-scale parallelization without compromising rendering performance. Experimental results using BC1 and BC7 texture compression formats show that GPU-based decompression can be achieved with negligible or imperceptible degradation in the visual quality of rendered 3DGS scenes.","authors":["Amir Said","Randall Rauwendaal"],"published":"2026-07-16T03:10:27Z","updated":"2026-07-16T03:10:27Z","abstract_url":"https://arxiv.org/abs/2607.14513v1","html_url":"https://arxiv.org/html/2607.14513v1","pdf_url":"https://arxiv.org/pdf/2607.14513v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14509v1","title":"Multi-Scale ViT Inference with Habitat-Fit Priors and kNN Retrieval for Multi-Species Plant Identification","abstract":"This paper describes DS@GT ARC's third-place solution to the PlantCLEF 2026 challenge on multi-species plant identification in vegetation quadrat images, where systems must predict every species present in high-resolution (~3000 x 3000 pixel) plot photographs while training only on single-label images of individual plants. The pipeline is built around a fine-tuned DINOv2 ViT-L/14 classifier applied over a multi-scale tile decomposition of each quadrat, with per-tile predictions blended with a FAISS kNN retriever and post-processed by source-aware temporal fusion across repeated plot visits, a habitat-fit demotion that injects geographic and altitude priors from the training data, and a South-Western Europe geographic mask. Habitat-fit demotion and multi-scale aggregation are the largest individual contributors in the ablations. Two complementary training-centric directions, a cross-region transformer with noisy-student distillation on the LUCAS dataset and a label-as-query transformer decoder over synthetic CLS-domain pseudo-quadrats, yielded null results. An inference-time augmentation with instance-aware segmentation crops also did not improve performance. The selected submission reaches a private-leaderboard macro-F1 of 0.43902 (third place; public 0.51096); an unselected configuration of the same pipeline scored above 0.45 on the private set. Code: https://github.com/dsgt-arc/plantclef-2026.","authors":["Alper Erten","Murilo Gustineli","Adrian Cheung"],"published":"2026-07-16T02:47:38Z","updated":"2026-07-16T02:47:38Z","abstract_url":"https://arxiv.org/abs/2607.14509v1","html_url":"https://arxiv.org/html/2607.14509v1","pdf_url":"https://arxiv.org/pdf/2607.14509v1.pdf","matched_keywords":["retrieval","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14497v1","title":"Reinforcing Egocentric Spatial Perception in Multimodal Large Language Models via Ego Scene Augmentation","abstract":"Egocentric Visual Question Answering (VQA) has attracted widespread attention as an important task for enabling Multimodal Large Language Models (MLLMs) to interact with the real world. However, existing MLLMs struggle to perform effective spatial reasoning in complex egocentric scenes due to their limited spatial perception capabilities. To this end, we introduce Ego Scene Augmentation (ESA), an egocentric spatial perception framework, which actively enhances the spatial perception capabilities from the egocentric perspective, powered by the proposed Ego-element Graph. Our core insight is leveraging the Ego-element Graph as an intermediary representation to augment the egocentric spatial perception of MLLMs via visual foundational models. Specifically, we 1) construct the Ego-element Graph, which encapsulates and integrates egocentric spatial features enabled by visual foundational models; 2) enhance the spatial perception capabilities of MLLMs via the Ego-element Graph for ego-perspective scenes. Our proposed ESA framework presents significant performance improvement on the EgoTextVQA benchmark. We achieve an 8.14% gain on the indoor setting and an 8.72% gain on the outdoor setting. Furthermore, our ESA shows the most impressive performance improvement in the shopping subset of the indoor setting. The project code is publicly available.","authors":["Chi Kit Wong","Ye Pan","Yuanhuiyi Lyu","Xu Zheng","Zidong Cao","Lutao Jiang","Zixin Zhang","Huiyu Zhou","Xuming Hu"],"published":"2026-07-16T02:22:26Z","updated":"2026-07-16T02:22:26Z","abstract_url":"https://arxiv.org/abs/2607.14497v1","html_url":"https://arxiv.org/html/2607.14497v1","pdf_url":"https://arxiv.org/pdf/2607.14497v1.pdf","matched_keywords":["representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14481v1","title":"Immediate 3D Gaussian Splat Reconstruction of Unordered Input with Global Consistency","abstract":"3D Gaussian Splatting (3DGS) has become the method of choice for reconstructing and real-time rendering of captured scenes. To capture a scene with good visual quality, continuous image sequences are usually combined with out-of-order shots for better scene coverage. Structure from motion can reconstruct such captures, but only after they are all available and often with high computational cost. Incremental reconstruction methods -- often derived from SLAM solutions -- provide immediate feedback, but cannot handle the out-of-order capture we require. We provide the first immediate feedback solution for such radiance field capture that provides global consistency. We first introduce a method for fast matching in out-of-order sequences, by repurposing visual place recognition models and a covisibility graph, and provide an efficient way to find highly connected keyframes, improving quality even for ordered sequences. We show how these steps -- together with GPU optimization and careful Gaussian primitive placement -- provide fast local reconstruction, in our challenging radiance field reconstruction case. We then introduce a novel cluster-based method, again using the covisibility graph, to provide efficient loop closure that does not require sequential input. Finally, to handle large scenes in our context, we introduce a progressive hierarchy that allows our method to scale to large environments, without compromising efficiency. Our results show we provide immediate feedback 3DGS reconstruction with good visual quality in several datasets, with up to thousands of input images.","authors":["Andreas Meuleman","Linus Franke","Boris Zhestiankin","Camille Montemagni","George Drettakis"],"published":"2026-07-16T01:53:13Z","updated":"2026-07-16T01:53:13Z","abstract_url":"https://arxiv.org/abs/2607.14481v1","html_url":"https://arxiv.org/html/2607.14481v1","pdf_url":"https://arxiv.org/pdf/2607.14481v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14470v1","title":"G$^2$SR: Geometric Methods for Fast and Memory-Efficient Gaussian-based Surface Reconstruction","abstract":"Few-view surface reconstruction recovers the visible surfaces of a scene from a few posed RGB images, providing the 3D models that robots need to explore and interact online. On mobile platforms, the reconstruction must be fast and geometrically accurate while keeping a small memory footprint to ensure safe and efficient operation. 3D Gaussian Splatting (3DGS) offers a high-fidelity scene representation, but building it from a few views is ill-posed, as many distinct surfaces reproduce the same images, making traditional photometric methods prone to \"floater\" artifacts. End-to-end methods resolve the ambiguity by regressing splats with large, usually Transformer-based, networks that require heavy compute and memory while generalizing poorly to new scenes. We propose G2SR, which exploits a well-posed core of the task: given cross-view 2D splat correspondences, 3D splats follow analytically from multi-view geometry. G2SR employs a lightweight neural frontend to detect and track 2D Gaussian splats on the image plane and an analytic backend to triangulate each into a metric-scale 3D splat. On ScanNet, Replica, and DTU, G2SR matches or exceeds the geometric accuracy of state-of-the-art end-to-end methods while running at 69-89 reconstructions per second within 203 MB of GPU memory (5-107x less) for 2- and 3-view inputs at 384 x 512 resolution, offering a practical path to online Gaussian-based surface reconstruction.","authors":["Dasong Gao","Vivienne Sze","Sertac Karaman"],"published":"2026-07-16T01:33:37Z","updated":"2026-07-16T01:33:37Z","abstract_url":"https://arxiv.org/abs/2607.14470v1","html_url":"https://arxiv.org/html/2607.14470v1","pdf_url":"https://arxiv.org/pdf/2607.14470v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14463v1","title":"Depth-Dependent Hidden-State Collapse in Dynamical System Autoencoders for LiDAR Point-Cloud Classification","abstract":"We study Dynamical System Autoencoders (DSAE) for LiDAR point-cloud classification using spatial coordinates and Product Coefficient feature augmentations. The experiments compare separately trained DSAE architectures at encoder depths $K=1,\\ldots,5$ and evaluate the resulting hidden representations with Random Forest, kNN, and a majority-class Dummy baseline. The main finding is a hidden-state collapse at $K=5$. For both xyz and xyz plus Product Coefficient inputs, the hidden-state standard deviation falls to the order of $10^{-5}$, while all three classifiers attain the same macro F1 score of $0.224688$. We prove that between-class hidden scatter is bounded by total hidden scatter, which in turn is controlled by the reported hidden-state variance. Thus a nearly constant hidden representation cannot retain substantial class-separating structure. Product Coefficients neither improve pre-collapse macro F1 nor prevent the $K=5$ collapse in the present DSAE setting. These results identify large-depth representation collapse as a concrete failure mode for DSAE LiDAR classification.","authors":["Patricia Medina","Hy P. G. Lam"],"published":"2026-07-16T01:20:42Z","updated":"2026-07-16T01:20:42Z","abstract_url":"https://arxiv.org/abs/2607.14463v1","html_url":"https://arxiv.org/html/2607.14463v1","pdf_url":"https://arxiv.org/pdf/2607.14463v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14445v1","title":"Cotton-SF YOLO: Learning Structural and Frequency Cues for Early Cotton Square Detection in Complex Field Environments","abstract":"Cotton squares are important phenotypic indicators of the early reproductive growth of cotton, and automatic field detection of cotton squares provides an important basis for cotton growth monitoring and precision cultivation management. However, early cotton square detection in complex field environments remains insufficiently explored, as cotton squares are small, frequently occluded, easily blurred, subject to illumination variations, and exhibit low contrast against surrounding cotton leaves. To address these challenges, we propose a task-oriented framework based on YOLO26m, named Cotton-SF YOLO, for cotton square detection under natural field conditions. To improve the perception of small and irregular cotton square boundaries, we introduce Dynamic Snake Convolution into the detector, enabling adaptive extraction of deformable edge features. Furthermore, a frequency-domain feature modulation module is designed by incorporating spectral enhancement into the C2f structure, which recalibrate frequency-domain representations and strengthen discriminative edge and texture cues while reducing interference from complex cotton leaf backgrounds. Trained and evaluated on our newly constructed and annotated field dataset with manually annotated cotton squares, the proposed model achieves mAP$_{50}$, mAP$_{50:95}$, and recall values of 0.8196, 0.4942, and 0.7939, improving over the baseline YOLO26m by 1.25%, 3.45%, and 2.96%, respectively. Ablation experiments and visualization demonstrate that the best performance is achieved with the complementary effects of structural and frequency cues.","authors":["Chengjia Zhang","Yu Li","Feiri Ali","Yan Zhang","Xin Chen","Longke He","Daokun Ma","Liting Gao"],"published":"2026-07-16T00:40:59Z","updated":"2026-07-16T00:40:59Z","abstract_url":"https://arxiv.org/abs/2607.14445v1","html_url":"https://arxiv.org/html/2607.14445v1","pdf_url":"https://arxiv.org/pdf/2607.14445v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14423v1","title":"Emergent Region-Level Facial Correspondence in Frozen Vision Foundation Models","abstract":"Frozen self-supervised vision models can align parts of generic objects, but it remains unclear whether this correspondence extends to human faces, where global layout is shared while identity-specific appearance varies sharply. We test whether frozen DINOv3 features define a region-level facial coordinate system: a feature space in which eyes, brows, nose, mouth, skin, and hair remain distinguishable across people and across time without face-specific training. Using DINOv3 ViT-L/16 patch embeddings and FaRL only as a face-part labeling interface, we evaluate cross-identity nearest-neighbor matching and temporal label propagation on 200 CelebDF-v2 real videos. DINOv3 achieves 83.0% region-level semantic accuracy under unconstrained cross-identity matching, compared with a 23.0% area-weighted random baseline, and 95.5% temporal tracking accuracy without a learned temporal module. A no-FaRL control collapses to 0.9%, showing that FaRL supplies semantic initialization while DINOv3 supplies dense spatial correspondence. The strongest correspondence appears at an intermediate layer: block 18 gives a 4.93x same-region versus cross-region discrimination ratio, compared with 1.48x at the final block. Against CLIP ViT-L/14, DINOv3 shows only a small aggregate advantage but a +16.8 pp gain on anatomical regions, indicating that image-level contrastive supervision captures coarse facial layout but not fine-grained anatomical identity. These results establish frozen DINOv3 as a strong zero-shot representation for region-level facial correspondence and identify intermediate self-supervised features as the most useful layer for dense face analysis.","authors":["Izaldein Al-Zyoud","Abdulmotaleb El Saddik"],"published":"2026-07-15T23:23:28Z","updated":"2026-07-15T23:23:28Z","abstract_url":"https://arxiv.org/abs/2607.14423v1","html_url":"https://arxiv.org/html/2607.14423v1","pdf_url":"https://arxiv.org/pdf/2607.14423v1.pdf","matched_keywords":["video","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"},{"id":"2607.14415v1","title":"$K$-NeAS: Scalable Multi-Material CT Reconstruction Using Neural SDFs","abstract":"Computed Tomography (CT) carries significant ionizing radiation risks, driving the need for sparse-view reconstruction. Implicit scene representations (ISRs) address this by recovering continuous volumetric attenuation fields directly from sparse projections, and recent geometry-aware extensions jointly model surface geometry alongside attenuation to improve fidelity and enable clean tissue segmentation without manual thresholding. However, these methods remain limited by manually tuned attenuation bounds and rigid two-material constraints. This paper proposes $K$-NeAS, a unified and scalable architecture for automated, multi-material surface reconstruction. We replace independent material networks with a shared latent backbone and introduce a fully differentiable $K$-material sequential soft selector to model an arbitrary number of overlapping tissues. To eliminate manual tuning, we automate attenuation bounding using a Gaussian Mixture Model (GMM) and implement a scheduled auxiliary floater loss to mitigate geometric hallucinations common under extreme sparsity. Evaluated across four clinical Cone-Beam CT (CBCT) datasets, $K$-NeAS successfully scales to arbitrary material counts, achieving superior 3D volumetric fidelity at $K=3$ materials on complex multi-tissue regions such as the Abdomen ($33.28\\text{ dB}$ 3D PSNR vs. $31.40\\text{ dB}$ single-material NeAS baseline, a $+1.88\\text{ dB}$ improvement). Furthermore, our model exhibits enhanced robustness under sparse-sampling conditions, outperforming baseline 3D PSNR by up to $1.17\\text{ dB}$ under 5- and 10-view constraints.","authors":["Daksh K. Shah","Emmanouil Nikolakakis","Razvan V. Marinescu"],"published":"2026-07-15T23:08:45Z","updated":"2026-07-15T23:08:45Z","abstract_url":"https://arxiv.org/abs/2607.14415v1","html_url":"https://arxiv.org/html/2607.14415v1","pdf_url":"https://arxiv.org/pdf/2607.14415v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-17T03:56:55+00:00","last_seen_at":"2026-07-17T03:56:55+00:00"}],"tracked_paper_count":70,"storage_mode":"latest_overwrite"}};
